INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2646654911214962602', '人工智能', '比博斯特完成超10亿元B轮融资，智能底盘三轴产品全覆盖｜36氪独家', 'https://36kr.com/p/3740907027054600?f=rss', '36kr', '2026-04-29', '36氪独家获悉，智能底盘企业比博斯特近日完成B+轮融资，由浙江省新能源汽车产业基金领投，顺创产投、杭资直投基金等联合投资。企业B+轮融资超7亿元，B轮系列融资总额已超10亿元。本轮融资将用于已有产品的规模化增长及前沿产品的开发。\n  比博斯特成立于2021年，其股东不仅包括主机厂蔚来，还涵盖恒隆、保隆等汽车底盘供应链头部企业。2025年，曾在底盘巨头采埃孚担任高管的巫子平、郁炜陆续加入比博斯特，出', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:13', '2026-04-29 09:33:13', 0.5);
