INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2874163204386195259', '半导体', '8点1氪：中方禁止外资收购Manus；上海迪士尼回应游客吸烟冲突事件；泡泡玛特LABUBU 冰箱未发售已溢价3000元', 'https://36kr.com/p/3785730095127817?f=rss', '36kr', '2026-04-28', 'TOP3大新闻\n  DeepSeek 输入缓存降价\n  多家美国廉价航空公司寻求政府资金纾困\n  东方甄选回应大量用户申请退会员\n  穿西装开空调太费电，日本东京鼓励公务员穿短裤\n  印度移动支付平台MobiKwik获央行批准\n  TOP3大事件\n  国家发展改革委：依法依规对外资收购Manus项目作出禁止投资决定\n  据国家发展改革委网站4月27日消息，外商投资安全审查工作机制办公室（国家发展改', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:16:48', '2026-04-29 10:16:47', '2026-04-29 10:16:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-2950243722768055209', '医疗健康', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:16:45', '2026-04-29 10:16:44', '2026-04-29 10:16:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-3015692624349357293', '人工智能', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:14', '2026-04-29 09:33:14', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-3042232877416082523', '机器人', '港股IPO热潮中的中资券商：保荐数量与市场份额领跑', 'https://36kr.com/newsflashes/3787179604679683?f=rss', '36kr', '2026-04-29', '2025年港股IPO市场强势复苏，全年新股上市数量与募资规模双双攀升，募资总额接近2900亿港元，时隔4年重回全球榜首。进入2026年，已有47家企业成功赴港上市，合计募资接近1400亿港元，且当前排队企业多达434家。综合来看，港股IPO业务呈现三大鲜明特征：A股企业赴港上市持续升温，硬科技与生物医药成为主力赛道；中资券商保荐数量与市场份额大幅领先，头部机构加速布局海外投行生态；项目储备持续饱满', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:16:56', '2026-04-29 10:16:56', '2026-04-29 10:16:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-3153301799146134844', '半导体', '多地银行加速旗下村镇银行整合重组', 'https://36kr.com/newsflashes/3787165643070723?f=rss', '36kr', '2026-04-29', '今年以来，多家银行加速旗下村镇银行减量提质改革，“村并村”“村改支”等整合重组案例密集落地，行业改革持续提速。苏商银行特约研究员高政扬对记者表示，当前中小金融机构改革有序推进。针对部分中小银行治理不完善、风控能力薄弱、抗风险水平不足等痛点，监管部门持续压实各方主体责任，引导行业通过兼并重组优化组织架构，稳妥化解存量风险。本轮整合重组改革，有助于筑牢区域金融安全防线，优化县域金融服务布局，持续增强金', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:26', '2026-04-29 08:43:26', '2026-04-29 08:43:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-32072936839245225', '人工智能', '前米哈游高管创业，AI 原生增长 Agent LeapMind Growth 获 CMC 资本领投', 'https://36kr.com/p/3786123369094405?f=rss', '36kr', '2026-04-29', '\n  2026 年 4 月 29&nbsp;日，上海讯 ——AI 原生增长 Agent LeapMind Growth&nbsp;今日宣布完成天使 + 轮融资，由 CMC 资本领投。本轮融资将主要用于核心产品 GrowthGPT 的研发迭代、产研团队扩充及早期市场拓展。\n  LeapMind Growth 成立于 2025 年 4 月，由前米哈游全球用户增长负责人、前快手增长策略中心负责人马如平（', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:23:50', '2026-04-29 10:23:50', '2026-04-29 10:24:10', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-3544812992244806033', '新材料', '新政后首单“H转深A”诞生，越疆科技创业板IPO获受理', 'https://36kr.com/newsflashes/3787137966382341?f=rss', '36kr', '2026-04-29', '4月27日，深交所官网显示，深圳市越疆科技股份有限公司（简称“越疆科技”）的创业板IPO申请已获受理。资料显示，越疆科技已于2024年12月在港交所上市。2025年6月10日印发的《中共中央办公厅 国务院办公厅关于深入推进深圳综合改革试点深化改革创新扩大开放的意见》提到，允许在香港联合交易所上市的粤港澳大湾区企业，按照政策规定在深圳证券交易所上市。市场分析指出，伴随着越疆“回A”的推进，“H转深A', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:46:02', '2026-04-29 08:46:02', '2026-04-29 08:46:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-3709838709148725669', '新材料', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升��；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:20', '2026-04-29 09:24:19', '2026-04-29 09:24:19', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-3761816066276343478', '人工智能', '未岚大陆第100万台智能割草机器人下线，马来西亚产线已完成、全面启动生产｜最前线', 'https://36kr.com/p/3784879395134465?f=rss', '36kr', '2026-04-27', '作者｜黄楠\n  编辑｜袁斯来\n  近日，智能割草机器人公司未岚大陆第100万台智能割草机器人下线仪式在其常州研发生产基地举办。未岚大陆CEO任冠佼、总裁兼CTO陈子冲、德国莱茵TÜV电子电气产品服务全球高级副总裁郝福来（Frank Holzmann）等出席仪式。\n  在割草机器人赛道竞争白热化的节点，百万台是对技术路线选择、供应链韧性与全球化布局的一次系统验证。从2021年发布第一款无边界智能割草', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-38340493270480653', '人工智能', '独家对谈｜兴辉时代创始人高兴辉，90后小镇女孩离开教培大厂，三年创造2亿GMV的倔强人生', 'https://36kr.com/p/3786265971334150?f=rss', '36kr', '2026-04-29', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  兴辉，山西人，三次面试新东方才被录用。\n  转战高途教育后，她与另外三名男同事一同被封为公司的“三王一后”。\n  如今她已自己创业近三年。带着对教培行业发展水温的好奇，我们拜访了兴辉的公司。\n  一进门，同事们喊她“辉哥”——这与她外表精瘦，笑起来有虎牙的形象相比，实在让人难以关联。\n  但当我们听到在整个教培行业最为', '人事变动可能影响公司战略方向。', 'person', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:16:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-4189898634130860607', '人工智能', '亚马逊云科技推出桌面AI助手Amazon Quick', 'https://36kr.com/newsflashes/3789015541439491?f=rss', '36Kr', '2026-04-30', '4月30日，亚马逊云科技宣布推出桌面AI助手Amazon Quick，将个人AI助手引入桌面。据介绍，用户能够直接在Amazon Quick中创建实时仪表板、智能应用、演示文稿和图片。Amazon Quick通过集成Google Workspace、Zoom、Microsoft 365以及Salesforce等，将应用、工具和数据汇聚一处，实现日常应用的一站式操作。（界面）', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 17:16:58', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-4207611386806492270', '人工智能', '8点1氪丨百度废除字母职级标签；Meta被曝准备撤销对Manus收购；张雪称曾拒绝了半个亿的商务合作', 'https://36kr.com/p/3787150633065728?f=rss', '36kr', '2026-04-29', '今日热点导览\n  阿联酋宣布将退出欧佩克及“欧佩克+”\n  比亚迪宣布5月1日起涨价\n  五粮液：延期披露年报、一季报\n  普通本科高校上新38种专业\n  全马“破2”跑鞋被炒至近2万元\n  韩股市值超越英国，成为全球第八大股市\n  TOP3大新闻\n  百度职级体系大调整：字母标签改为5级至12级数字职级体系\n  4月28日，据《科创板日报》，百度发布全员信，通知职级体系大调整，其将中管层以下的专', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:55:05', '2026-04-29 10:55:05', '2026-04-29 10:55:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-4226073143826552606', '人工智能', '最前线｜爱芯元智仇肖莘：大算力芯片将成为企业明年的主要增长引擎', 'https://36kr.com/p/3784806758243587?f=rss', '36kr', '2026-04-27', '在汽车行业越来越强调降本的今天，车企心中的天平逐渐偏向了更具性价比的国产芯片。爱芯元智看到了这一发展机遇，北京车展前期，爱芯元智与千里科技、阶跃星辰等企业成立“千里联盟”，同时企业将于今年三季��发布M97这颗大算力辅助驾驶芯片。\n  爱芯元智创始人仇肖莘在北京车展上公开表示，“大算力产品已成功流片，正进入正常的开发周期”，2026年将逐步导入多款车型，成为业绩增长的重要引擎。目前，传统终端计算产', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-4277649382711999637', '人工智能', '「优时科技」完成数亿元B2轮融资，从L4视觉自动驾驶延展至人形机器人，打造数据飞轮｜36氪首发', 'https://36kr.com/p/3788687934249989?f=rss', '36Kr', '2026-04-30', '一季度过去，具身智能行业的融资热潮还在继续。\n  36氪获悉，专注于L4低速自动驾驶的公司「优时科技」宣布完成数亿元人民币B2轮融资。本轮融资由前海方舟领投，前海母基金旗下多支基金参与，联同鲲翎资本、厚天资本等8家投资机构共同完成。\n  在此之前，「优时科技」已完成了6轮融资：\n  ·2018年6月，拿到&nbsp;PNP&nbsp;中国领投、北京汇丰投融、北京金种子和上海平阳复辉跟投的数百万人民', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:01:51', '2026-04-30 18:01:50', '2026-04-30 18:02:39', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-4337914910016808756', '机器人', '香港金管局：3月份港元货币供应量M2及M3同比均上升1.2%', 'https://36kr.com/newsflashes/3789083440061446?f=rss', '36Kr', '2026-04-30', '4月30日，香港金融管理局发表的统计数字显示，认可机构的存款总额在2026年3月份上升0.1%，其中港元存款上升0.7%，外币存款则下跌0.3%。2026年第1季，存款总额及港元存款分别上升1.0%及1.9%。香港人民币存款在3月份上升0.6%，于3月底为10,352亿元人民币。跨境贸易结算的人民币汇款总额于3月份为12,900亿元人民币，而2月份为8,665亿元人民币。存款变动受多项因素影响，包', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 17:17:46', '2026-04-30 17:17:46', '2026-04-30 17:17:46', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-4399154367081110481', '半导体', '8点1氪：中方禁止外资收购Manus；上海迪士尼回应游客吸烟冲突事件；泡泡玛特LABUBU 冰箱未发售已溢价3000元', 'https://36kr.com/p/3785730095127817?f=rss', '36kr', '2026-04-28', 'TOP3大新闻\n  DeepSeek 输入缓存降价\n  多家美国廉价航空公司寻求政府资金纾困\n  东方甄选回应大量用户申请退会员\n  穿西装开空调太费电，日本东京鼓励公务员穿短裤\n  印度移动支付平台MobiKwik获央行批准\n  TOP3大事件\n  国家发展改革委：依法依规对外资收购Manus项目作出禁止投资决定\n  据国家发展改革委网站4月27日消息，外商投资安全审查工作机制办公室（国家发展改', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:23:58', '2026-04-29 10:23:58', '2026-04-29 10:24:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-4416669239712055046', '人工智能', '氪星晚报｜五一假期约600万人次进出香港；谷歌将在韩国新建人工智能园区，韩国总统府证实；英国大型企业普遍不清楚自身数据在海外被人工智能如何使用', 'https://36kr.com/p/3784957482523648?f=rss', '36kr', '2026-04-27', '大公司：\n  谷歌将在韩国新建人工智能园区，韩国总统府证实\n  韩国总统政策顾问金龙范于周一表示，韩国政府与谷歌达成协议，将在首尔共建一座人工智能园区，深化谷歌与韩国本土技术人才、初创企业的合作。金龙范介绍，韩国总统李在明当日在首尔会见了谷歌深度思维（DeepMind）首席执行官德米斯・哈萨比斯。韩国科学技术部与谷歌就此人工智能园区项目签署了合作谅解备忘录。\n  法国汽车零部件供应商Forvia ', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-4512287295308919655', '人工智能', '8点1氪丨官方通报“霸王茶姬中喝出水银”；马斯克称创办OpenAI只为拯救人类；三星家族财富一年翻倍至3000亿跃居亚洲第三', 'https://36kr.com/p/3788573115735299?f=rss', '36Kr', '2026-04-30', '今日热点导览\n  \n   四大主播集体离职，东方甄选奖励300名员工超4亿元股份，人均超140万元\n   马斯克天价薪酬方案曝光，薪酬目标包括火星殖民以及太空数据中心建设\n   5月1日起北京禁飞禁售无人机，大疆在京门店4月29日将下架相关产品\n   朋友圈改版，腾讯客服表示会持续优化\n   8天预计发送旅客1.58亿人次，铁路 “五一”假期运输今天启动\n  \n  TOP 3大新闻\n  官方通报“', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:20', '2026-04-30 18:00:20', '2026-04-30 18:01:07', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-4623541858693290806', '人工智能', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 09:24:27', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-469858467568843514', '人工智能', '氪星晚报 ｜腾讯ima推出全新知识Agent——copilot；魔法原子：目标到2036年营收达140亿美元', 'https://36kr.com/p/3787748082293766?f=rss', '36Kr', '2026-04-29', '大公司：\n  魔法原子：目标到2036年营收达140亿美元\n  36氪获悉，美西时间4月28日，魔法原子在硅谷举办全球具身智能创新大会（GEIS）落幕。会上发布自研世界模型Magic-Mix、灵巧手MagicHand H01及旗舰人形机器人MagicBot X1。大会上，公司首次对外披露魔法原子的长期营收目标：到2036年，公司将向140亿美元营收规模迈进，并宣布未来五年将持续投入10亿美元，打造', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:41', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-4764768639237152147', '医疗健康', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:54:44', '2026-04-29 10:54:43', '2026-04-29 10:54:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-4786308338254175970', '新能源汽车', '欧莱雅一季度增长6.7%，中国区再现重大人事变动｜独家', 'https://36kr.com/p/3786192457063685?f=rss', '36Kr', '2026-04-30', '文｜贺哲馨\n  编辑｜乔芊\n  刚刚过去的一周，欧莱雅交出了一份超出市场预期的成绩单。\n  公司在2026年一季度实现销售额约121.5亿欧元，同比增长3.6%；在可比口径下（like-for-like），销售增长达到7.6%，经调整后为6.7%。 这一增速不仅高于此前市场普遍预期，财报发布次日，欧莱雅股价大涨9%，创下自2008年11月以来最大单日涨幅。\n  分品类看，四大事业部全部实现了增长，', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:02:32', '2026-04-30 18:02:31', '2026-04-30 18:02:31', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-4868803810980305550', '人工智能', '成大生物在上海成立医药科技新公司', 'https://36kr.com/newsflashes/3787272147016969?f=rss', '36kr', '2026-04-29', '36氪获悉，爱企查App显示，近日，上海成大致远医药科技有限公司成立，法定代表人为李业基，注册资本10亿元人民币，经营范围包括人工智能理论与算法软件开发、人工智能基础软件开发、人工智能应用软件开发、人工智能双创服务平台等。股东信息显示，该公司由辽宁成大生物股份有限公司全资持股。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:23:50', '2026-04-29 10:23:50', '2026-04-29 10:23:50', 0.5);
