INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-5065179745591388058', '人工智能', '用AI做IP，文娱科技公司星迹互动完成数千万元天使轮融资｜36氪融资首发', 'https://36kr.com/p/3784697499786503?f=rss', '36kr', '2026-04-28', '近期，数字科技文娱公司星迹互动完成了数千万元的天使轮融资。本轮投资方包括正大集团、北京大融文化传媒、禹牧智能以及麦迈科技等。36氪获悉，此次融资将主要用于公司人员规模的扩张、产能拉升以及平台建设。\n  星迹互动于2025年成立，以AI为核心驱动力，专注于精品IP的开发与运营。具体来讲，公司的业务包括新老IP的开发与运营、漫剧的承制与出海、儿童原创动画孵化，以及数字人IP与虚拟偶像的打造。\n  公司', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-5244329407015520654', '人工智能', 'HappyHorse没有惊喜', 'https://36kr.com/p/3789098887077123?f=rss', '36Kr', '2026-04-30', '作者&nbsp;|&nbsp;兰杰\n  编辑&nbsp;|&nbsp;乔芊\n  4月27日，预热已久的HappyHorse终于开启测试，颇为遗憾的是，它没能像横空出世的Seedance2.0那样掀起巨浪。没有惊喜，对于HappyHorse来讲是一个颇为中肯的评价。&nbsp;\n  HappyHorse是阿里巴巴ATH事业群旗下创新事业部研发的视频模型，于4月27日开启灰测，并接入千问App。\n  ', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:51', '2026-04-30 18:01:50', '2026-04-30 18:02:39', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-5277811368837111381', '人工智能', '「微滔生物」A轮次融资超5000万美元，LNP路线体内CAR-T已发表初步人体数据', 'https://36kr.com/p/3787339522432256?f=rss', '36Kr', '2026-04-30', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，微滔生物近日接连完成A轮及A+轮融资，累计募资金额超5000万美元。两轮融资分别由正心谷资本和德诚资本领投，OrbiMed（奥博资本）、汉康资本、卫材创新风投基金（Eisai Innovation Inc.）、建发新兴投资，以及老股东启明创投、顺禧基金、杏泽资本等跟投。\n  据了解，微滔生物的A轮次募集资金将主要用于推进核心药物管线GT801的临床进程', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:49', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-5594838990521745952', '人工智能', '8点1氪：中方禁止外资收购Manus；上海迪士尼回应游客吸烟冲突事件；泡泡玛特LABUBU 冰箱未发售已溢价3000元', 'https://36kr.com/p/3785730095127817?f=rss', '36kr', '2026-04-28', 'TOP3大新闻\n  DeepSeek 输入缓存降价\n  多家美国廉价航空公司寻求政府资金纾困\n  东方甄选回应大量用户申请退会员\n  穿西装开空调太费电，日本东京鼓励公务员穿短裤\n  印度移动支付平台MobiKwik获央行批准\n  TOP3大事件\n  国家发展改革委：依法依规对外资收购Manus项目作出禁止投资决定\n  据国家发展改革委网站4月27日消息，外商投资安全审查工作机制办公室（国家发展改', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-5714690529552478805', '医疗健康', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:23:56', '2026-04-29 10:23:55', '2026-04-29 10:23:58', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-5763093805502803034', '机器人', '风电产业链业绩分化，“两海”市场成胜负手', 'https://36kr.com/newsflashes/3787147629239555?f=rss', '36kr', '2026-04-29', '近日，风电产业链厂商2025年度业绩陆续出炉。过去一年，风电整机厂商营收普遍水涨船高，但利润分化明显。相比之下，齿轮箱、风电主轴、风电基础装备等上下游核心部件供应商业绩普遍高增长。总的来看，海外及海上“两海”业务占比高的厂商业绩要好于业务结构单一的厂商。因此，布局“两海”业务成为风电厂商共识。业内人士判断，海外和海上是中国风电产业发展的两个关键增量市场，其中，中国的海上风电已进入规模化开发阶段。（', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:46:04', '2026-04-29 08:46:04', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-582192918095474576', '机器人', '香港金管局：3月份港元货币供应量M2及M3同比均上升1.2%', 'https://36kr.com/newsflashes/3789083440061446?f=rss', '36Kr', '2026-04-30', '4月30日，香港金融管理局发表的统计数字显示，认可机构的存款总额在2026年3月份上升0.1%，其中港元存款上升0.7%，外币存款则下跌0.3%。2026年第1季，存款总额及港元存款分别上升1.0%及1.9%。香港人民币存款在3月份上升0.6%，于3月底为10,352亿元人民币。跨境贸易结算的人民币汇款总额于3月份为12,900亿元人民币，而2月份为8,665亿元人民币。存款变动受多项因素影响，包', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:01:07', '2026-04-30 18:01:07', '2026-04-30 18:01:07', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-5843254159571005290', '人工智能', '比博斯特完成超10亿元B轮融资，智能底盘三轴产品全覆盖｜36氪独家', 'https://36kr.com/p/3740907027054600?f=rss', '36kr', '2026-04-29', '36氪独家获悉，智能底盘企业比博斯特近日完成B+轮融资，由浙江省新能源汽车产业基金领投，顺创产投、杭资直投基金等联合投资。企业B+轮融资超7亿元，B轮系列融资总额已超10亿元。本轮融资将用于已有产品的规模化增长及前沿产品的开发。\n  比博斯特成立于2021年，其股东不仅包括主机厂蔚来，还涵盖恒隆、保隆等汽车底盘供应链头部企业。2025年，曾在底盘巨头采埃孚担任高管的巫子平、郁炜陆续加入比博斯特，出', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 09:24:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-5852265297060820303', '人工智能', 'Alphabet CFO：将2026年资本支出指引区间上调至1800亿-1900亿美元', 'https://36kr.com/newsflashes/3788932325235716?f=rss', '36Kr', '2026-04-30', 'Alphabet首席财务官阿纳特・阿什肯纳齐在财报电话会上表示，投资方面，我们将2026年全年资本支出指引区间上调至1800亿至1900亿美元，此前预期为1750亿至1850亿美元，新增3月完成的Intersect收购相关投资。我们看到人工智能计算资源的内部与外部需求空前高涨。我们在人工智能领域的投资正带来强劲增长，谷歌云创纪录的收入与订单储备增长、谷歌服务的优异表现均印证了这一点。展望未来，这些', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 16:47:35', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-6121680997038393384', '半导体', '多地银行加速旗下村镇银行整合重组', 'https://36kr.com/newsflashes/3787165643070723?f=rss', '36kr', '2026-04-29', '今年以来，多家银行加速旗下村镇银行减量提质改革，“村并村”“村改支”等整合重组案例密集落地，行业改革持续提速。苏商银行特约研究员高政扬对记者表示，当前中小金融机构改革有序推进。针对部分中小银行治理不完善、风控能力薄弱、抗风险水平不足等痛点，监管部门持续压实各方主体责任，引导行业通过兼并重组优化组织架构，稳妥化解存量风险。本轮整合重组改革，有助于筑牢区域金融安全防线，优化县域金融服务布局，持续增强金', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:46:01', '2026-04-29 08:46:00', '2026-04-29 08:46:00', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-6151243499293259776', '人工智能', 'Bug频出，官方致歉：《异环》能跳出《幻塔》的剧本吗？', 'https://36kr.com/p/3787956437179395?f=rss', '36Kr', '2026-04-30', '文丨贝果树\n  编辑丨果脯、刘士武\n  4月28日，距离游戏公测仅过5天，《异环》官方就不得不发布一篇正式的道歉信，以回应游戏在玩家群体间面临的诸多质疑与争议。\n  信中，官方公布了后续针对叙事、玩法、游戏Bug等功能的后续优化计划，并向全体玩家发放自选S级常驻角色作为补偿。\n  \n  《异环》官方发布道歉信\n  没办法，尽管现如今大家都说“开服没有争议的二游不是好二游”，但公测后的《异环》，暴露', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:49', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-6249651594192147459', '人工智能', '独家对谈｜兴辉时代创始人高兴辉，90后小镇女孩离开教培大厂，三年创造2亿GMV的倔强人生', 'https://36kr.com/p/3786265971334150?f=rss', '36kr', '2026-04-29', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  兴辉，山西人，三次面试新东方才被录用。\n  转战高途教育后，她与另外三名男同事一同被封为公司的“三王一后”。\n  如今她已自己创业近三年。带着对教培行业发展水温的好奇，我们拜访了兴辉的公司。\n  一进门，同事们喊她“辉哥”——这与她外表精瘦，笑起来有虎牙的形象相比，实在让人难以关联。\n  但当我们听到在整个教培行业最为', '人事变动可能影响公司战略方向。', 'person', 0.5, '2026-04-29 10:55:05', '2026-04-29 10:55:05', '2026-04-29 10:55:25', 0.5);
