INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-6257456812612549296', '人工智能', '第20届中国投资年会圆满闭幕！ “K型曲线”下，寻找穿越分化的确定性', 'https://36kr.com/p/3787806140636420?f=rss', '36Kr', '2026-04-29', '2026年4月22日至24日，第20届中国投资年会·年度峰会于北京海淀盛大召开。本届大会以“K型曲线”为主题，由北京市海淀区人民政府指导，投中信息、投中网主办，北京中关村科学城创新发展有限公司协办。本届年会连续第二年扎根北京海淀，双方合作正从初次携手走向深度融合。超千名行业领袖、投资人及创业者齐聚海淀，共同研判中国私募股权市场的结构性变局。\n  群贤毕至，重磅嘉宾阵容\n  大会嘉宾阵容星光熠熠，政', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 16:47:35', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-6301064565916119209', '人工智能', '36氪首发 | 韩国现代、微光创投押注焊接机器人，营收预计破数亿，拿下船厂数千万订单', 'https://36kr.com/p/3785955616152839?f=rss', '36kr', '2026-04-28', '作者丨欧雪\n  编辑丨袁斯来\n  硬氪获悉，专注于焊接垂直场景的具身智能机器人公司——昇视唯盛已完成数千万元A+轮融资。本轮融资由韩国现代、微光创投联合投资，资金将主要用于“具身大脑”的研发、软硬件产品的迭代以及市场推广。\n  昇视唯盛成立于2020年，核心团队由来自哈尔滨工业大学、上海交通大学等高校的机器人领域专家，以及拥有多年工业自动化从业经验的资深人员组成。创始人王德钊及核心团队在机器人及自', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-6362990918198722067', '新能源汽车', '加州海岸委员会向马斯克和SpaceX致歉，承诺未来监管决策不考虑政治因素', 'https://36kr.com/newsflashes/3787173820619785?f=rss', '36kr', '2026-04-29', '根据电动汽车分析师索耶·梅瑞特在X上分享的消息，美国加州海岸委员会已向加州海岸委员会已向埃隆·马斯克和 SpaceX公司正式道歉，并承诺未来在监管决策中不会考虑政治观点或言论。马斯克转发了梅瑞特的这篇帖子。梅瑞特评论称：“这份文件意味着 SpaceX和加州海岸委员会已就其联邦诉讼达成和解，并为SpaceX未来的猎鹰9号火箭发射提供了长期的监管清晰度。”（新浪财经）', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:23', '2026-04-29 09:24:22', '2026-04-29 09:24:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-6400105909331206160', '人工智能', '用AI做IP，文娱科技公司星迹互动完成数千万元天使轮融资｜36氪融资首发', 'https://36kr.com/p/3784697499786503?f=rss', '36kr', '2026-04-28', '近期，数字科技文娱公司星迹互动完成了数千万元的天使轮融资。本轮投资方包括正大集团、北京大融文化传媒、禹牧智能以及麦迈科技等。36氪获悉，此次融资将主要用于公司人员规模的扩张、产能拉升以及平台建设。\n  星迹互动于2025年成立，以AI为核心驱动力，专注于精品IP的开发与运营。具体来讲，公司的业务包括新老IP的开发与运营、漫剧的承制与出海、儿童原创动画孵化，以及数字人IP与虚拟偶像的打造。\n  公司', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-6555710364313227345', '人工智能', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-6584812518188946179', '人工智能', '8点1氪：中方禁止外资收购Manus；上海迪士尼回应游客吸烟冲突事件；泡泡玛特LABUBU 冰箱未发售已溢价3000元', 'https://36kr.com/p/3785730095127817?f=rss', '36kr', '2026-04-28', 'TOP3大新闻\n  DeepSeek 输入缓存降价\n  多家美国廉价航空公司寻求政府资金纾困\n  东方甄选回应大量用户申请退会员\n  穿西装开空调太费电，日本东京鼓励公务员穿短裤\n  印度移动支付平台MobiKwik获央行批准\n  TOP3大事件\n  国家发展改革委：依法依规对外资收购Manus项目作出禁止投资决定\n  据国家发展改革委网站4月27日消息，外商投资安全审查工作机制办公室（国家发展改', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:14', '2026-04-29 09:33:14', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-6693036572413765259', '人工智能', '白宫据悉正在研讨恢复与Anthropic合作', 'https://36kr.com/newsflashes/3787275928411395?f=rss', '36kr', '2026-04-29', '据知情人士透露，白宫正在制定指导方针，允许各机构绕过对Anthropic的供应链风险的认定，并引入包括其迄今为止最强大的Mythos在内的新模型。两位消息人士称，目前正在起草的一项行政命令草案，除其他与政府使用人工智能相关的措施外，可能还会为政府提供一种缓和与Anthropic公司对抗的途径。（新浪财经）', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:54:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-6792418160954771656', '人工智能', '“36氪企业全情报”官方股票舆情交流社群，正式开放招募！', 'https://36kr.com/p/3787661080714497?f=rss', '36Kr', '2026-04-29', '36氪企业全情报官方专属社群现已正式对外开放，正式打造唯一官方股票舆情情报社群，面向所有股民、理财爱好者、个股深度研究者，适配不同投资风格与交易节奏，帮你高效拿捏舆情风向、把握行情先机。\n  从股市舆情解读、个股情报拆解，到行情逻辑分析、投资干货交流，一站式帮投资者告别信息滞后、看懂涨跌本质。\n  \n  扫码进入：“36氪企业全情报”官方股票舆情交流社群\n  为什么要做专属股票舆', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-6846463960806099961', '人工智能', '氪星晚报｜澳门一季度GDP按年实质增长7.1%；小红书发内部信：加大AI投入，柯南出任总裁', 'https://36kr.com/p/3789059666173189?f=rss', '36Kr', '2026-04-30', '大公司：\n  联发科一季度毛利率为46.3%，同比下滑1.8个百分点\n  4月30日，联发科举行法说会并公布2026年第一季度财报，单季每股盈余（EPS）为新台币15.17元，环比增加5.6%、同比减少17.4%；合并营收为新台币1491.51亿元，环比减少0.7%、同比减少2.7%；毛利率为46.3%，环比增加0.2个百分点，同比下滑1.8个百分点。公司表示，毛利率季增主要受惠产品组合优化，年减', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:51', '2026-04-30 18:01:50', '2026-04-30 18:02:39', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-6907922783603705646', '半导体', '恒指收跌1.28%，恒生科技指数跌0.79%', 'https://36kr.com/newsflashes/3789039716080900?f=rss', '36Kr', '2026-04-30', '36氪获悉，恒指收跌1.28%，恒生科技指数跌0.79%；汽车、传媒、软件服务板块领跌，蔚来跌超6%，比亚迪股份跌超5%，腾讯音乐跌超4%，小米集团、阿里巴巴跌超3%；半导体、机械板块走强，中芯国际涨超7%，潍柴动力涨超6%；南向资金净买入121.92亿港元。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:22', '2026-04-30 16:46:21', '2026-04-30 16:46:21', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-7015696674222783378', '人工智能', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:14', '2026-04-29 09:33:14', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-7074088631742800557', '半导体', '8点1氪：中方禁止外资收购Manus；上海迪士尼回应游客吸烟冲突事件；泡泡玛特LABUBU 冰箱未发售已溢价3000元', 'https://36kr.com/p/3785730095127817?f=rss', '36kr', '2026-04-28', 'TOP3大新闻\n  DeepSeek 输入缓存降价\n  多家美国廉价航空公司寻求政府资金纾困\n  东方甄选回应大量用户申请退会员\n  穿西装开空调太费电，日本东京鼓励公务员穿短裤\n  印度移动支付平台MobiKwik获央行批准\n  TOP3大事件\n  国家发展改革委：依法依规对外资收购Manus项目作出禁止投资决定\n  据国家发展改革委网站4月27日消息，外商投资安全审查工作机制办公室（国家发展改', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:47', '2026-04-29 10:54:47', '2026-04-29 10:54:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-7129300612449399474', '人工智能', '「微滔生物」A轮次融资超5000万美元，LNP路线体内CAR-T已发表初步人体数据', 'https://36kr.com/p/3787339522432256?f=rss', '36Kr', '2026-04-30', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，微滔生物近日接连完成A轮及A+轮融资，累计募资金额超5000万美元。两轮融资分别由正心谷资本和德诚资本领投，OrbiMed（奥博资本）、汉康资本、卫材创新风投基金（Eisai Innovation Inc.）、建发新兴投资，以及老股东启明创投、顺禧基金、杏泽资本等跟投。\n  据了解，微滔生物的A轮次募集资金将主要用于推进核心药物管线GT801的临床进程', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 17:17:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-7529662893495587614', '人工智能', '欧盟《数字市场法》监管范围拟扩大至云服务与AI领域', 'https://36kr.com/newsflashes/3787149562682627?f=rss', '36kr', '2026-04-29', '欧盟监管机构周二表示，计划将其旨在遏制大型科技公司权力的里程碑式法规《数字市场法》的监管重点转向云服务和人工智能领域。此举旨在促进公平竞争，此前该法已在其他数字领域取得了积极成效。（新浪财经）', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-7552417254928772781', '人工智能', '「优时科技」完成数亿元B2轮融资，从L4视觉自动驾驶延展至人形机器人，打造数据飞轮｜36氪首发', 'https://36kr.com/p/3788687934249989?f=rss', '36Kr', '2026-04-30', '一季度过去，具身智能行业的融资热潮还在继续。\n  36氪获悉，专注于L4低速自动驾驶的公司「优时科技」宣布完成数亿元人民币B2轮融资。本轮融资由前海方舟领投，前海母基金旗下多支基金参与，联同鲲翎资本、厚天资本等8家投资机构共同完成。\n  在此之前，「优时科技」已完成了6轮融资：\n  ·2018年6月，拿到&nbsp;PNP&nbsp;中国领投、北京汇丰投融、北京金种子和上海平阳复辉跟投的数百万人民', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:00:20', '2026-04-30 18:00:20', '2026-04-30 18:01:07', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-7583475555313283386', '人工智能', '苹果计划在iOS 27中借助AI对照片编辑功能进行全面升级', 'https://36kr.com/newsflashes/3787148066593798?f=rss', '36kr', '2026-04-29', '当地时间4月28日，据报道，苹果公司正计划对iPhone、iPad和Mac的内置照片编辑功能进行重大升级，并深度依托人工智能技术，以此缩小与安卓设备的竞争差距。据知情人士透露，该公司正在为计划于今年秋季发布的iOS 27、iPadOS 27和macOS 27开发一套由Apple Intelligence平台驱动的新工具套件。这些功能将允许用户利用设备端的AI模型对图片进行扩展、增强和重新构图。知情', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-7923239350867565126', '人工智能', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-7926329963740796073', '人工智能', '“小长假”前一天北京拍地91.597亿，最贵楼面价超6万', 'https://36kr.com/p/3789084813548803?f=rss', '36Kr', '2026-04-30', '4月最后一天，北京楼市迎来一次春季土拍盛宴，分别位于朝阳东坝、丰台万泉寺、昌平北七家的三宗宅地成交，总价合计91.597亿元。\n  2026年1-4月，北京合计出让住宅用地13宗（2025年同期成交7宗），总成交价为217.577亿元（2025年同期成交约334.9亿元），相比去年同期有约35%的金额降幅。\n  但今年1-4月成交宅地规划总建面约83.7万㎡，与去年同期成交总建面82.2万㎡的总量', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 17:16:59', '2026-04-30 17:16:58', '2026-04-30 17:17:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-7954746701342726314', '半导体', '可回收火箭密集验证窗口开启，商业航天产业链有望迈入规模化量产元年', 'https://36kr.com/newsflashes/3787190594558981?f=rss', '36kr', '2026-04-29', '4月下旬，中国商业航天迎来可回收火箭密集验证窗口。长征十号乙、朱雀三号等多型火箭接连实施回收技术验证，国家《商业航天标准体系（1.0版）》同步落地。在产业政策与核心技术共振之下，A股产业链公司一季报业绩兑现亮眼。Wind数据显示，万得商业航天概念指数近期表现不俗，4月7日以来累计上涨6.51%。分析人士认为，可回收技术的工程化落地将推动发射成本指数级下降，叠加政策标准体系的顶层引导，商业航天正从技', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:23:58', '2026-04-29 10:23:58', '2026-04-29 10:23:58', 0.5);
