INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8001470161226155439', '新能源汽车', '恒指开盘涨0.63%，恒生科技指数涨1.07%', 'https://36kr.com/newsflashes/3787224093023490?f=rss', '36kr', '2026-04-29', '36氪获悉，恒指开盘涨0.63%，恒生科技指数涨1.07%；科技、汽车股走强，蔚来、京东健康涨超4%，理想汽车涨超3%，小鹏集团、哔哩哔哩涨超2%；有色金属、煤炭板块调整，五矿资源、中煤能源跌超1%；新股商米科技高开292.20%。', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:54:53', '2026-04-29 10:54:53', '2026-04-29 10:54:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-8090682089719640657', '人工智能', '第20届中国投资年会圆满闭幕！ “K型曲线”下，寻找穿越分化的确定性', 'https://36kr.com/p/3787806140636420?f=rss', '36Kr', '2026-04-29', '2026年4月22日至24日，第20届中国投资年会·年度峰会于北京海淀盛大召开。本届大会以“K型曲线”为主题，由北京市海淀区人民政府指导，投中信息、投中网主办，北京中关村科学城创新发展有限公司协办。本届年会连续第二年扎根北京海淀，双方合作正从初次携手走向深度融合。超千名行业领袖、投资人及创业者齐聚海淀，共同研判中国私募股权市场的结构性变局。\n  群贤毕至，重磅嘉宾阵容\n  大会嘉宾阵容星光熠熠，政', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-8103394282422222281', '机器人', '国家医保局：1到3月职工医保个人账户共济1.15亿人次', 'https://36kr.com/newsflashes/3789098027293699?f=rss', '36Kr', '2026-04-30', '国家医保局消息，今年1到3月职工医保个人账户共济1.15亿人次，金额153.24亿元。职工医保个人账户资金可用于被共济的近亲属在定点医药机构发生的由个人负担的医药费用，以及参加居民基本医保、长期护理保险的个人缴费。目前，职工医保个人账户共济可以通过即时调用被绑定人个人账户、医保钱包等方式实现。（央视新闻）', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:01:07', '2026-04-30 18:01:07', '2026-04-30 18:01:16', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8156855546689934303', '人工智能', '8点1氪丨百度废除字母职级标签；Meta被曝准备撤销对Manus收购；张雪称曾拒绝了半个亿的商务合作', 'https://36kr.com/p/3787150633065728?f=rss', '36kr', '2026-04-29', '今日热点导览\n  阿联酋宣布将退出欧佩克及“欧佩克+”\n  比亚迪宣布5月1日起涨价\n  五粮液：延期披露年报、一季报\n  普通本科高校上新38种专业\n  全马“破2”跑鞋被炒至近2万元\n  韩股市值超越英国，成为全球第八大股市\n  TOP3大新闻\n  百度职级体系大调整：字母标签改为5级至12级数字职级体系\n  4月28日，据《科创板日报》，百度发布全员信，通知职级体系大调整，其将中管层以下的专', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:13', '2026-04-29 09:33:13', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8382199212069777980', '人工智能', '8点1氪：中方禁止外资收购Manus；上海迪士尼回应游客吸烟冲突事件；泡泡玛特LABUBU 冰箱未发售已溢价3000元', 'https://36kr.com/p/3785730095127817?f=rss', '36kr', '2026-04-28', 'TOP3大新闻\n  DeepSeek 输入缓存降价\n  多家美国廉价航空公司寻求政府资金纾困\n  东方甄选回应大量用户申请退会员\n  穿西装开空调太费电，日本东京鼓励公务员穿短裤\n  印度移动支付平台MobiKwik获央行批准\n  TOP3大事件\n  国家发展改革委：依法依规对外资收购Manus项目作出禁止投资决定\n  据国家发展改革委网站4月27日消息，外商投资安全审查工作机制办公室（国家发展改', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 09:24:27', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8390697756116544540', '人工智能', '比博斯特完成超10亿元B轮融资，智能底盘三轴产品全覆盖｜36氪独家', 'https://36kr.com/p/3740907027054600?f=rss', '36kr', '2026-04-29', '36氪独家获悉，智能底盘企业比博斯特近日完成B+轮融资，由浙江省新能源汽车产业基金领投，顺创产投、杭资直投基金等联合投资。企业B+轮融资超7亿元，B轮系列融资总额已超10亿元。本轮融资将用于已有产品的规模化增长及前沿产品的开发。\n  比博斯特成立于2021年，其股东不仅包括主机厂蔚来，还涵盖恒隆、保隆等汽车底盘供应链头部企业。2025年，曾在底盘巨头采埃孚担任高管的巫子平、郁炜陆续加入比博斯特，出', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:54:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8532692687367786623', '半导体', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:54:47', '2026-04-29 10:54:47', '2026-04-29 10:54:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8578656282512573895', '人工智能', '氪星晚报｜五一假期约600万人次进出香港；谷歌将在韩国新建人工智能园区，韩国总统府证实；英国大型企业普遍不清楚自身数据在海外被人工智能如何使用', 'https://36kr.com/p/3784957482523648?f=rss', '36kr', '2026-04-27', '大公司：\n  谷歌将在韩国新建人工智能园区，韩国总统府证实\n  韩国总统政策顾问金龙范于周一表示，韩国政府与谷歌达成协议，将在首尔共建一座人工智能园区，深化谷歌与韩国本土技术人才、初创企业的合作。金龙范介绍，韩国总统李在明当日在首尔会见了谷歌深度思维（DeepMind）首席执行官德米斯・哈萨比斯。韩国科学技术部与谷歌就此人工智能园区项目签署了合作谅解备忘录。\n  法国汽车零部件供应商Forvia ', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-8624351803974838557', '人工智能', '8点1氪丨官方通报“霸王茶姬中喝出水银”；马斯克称创办OpenAI只为拯救人类；三星家族财富一年翻倍至3000亿跃居亚洲第三', 'https://36kr.com/p/3788573115735299?f=rss', '36Kr', '2026-04-30', '今日热点导览\n  \n   四大主播集体离职，东方甄选奖励300名员工超4亿元股份，人均超140万元\n   马斯克天价薪酬方案曝光，薪酬目标包括火星殖民以及太空数据中心建设\n   5月1日起北京禁飞禁售无人机，大疆在京门店4月29日将下架相关产品\n   朋友圈改版，腾讯客服表示会持续优化\n   8天预计发送旅客1.58亿人次，铁路 “五一”假期运输今天启动\n  \n  TOP 3大新闻\n  官方通报“', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 17:17:46', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8671452078777086279', '人工智能', '比博斯特完成超10亿元B轮融资，智能底盘三轴产品全覆盖｜36氪独家', 'https://36kr.com/p/3740907027054600?f=rss', '36kr', '2026-04-29', '36氪独家获悉，智能底盘企业比博斯特近日完成B+轮融资，由浙江省新能源汽车产业基金领投，顺创产投、杭资直投基金等联合投资。企业B+轮融资超7亿元，B轮系列融资总额已超10亿元。本轮融资将用于已有产品的规模化增长及前沿产品的开发。\n  比博斯特成立于2021年，其股东不仅包括主机厂蔚来，还涵盖恒隆、保隆等汽车底盘供应链头部企业。2025年，曾在底盘巨头采埃孚担任高管的巫子平、郁炜陆续加入比博斯特，出', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:23:50', '2026-04-29 10:23:50', '2026-04-29 10:24:10', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8701229578457672944', '元宇宙', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:23:53', '2026-04-29 10:23:53', '2026-04-29 10:24:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8761193694572405204', '人工智能', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 09:24:27', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-8768854672427958309', '人工智能', '别急着All-in DeepSeek V4，先看看这10位从业者的真心话', 'https://36kr.com/p/3788151000751364?f=rss', '36Kr', '2026-04-29', '文｜周鑫雨 王毓婵\n  编辑｜杨轩\n  解读DeepSeek V4的技术报告，是这几天AI行业最狂热的集体活动。\n  V4很强吗？在工程优化的维度中，答案是毋庸置疑的。过去，大家信奉“Scaling Law的暴力美学”——也就是靠堆更多优质算力、更大参数规模来提升模型性能。而V4走的是一条完全不同的路，它定义了一种“模型训练的克制美学”：\n  它不靠疯狂堆算力和参数，而是通过一系列组合优化和重构：', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 17:17:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-8793267388551993222', '半导体', '可回收火箭密集验证窗口开启，商业航天产业链有望迈入规模化量产元年', 'https://36kr.com/newsflashes/3787190594558981?f=rss', '36kr', '2026-04-29', '4月下旬，中国商业航天迎来可回收火箭密集验证窗口。长征十号乙、朱雀三号等多型火箭接连实施回收技术验证，国家《商业航天标准体系（1.0版）》同步落地。在产业政策与核心技术共振之下，A股产业链公司一季报业绩兑现亮眼。Wind数据显示，万得商业航天概念指数近期表现不俗，4月7日以来累计上涨6.51%。分析人士认为，可回收技术的工程化落地将推动发射成本指数级下降，叠加政策标准体系的顶层引导，商业航天正从技', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:16:48', '2026-04-29 10:16:47', '2026-04-29 10:16:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-8905412988690868056', '半导体', '恒指收跌1.28%，恒生科技指数跌0.79%', 'https://36kr.com/newsflashes/3789039716080900?f=rss', '36Kr', '2026-04-30', '36氪获悉，恒指收跌1.28%，恒生科技指数跌0.79%；汽车、传媒、软件服务板块领跌，蔚来跌超6%，比亚迪股份跌超5%，腾讯音乐跌超4%，小米集团、阿里巴巴跌超3%；半导体、机械板块走强，中芯国际涨超7%，潍柴动力涨超6%；南向资金净买入121.92亿港元。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:47:20', '2026-04-30 16:47:20', '2026-04-30 17:17:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-8939220775092154440', '人工智能', 'Alphabet CFO：将2026年资本支出指引区间上调至1800亿-1900亿美元', 'https://36kr.com/newsflashes/3788932325235716?f=rss', '36Kr', '2026-04-30', 'Alphabet首席财务官阿纳特・阿什肯纳齐在财报电话会上表示，投资方面，我们将2026年全年资本支出指引区间上调至1800亿至1900亿美元，此前预期为1750亿至1850亿美元，新增3月完成的Intersect收购相关投资。我们看到人工智能计算资源的内部与外部需求空前高涨。我们在人工智能领域的投资正带来强劲增长，谷歌云创纪录的收入与订单储备增长、谷歌服务的优异表现均印证了这一点。展望未来，这些', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:41', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-8967133717579299759', '人工智能', '不谈空话，谈合作丨这场AI+产业对接会只聊落地', 'https://36kr.com/p/3788996733803782?f=rss', '36Kr', '2026-04-30', '\n  \n  “世界咖啡”[AI+]产业对接会正式定档北京亦庄。\n  <img src=\"https://', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:00:20', '2026-04-30 18:00:20', '2026-04-30 18:01:07', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-9079278678269471108', '机器人', '港股IPO热潮中的中资券商：保荐数量与市场份额领跑', 'https://36kr.com/newsflashes/3787179604679683?f=rss', '36kr', '2026-04-29', '2025年港股IPO市场强势复苏，全年新股上市数量与募资规模双双攀升，募资总额接近2900亿港元，时隔4年重回全球榜首。进入2026年，已有47家企业成功赴港上市，合计募资接近1400亿港元，且当前排队企业多达434家。综合来看，港股IPO业务呈现三大鲜明特征：A股企业赴港上市持续升温，硬科技与生物医药成为主力赛道；中资券商保荐数量与市场份额大幅领先，头部机构加速布局海外投行生态；项目储备持续饱满', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:25', '2026-04-29 09:24:25', '2026-04-29 09:24:27', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-957785418092703717', '人工智能', '8点1氪：中方禁止外资收购Manus；上海迪士尼回应游客吸烟冲突事件；泡泡玛特LABUBU 冰箱未发售已溢价3000元', 'https://36kr.com/p/3785730095127817?f=rss', '36kr', '2026-04-28', 'TOP3大新闻\n  DeepSeek 输入缓存降价\n  多家美国廉价航空公司寻求政府资金纾困\n  东方甄选回应大量用户申请退会员\n  穿西装开空调太费电，日本东京鼓励公务员穿短裤\n  印度移动支付平台MobiKwik获央行批准\n  TOP3大事件\n  国家发展改革委：依法依规对外资收购Manus项目作出禁止投资决定\n  据国家发展改革委网站4月27日消息，外商投资安全审查工作机制办公室（国家发展改', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_-975274135136708355', '人工智能', '独家对谈｜兴辉时代创始人高兴辉，90后小镇女孩离开教培大厂，三年创造2亿GMV的倔强人生', 'https://36kr.com/p/3786265971334150?f=rss', '36kr', '2026-04-29', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  兴辉，山西人，三次面试新东方才被录用。\n  转战高途教育后，她与另外三名男同事一同被封为公司的“三王一后”。\n  如今她已自己创业近三年。带着对教培行业发展水温的好奇，我们拜访了兴辉的公司。\n  一进门，同事们喊她“辉哥”——这与她外表精瘦，笑起来有虎牙的形象相比，实在让人难以关联。\n  但当我们听到在整个教培行业最为', '人事变动可能影响公司战略方向。', 'person', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:54:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_-996793671025724430', '半导体', '石英股份：光纤业务目前产能利用率较高，订单情况良好', 'https://36kr.com/newsflashes/3789103950765313?f=rss', '36Kr', '2026-04-30', '36氪获悉，石英股份公告，2026年一季度公司实现营收2.56亿元，同比小幅增长，其中光伏业务阶段性承压，光纤半导体业务收入占比延续增长态势。光纤业务按市场订单动态排产，目前产能利用率较高、订单情况良好。公司已形成年产10万吨高纯石英砂整体产能，半导体石英材料三期项目中年产6万吨高纯石英砂生产线已建成投产。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 17:17:22', '2026-04-30 17:17:22', '2026-04-30 17:17:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_1112424505265078969', '人工智能', '前米哈游高管创业，AI 原生增长 Agent LeapMind Growth 获 CMC 资本领投', 'https://36kr.com/p/3786123369094405?f=rss', '36kr', '2026-04-29', '\n  2026 年 4 月 29&nbsp;日，上海讯 ——AI 原生增长 Agent LeapMind Growth&nbsp;今日宣布完成天使 + 轮融资，由 CMC 资本领投。本轮融资将主要用于核心产品 GrowthGPT 的研发迭代、产研团队扩充及早期市场拓展。\n  LeapMind Growth 成立于 2025 年 4 月，由前米哈游全球用户增长负责人、前快手增长策略中心负责人马如平（', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 09:24:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_1115884655398479693', '机器人', '业内人士：厄尔尼诺现象最早或年中出现，关注农产品市场结构性机遇', 'https://36kr.com/newsflashes/3787140499184640?f=rss', '36kr', '2026-04-29', '日前，世界气象组织等多家权威机构联合预警，厄尔尼诺现象可能最早于2026年5月至7月正式登场，且大概率发展为中等及以上强度并持续至年底。这一气候异常现象将重构全球降水与气温分布模式，对全球农业生产造成显著冲击。业内人士表示，当前农产品期货价格已受市场预期带动提前异动，随着厄尔尼诺现象预期逐步兑现，农产品市场的结构性机遇将进一步释放，可关注天然橡胶、棕榈油以及白糖等品种多头机会。（中证网）', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:46:04', '2026-04-29 08:46:04', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_1337167228121455973', '元宇宙', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:16:42', '2026-04-29 10:16:42', '2026-04-29 10:16:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_1360796257388444096', '人工智能', '2025年我国全年词元累计调用量达21100万亿，日均调用量呈指数级增长', 'https://36kr.com/newsflashes/3787291440831488?f=rss', '36kr', '2026-04-29', '今天，《全国数据资源调查报告（2025年）》在第九届数字中国建设峰会上发布，报告显示，我国数据资源正以更大力度，赋能人工智能创新发展。“词元”（Token），是人工智能大模型为了高效处理数据，把数据进行拆分后的最小信息单元。2025年，全国日均词元调用量从年初的超万亿增长到年末的100万亿，呈现指数级增长；全年词元累计调用量达到约21100万亿。（央视新闻）', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:54:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_1452348108502335898', '人工智能', '“擎天租”完成数亿元Pre-A轮融资', 'https://36kr.com/newsflashes/3787289802939395?f=rss', '36kr', '2026-04-29', '4月29日，“擎天租”宣布完成数亿元Pre-A轮融资。本轮投资方包括正大集团旗下正大机器人、长信股份等产业方，美格智能、蓝思科技等多家上市公司参与，老股东明嘉资本、知行投资和睿资创投超额认购。融资资金将主要用于全国履约服务网络建设、机器人资产与调度系统升级、物流保险体系完善、标准化场景产品打磨及全球化服务网络拓展。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:54:56', 0.5);
