INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_1571384454386453467', '人工智能', '“小长假”前一天北京拍地91.597亿，最贵楼面价超6万', 'https://36kr.com/p/3789084813548803?f=rss', '36Kr', '2026-04-30', '4月最后一天，北京楼市迎来一次春季土拍盛宴，分别位于朝阳东坝、丰台万泉寺、昌平北七家的三宗宅地成交，总价合计91.597亿元。\n  2026年1-4月，北京合计出让住宅用地13宗（2025年同期成交7宗），总成交价为217.577亿元（2025年同期成交约334.9亿元），相比去年同期有约35%的金额降幅。\n  但今年1-4月成交宅地规划总建面约83.7万㎡，与去年同期成交总建面82.2万㎡的总量', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:51', '2026-04-30 18:01:50', '2026-04-30 18:02:16', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_1602313235441549972', '人工智能', 'HappyHorse没有惊喜', 'https://36kr.com/p/3789098887077123?f=rss', '36Kr', '2026-04-30', '作者&nbsp;|&nbsp;兰杰\n  编辑&nbsp;|&nbsp;乔芊\n  4月27日，预热已久的HappyHorse终于开启测试，颇为遗憾的是，它没能像横空出世的Seedance2.0那样掀起巨浪。没有惊喜，对于HappyHorse来讲是一个颇为中肯的评价。&nbsp;\n  HappyHorse是阿里巴巴ATH事业群旗下创新事业部研发的视频模型，于4月27日开启灰测，并接入千问App。\n  ', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 17:16:59', '2026-04-30 17:16:58', '2026-04-30 17:17:46', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_1739610812499250894', '人工智能', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:14', '2026-04-29 09:33:14', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_1787569992093949921', '人工智能', '最前线｜爱芯元智仇肖莘：大算力芯片将成为企业明年的主要增长引擎', 'https://36kr.com/p/3784806758243587?f=rss', '36kr', '2026-04-27', '在汽车行业越来越强调降本的今天，车企心中的天平逐渐偏向了更具性价比的国产芯片。爱芯元智看到了这一发展机遇，北京车展前期，爱芯元智与千里科技、阶跃星辰等企业成立“千里联盟”，同时企业将于今年三季度发布M97这颗大算力辅助驾驶芯片。\n  爱芯元智创始人仇肖莘在北京车展上公开表示，“大算力产品已成功流片，正进入正常的开发周期”，2026年将逐步导入多款车型，成为业绩增长的重要引擎。目前，传统终端计算产品', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_1804502522474460535', '机器人', '港股IPO热潮中的中资券商：保荐数量与市场份额领跑', 'https://36kr.com/newsflashes/3787179604679683?f=rss', '36kr', '2026-04-29', '2025年港股IPO市场强势复苏，全年新股上市数量与募资规模双双攀升，募资总额接近2900亿港元，时隔4年重回全球榜首。进入2026年，已有47家企业成功赴港上市，合计募资接近1400亿港元，且当前排队企业多达434家。综合来看，港股IPO业务呈现三大鲜明特征：A股企业赴港上市持续升温，硬科技与生物医药成为主力赛道；中资券商保荐数量与市场份额大幅领先，头部机构加速布局海外投行生态；项目储备持续饱满', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:24:11', '2026-04-29 10:24:11', '2026-04-29 10:24:11', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_1913707523488530019', '人工智能', '前米哈游高管创业，AI 原生增长 Agent LeapMind Growth 获 CMC 资本领投', 'https://36kr.com/p/3786123369094405?f=rss', '36kr', '2026-04-29', '\n  2026 年 4 月 29&nbsp;日，上海讯 ——AI 原生增长 Agent LeapMind Growth&nbsp;今日宣布完成天使 + 轮融资，由 CMC 资本领投。本轮融资将主要用于核心产品 GrowthGPT 的研发迭代、产研团队扩充及早期市场拓展。\n  LeapMind Growth 成立于 2025 年 4 月，由前米哈游全球用户增长负责人、前快手增长策略中心负责人马如平（', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_2001590496812983711', '机器人', '国家医保局：1到3月职工医保个人账户共济1.15亿人次', 'https://36kr.com/newsflashes/3789098027293699?f=rss', '36Kr', '2026-04-30', '国家医保局消息，今年1到3月职工医保个人账户共济1.15亿人次，金额153.24亿元。职工医保个人账户资金可用于被共济的近亲属在定点医药机构发生的由个人负担的医药费用，以及参加居民基本医保、长期护理保险的个人缴费。目前，职工医保个人账户共济可以通过即时调用被绑定人个人账户、医保钱包等方式实现。（央视新闻）', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 17:17:46', '2026-04-30 17:17:46', '2026-04-30 17:17:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_2040460200001672487', '人工智能', '用AI做IP，文娱科技公司星迹互动完成数千万元天使轮融资｜36氪融资首发', 'https://36kr.com/p/3784697499786503?f=rss', '36kr', '2026-04-28', '近期，数字科技文娱公司星迹互动完成了数千万元的天使轮融资。本轮投资方包括正大集团、北京大融文化传媒、禹牧智能以及麦迈科技等。36氪获悉，此次融资将主要用于公司人员规模的扩张、产能拉升以及平台建设。\n  星迹互动于2025年成立，以AI为核心驱动力，专注于精品IP的开发与运营。具体来讲，公司的业务包括新老IP的开发与运营、漫剧的承制与出海、儿童原创动画孵化，以及数字人IP与虚拟偶像的打造。\n  公司', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:45:57', 0.5);
