INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_2085135752939193203', '人工智能', '「微滔生物」A轮次融资超5000万美元，LNP路线体内CAR-T已发表初步人体数据', 'https://36kr.com/p/3787339522432256?f=rss', '36Kr', '2026-04-30', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，微滔生物近日接连完成A轮及A+轮融资，累计募资金额超5000万美元。两轮融资分别由正心谷资本和德诚资本领投，OrbiMed（奥博资本）、汉康资本、卫材创新风投基金（Eisai Innovation Inc.）、建发新兴投资，以及老股东启明创投、顺禧基金、杏泽资本等跟投。\n  据了解，微滔生物的A轮次募集资金将主要用于推进核心药物管线GT801的临床进程', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:01:51', '2026-04-30 18:01:50', '2026-04-30 18:02:39', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_2112811820007312800', '半导体', 'A股三大指数收盘涨跌不一，寒武纪涨停', 'https://36kr.com/newsflashes/3788971444804615?f=rss', '36Kr', '2026-04-30', '36氪获悉，A股三大指数收盘涨跌不一，沪指涨0.11%，深成指跌0.09%，创业板指跌0.27%；半导体、地产、能源板块领涨，寒武纪、万通发展涨停，杰瑞股份涨超7%，沐曦股份涨超6%；贵金属、汽车、白酒板块走弱，山金国际跌超4%，比亚迪跌超2%，古井贡酒跌超1%。', '该事件值得关注。', 'other', 0.5, '2026-04-30 16:47:20', '2026-04-30 16:47:20', '2026-04-30 16:47:35', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_2114247301688133664', '人工智能', '8点1氪丨百度废除字母职级标签；Meta被曝准备撤销对Manus收购；张雪称曾拒绝了半个亿的商务合作', 'https://36kr.com/p/3787150633065728?f=rss', '36kr', '2026-04-29', '今日热点导览\n  阿联酋宣布将退出欧佩克及“欧佩克+”\n  比亚迪宣布5月1日起涨价\n  五粮液：延期披露年报、一季报\n  普通本科高校上新38种专业\n  全马“破2”跑鞋被炒至近2万元\n  韩股市值超越英国，成为全球第八大股市\n  TOP3大新闻\n  百度职级体系大调整：字母标签改为5级至12级数字职级体系\n  4月28日，据《科创板日报》，百度发布全员信，通知职级体系大调整，其将中管层以下的专', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:23:50', '2026-04-29 10:23:50', '2026-04-29 10:24:11', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_2173827829867605252', '人工智能', '36氪首发 | 韩国现代、微光创投押注焊接机器人，营收预计破数亿，拿下船厂数千万订单', 'https://36kr.com/p/3785955616152839?f=rss', '36kr', '2026-04-28', '作者丨欧雪\n  编辑丨袁斯来\n  硬氪获悉，专注于焊接垂直场景的具身智能机器人公司——昇视唯盛已完成数千万元A+轮融资。本轮融资由韩国现代、微光创投联合投资，资金将主要用于“具身大脑”的研发、软硬件产品的迭代以及市场推广。\n  昇视唯盛成立于2020年，核心团队由来自哈尔滨工业大学、上海交通大学等高校的机器人领域专家，以及拥有多年工业自动化从业经验的资深人员组成。创始人王德钊及核心团队在机器人及自', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
