INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_259091758042882291', '人工智能', 'Bug频出，官方致歉：《异环》能跳出《幻塔》的剧本吗？', 'https://36kr.com/p/3787956437179395?f=rss', '36Kr', '2026-04-30', '文丨贝果树\n  编辑丨果脯、刘士武\n  4月28日，距离游戏公测仅过5天，《异环》官方就不得不发布一篇正式的道歉信，以回应游戏在玩家群体间面临的诸多质疑与争议。\n  信中，官方公布了后续针对叙事、玩法、游戏Bug等功能的后续优化计划，并向全体玩家发放自选S级常驻角色作为补偿。\n  \n  《异环》官方发布道歉信\n  没办法，尽管现如今大家都说“开服没有争议的二游不是好二游”，但公测后的《异环》，暴露', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 17:17:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_2650682933773287286', '人工智能', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_2651244853682426271', '新能源汽车', '恒指开盘涨0.63%，恒生科技指数涨1.07%', 'https://36kr.com/newsflashes/3787224093023490?f=rss', '36kr', '2026-04-29', '36氪获悉，恒指开盘涨0.63%，恒生科技指数涨1.07%；科技、汽车股走强，蔚来、京东健康涨超4%，理想汽车涨超3%，小鹏集团、哔哩哔哩涨超2%；有色金属、煤炭板块调整，五矿资源、中煤能源跌超1%；新股商米科技高开292.20%。', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:16:54', '2026-04-29 10:16:53', '2026-04-29 10:16:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_2712501194650801744', '人工智能', '氪星晚报｜澳门一季度GDP按年实质增长7.1%；小红书发内部信：加大AI投入，柯南出任总裁', 'https://36kr.com/p/3789059666173189?f=rss', '36Kr', '2026-04-30', '大公司：\n  联发科一季度毛利率为46.3%，同比下滑1.8个百分点\n  4月30日，联发科举行法说会并公布2026年第一季度财报，单季每股盈余（EPS）为新台币15.17元，环比增加5.6%、同比减少17.4%；合并营收为新台币1491.51亿元，环比减少0.7%、同比减少2.7%；毛利率为46.3%，环比增加0.2个百分点，同比下滑1.8个百分点。公司表示，毛利率季增主要受惠产品组合优化，年减', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:20', '2026-04-30 18:00:20', '2026-04-30 18:01:07', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_3003240500371517316', '人工智能', '比博斯特完成超10亿元B轮融资，智能底盘三轴产品全覆盖｜36氪独家', 'https://36kr.com/p/3740907027054600?f=rss', '36kr', '2026-04-29', '36氪独家获悉，智能底盘企业比博斯特近日完成B+轮融资，由浙江省新能源汽车产业基金领投，顺创产投、杭资直投基金等联合投资。企业B+轮融资超7亿元，B轮系列融资总额已超10亿元。本轮融资将用于已有产品的规模化增长及前沿产品的开发。\n  比博斯特成立于2021年，其股东不仅包括主机厂蔚来，还涵盖恒隆、保隆等汽车底盘供应链头部企业。2025年，曾在底盘巨头采埃孚担任高管的巫子平、郁炜陆续加入比博斯特，出', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:16:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_3156529655430976947', '人工智能', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_3161139906998818501', '人工智能', '别急着All-in DeepSeek V4，先看看这10位从业者的真心话', 'https://36kr.com/p/3788151000751364?f=rss', '36Kr', '2026-04-29', '文｜周鑫雨 王毓婵\n  编辑｜杨轩\n  解读DeepSeek V4的技术报告，是这几天AI行业最狂热的集体活动。\n  V4很强吗？在工程优化的维度中，答案是毋庸置疑的。过去，大家信奉“Scaling Law的暴力美学”——也就是靠堆更多优质算力、更大参数规模来提升模型性能。而V4走的是一条完全不同的路，它定义了一种“模型训练的克制美学”：\n  它不靠疯狂堆算力和参数，而是通过一系列组合优化和重构：', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:49', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_331564305361148110', '人工智能', '8点1氪丨百度废除字母职级标签；Meta被曝准备撤销对Manus收购；张雪称曾拒绝了半个亿的商务合作', 'https://36kr.com/p/3787150633065728?f=rss', '36kr', '2026-04-29', '今日热点导览\n  阿联酋宣布将退出欧佩克及“欧佩克+”\n  比亚迪宣布5月1日起涨价\n  五粮液：延期披露年报、一季报\n  普通本科高校上新38种专业\n  全马“破2”跑鞋被炒至近2万元\n  韩股市值超越英国，成为全球第八大股市\n  TOP3大新闻\n  百度职级体系大调整：字母标签改为5级至12级数字职级体系\n  4月28日，据《科创板日报》，百度发布全员信，通知职级体系大调整，其将中管层以下的专', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:16:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_3394230057939475121', '人工智能', '用AI做IP，文娱科技公司星迹互动完成数千万元天使轮融资｜36氪融资首发', 'https://36kr.com/p/3784697499786503?f=rss', '36kr', '2026-04-28', '近期，数字科技文娱公司星迹互动完成了数千万元的天使轮融资。本轮投资方包括正大集团、北京大融文化传媒、禹牧智能以及麦迈科技等。36氪获悉，此次融资将主要用于公司人员规模的扩张、产能拉升以及平台建设。\n  星迹互动于2025年成立，以AI为核心驱动力，专注于精品IP的开发与运营。具体来讲，公司的业务包括新老IP的开发与运营、漫剧的承制与出海、儿童原创动画孵化，以及数字人IP与虚拟偶像的打造。\n  公司', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:14', '2026-04-29 09:33:14', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_3404164939956573509', '半导体', '石英股份：光纤业务目前产能利用率较高，订单情况良好', 'https://36kr.com/newsflashes/3789103950765313?f=rss', '36Kr', '2026-04-30', '36氪获悉，石英股份公告，2026年一季度公司实现营收2.56亿元，同比小幅增长，其中光伏业务阶段性承压，光纤半导体业务收入占比延续增长态势。光纤业务按市场订单动态排产，目前产能利用率较高、订单情况良好。公司已形成年产10万吨高纯石英砂整体产能，半导体石英材料三期项目中年产6万吨高纯石英砂生产线已建成投产。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:02:17', '2026-04-30 18:02:16', '2026-04-30 18:02:23', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_3448294106752208151', '人工智能', '欧盟《数字市场法》监管范围拟扩大至云服务与AI领域', 'https://36kr.com/newsflashes/3787149562682627?f=rss', '36kr', '2026-04-29', '欧盟监管机构周二表示，计划将其旨在遏制大型科技公司权力的里程碑式法规《数字市场法》的监管重点转向云服务和人工智能领域。此举旨在促进公平竞争，此前该法已在其他数字领域取得了积极成效。（新浪财经）', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_3850252331154145724', '新能源汽车', '欧莱雅一季度增长6.7%，中国区再现重大人事变动｜独家', 'https://36kr.com/p/3786192457063685?f=rss', '36Kr', '2026-04-30', '文｜贺哲馨\n  编辑｜乔芊\n  刚刚过去的一周，欧莱雅交出了一份超出市场预期的成绩单。\n  公司在2026年一季度实现销售额约121.5亿欧元，同比增长3.6%；在可比口径下（like-for-like），销售增长达到7.6%，经调整后为6.7%。 这一增速不仅高于此前市场普遍预期，财报发布次日，欧莱雅股价大涨9%，创下自2008年11月以来最大单日涨幅。\n  分品类看，四大事业部全部实现了增长，', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:59', '2026-04-30 18:00:58', '2026-04-30 18:00:58', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_4313102002916739880', '半导体', 'A股三大指数收盘涨跌不一，寒武纪涨停', 'https://36kr.com/newsflashes/3788971444804615?f=rss', '36Kr', '2026-04-30', '36氪获悉，A股三大指数收盘涨跌不一，沪指涨0.11%，深成指跌0.09%，创业板指跌0.27%；半导体、地产、能源板块领涨，寒武纪、万通发展涨停，杰瑞股份涨超7%，沐曦股份涨超6%；贵金属、汽车、白酒板块走弱，山金国际跌超4%，比亚迪跌超2%，古井贡酒跌超1%。', '该事件值得关注。', 'other', 0.5, '2026-04-30 16:46:22', '2026-04-30 16:46:21', '2026-04-30 16:46:35', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4439988176781229808', '人工智能', '“擎天租”完成数亿元Pre-A轮融资', 'https://36kr.com/newsflashes/3787289802939395?f=rss', '36kr', '2026-04-29', '4月29日，“擎天租”宣布完成数亿元Pre-A轮融资。本轮投资方包括正大集团旗下正大机器人、长信股份等产业方，美格智能、蓝思科技等多家上市公司参与，老股东明嘉资本、知行投资和睿资创投超额认购。融资资金将主要用于全国履约服务网络建设、机器人资产与调度系统升级、物流保险体系完善、标准化场景产品打磨及全球化服务网络拓展。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:55:06', '2026-04-29 10:55:05', '2026-04-29 10:55:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_448930946819389004', '人工智能', '「微滔生物」A轮次融资超5000万美元，LNP路线体内CAR-T已发表初步人体数据', 'https://36kr.com/p/3787339522432256?f=rss', '36Kr', '2026-04-30', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，微滔生物近日接连完成A轮及A+轮融资，累计募资金额超5000万美元。两轮融资分别由正心谷资本和德诚资本领投，OrbiMed（奥博资本）、汉康资本、卫材创新风投基金（Eisai Innovation Inc.）、建发新兴投资，以及老股东启明创投、顺禧基金、杏泽资本等跟投。\n  据了解，微滔生物的A轮次募集资金将主要用于推进核心药物管线GT801的临床进程', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:00:20', '2026-04-30 18:00:20', '2026-04-30 18:01:16', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4492122964539566238', '人工智能', '成大生物在上海成立医药科技新公司', 'https://36kr.com/newsflashes/3787272147016969?f=rss', '36kr', '2026-04-29', '36氪获悉，爱企查App显示，近日，上海成大致远医药科技有限公司成立，法定代表人为李业基，注册资本10亿元人民币，经营范围包括人工智能理论与算法软件开发、人工智能基础软件开发、人工智能应用软件开发、人工智能双创服务平台等。股东信息显示，该公司由辽宁成大生物股份有限公司全资持股。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:55:06', '2026-04-29 10:55:05', '2026-04-29 10:55:05', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4556956383352550099', '新能源汽车', '恒指开盘涨0.63%，恒生科技指数涨1.07%', 'https://36kr.com/newsflashes/3787224093023490?f=rss', '36kr', '2026-04-29', '36氪获悉，恒指开盘涨0.63%，恒生科技指数涨1.07%；科技、汽车股走强，蔚来、京东健康涨超4%，理想汽车涨超3%，小鹏集团、哔哩哔哩涨超2%；有色金属、煤炭板块调整，五矿资源、中煤能源跌超1%；新股商米科技高开292.20%。', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:24:23', '2026-04-29 09:24:22', '2026-04-29 09:24:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4643805612850612136', '半导体', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:16:48', '2026-04-29 10:16:47', '2026-04-29 10:16:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4767327415361838758', '人工智能', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_482443192283000807', '机器人', '风电产业链业绩分化，“两海”市场成胜负手', 'https://36kr.com/newsflashes/3787147629239555?f=rss', '36kr', '2026-04-29', '近日，风电产业链厂商2025年度业绩陆续出炉。过去一年，风电整机厂商营收普遍水涨船高，但利润分化明显。相比之下，齿轮箱、风电主轴、风电基础装备等上下游核心部件供应商业绩普遍高增长。总的来看，海外及海上“两海”业务占比高的厂商业绩要好于业务结构单一的厂商。因此，布局“两海”业务成为风电厂商共识。业内人士判断，海外和海上是中国风电产业发展的两个关键增量市场，其中，中国的海上风电已进入规模化开发阶段。（', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:30', '2026-04-29 08:43:29', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_4896345683683068763', '人工智能', '白宫据悉正在研讨恢复与Anthropic合作', 'https://36kr.com/newsflashes/3787275928411395?f=rss', '36kr', '2026-04-29', '据知情人士透露，白宫正在制定指导方针，允许各机构绕过对Anthropic的供应链风险的认定，并引入包括其迄今为止最强大的Mythos在内的新模型。两位消息人士称，目前正在起草的一项行政命令草案，除其他与政府使用人工智能相关的措施外，可能还会为政府提供一种缓和与Anthropic公司对抗的途径。（新浪财经）', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:23:50', '2026-04-29 10:23:50', '2026-04-29 10:24:11', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_5140769101732492135', '半导体', '石英股份：光纤业务目前产能利用率较高，订单情况良好', 'https://36kr.com/newsflashes/3789103950765313?f=rss', '36Kr', '2026-04-30', '36氪获悉，石英股份公告，2026年一季度公司实现营收2.56亿元，同比小幅增长，其中光伏业务阶段性承压，光纤半导体业务收入占比延续增长态势。光纤业务按市场订单动态排产，目前产能利用率较高、订单情况良好。公司已形成年产10万吨高纯石英砂整体产能，半导体石英材料三期项目中年产6万吨高纯石���砂生产线已建成投产。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:00:44', '2026-04-30 18:00:43', '2026-04-30 18:00:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5210358311442655731', '人工智能', '36氪首发 | 韩国现代、微光创投押注焊接机器人，营收预计破数亿，拿下船厂数千万订单', 'https://36kr.com/p/3785955616152839?f=rss', '36kr', '2026-04-28', '作者丨欧雪\n  编辑丨袁斯来\n  硬氪获悉，专注于焊接垂直场景的具身智能机器人公司——昇视唯盛已完成数千万元A+轮融资。本轮融资由韩国现代、微光创投联合投资，资金将主要用于“具身大脑”的研发、软硬件产品的迭代以及市场推广。\n  昇视唯盛成立于2020年，核心团队由来自哈尔滨工业大学、上海交通大学等高校的机器人领域专家，以及拥有多年工业自动化从业经验的资深人员组成。创始人王德钊及核心团队在机器人及自', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:14', '2026-04-29 09:33:14', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_5325448889682329656', '人工智能', '“36氪企业全情报”官方股票舆情交流社群，正式开放招募！', 'https://36kr.com/p/3787661080714497?f=rss', '36Kr', '2026-04-29', '36氪企业全情报官方专属社群现已正式对外开放，正式打造唯一官方股票舆情情报社群，面向所有股民、理财爱好者、个股深度研究者，适配不同投资风格与交易节奏，帮你高效拿捏舆情风向、把握行情先机。\n  从股市舆情解读、个股情报拆解，到行情逻辑分析、投资干货交流，一站式帮投资者告别信息滞后、看懂涨跌本质。\n  \n  扫码进入：“36氪企业全情报”官方股票舆情交流社群\n  为什么要做专属股票舆', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 16:46:58', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5327531793169526286', '人工智能', '8点1氪丨百度废除字母职级标签；Meta被曝准备撤销对Manus收购；张雪称曾拒绝了半个亿的商务合作', 'https://36kr.com/p/3787150633065728?f=rss', '36kr', '2026-04-29', '今日热点导览\n  阿联酋宣布将退出欧佩克及“欧佩克+”\n  比亚迪宣布5月1日起涨价\n  五粮液：延期披露年报、一季报\n  普通本科高校上新38种专业\n  全马“破2”跑鞋被炒至近2万元\n  韩股市值超越英国，成为全球第八大股市\n  TOP3大新闻\n  百度职级体系大调整：字母标签改为5级至12级数字职级体系\n  4月28日，据《科创板日报》，百度发布全员信，通知职级体系大调整，其将中管层以下的专', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 09:45:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_5337570414003332808', '人工智能', '「优时科技」完成数亿元B2轮融资，从L4视觉自动驾驶延展至人形机器人，打造数据飞轮｜36氪首发', 'https://36kr.com/p/3788687934249989?f=rss', '36Kr', '2026-04-30', '一季度过去，具身智能行业的融资热潮还在继续。\n  36氪获悉，专注于L4低速自动驾驶的公司「优时科技」宣布完成数亿元人民币B2轮融资。本轮融资由前海方舟领投，前海母基金旗下多支基金参与，联同鲲翎资本、厚天资本等8家投资机构共同完成。\n  在此之前，「优时科技」已完成了6轮融资：\n  ·2018年6月，拿到&nbsp;PNP&nbsp;中国领投、北京汇丰投融、北京金种子和上海平阳复辉跟投的数百万人民', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 17:17:46', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_5622173180531812750', '机器人', '香港金管局：3月份港元货币供应量M2及M3同比均上升1.2%', 'https://36kr.com/newsflashes/3789083440061446?f=rss', '36Kr', '2026-04-30', '4月30日，香港金融管理局发表的统计数字显示，认可机构的存款总额在2026年3月份上升0.1%，其中港元存款上升0.7%，外币存款则下跌0.3%。2026年第1季，存款总额及港元存款分别上升1.0%及1.9%。香港人民币存款在3月份上升0.6%，于3月底为10,352亿元人民币。跨境贸易结算的人民币汇款总额于3月份为12,900亿元人民币，而2月份为8,665亿元人民币。存款变动受多项因素影响，包', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:02:39', '2026-04-30 18:02:39', '2026-04-30 18:02:39', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_5700194262896396536', '人工智能', '亚马逊云科技推出桌面AI助手Amazon Quick', 'https://36kr.com/newsflashes/3789015541439491?f=rss', '36Kr', '2026-04-30', '4月30日，亚马逊云科技宣布推出桌面AI助手Amazon Quick，将个人AI助手引入桌面。据介绍，用户能够直接在Amazon Quick中创建实时仪表板、智能应用、演��文稿和图片。Amazon Quick通过集成Google Workspace、Zoom、Microsoft 365以及Salesforce等，将应用、工具和数据汇聚一处，实现日常应用的一站式操作。（界面）', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:01', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5722095064365490496', '人工智能', '最前线｜爱芯元智仇肖莘：大算力芯片将成为企业明年的主要增长引擎', 'https://36kr.com/p/3784806758243587?f=rss', '36kr', '2026-04-27', '在汽车行业越来越强调降本的今天，车企心中的天平逐渐偏向了更具性价比的国产芯片。爱芯元智看到了这一发展机遇，北京车展前期，爱芯元智与千里科技、阶跃星辰等企业成立“千里联盟”，同时企业将于今年三季度发布M97这颗大算力辅助驾驶芯片。\n  爱芯元智创始人仇肖莘在北京车展上公开表示，“大算力产品已成功流片，正进入正常的开发周期”，2026年将逐步导入多款车型，成为业绩增长的重要引擎。目前，传统终端计算产品', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5732641017056066091', '人工智能', '前米哈游高管创业，AI 原生增长 Agent LeapMind Growth 获 CMC 资本领投', 'https://36kr.com/p/3786123369094405?f=rss', '36kr', '2026-04-29', '\n  2026 年 4 月 29&nbsp;日，上海讯 ——AI 原生增长 Agent LeapMind Growth&nbsp;今日宣布完成天使 + 轮融资，由 CMC 资本领投。本轮融资将主要用于核心产品 GrowthGPT 的研发迭代、产研团队扩充及早期市场拓展。\n  LeapMind Growth 成立于 2025 年 4 月，由前米哈游全球用户增长负责人、前快手增长策略中心负责人马如平（', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:54:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5772861886247985959', '新材料', '新政后首单“H转深A”诞生，越疆科技创业板IPO获受理', 'https://36kr.com/newsflashes/3787137966382341?f=rss', '36kr', '2026-04-29', '4月27日，深交所官网显示，深圳市越疆科技股份有限公司（简称“越疆科技”）的创业板IPO申请已获受理。资料显示，越疆科技已于2024年12月在港交所上市。2025年6月10日印发的《中共中央办公厅 国务院办公厅关于深入推进深圳综合改革试点深化改革创新扩大开放的意见》提到，允许在香港联合交易所上市的粤港澳大湾区企业，按照政策规定在深圳证券交易所上市。市场分析指出，伴随着越疆“回A”的推进，“H转深A', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:27', '2026-04-29 08:43:27', '2026-04-29 08:43:27', 0.5);
