INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5920126883688311808', '半导体', '多地银行加速旗下村镇银行整合重组', 'https://36kr.com/newsflashes/3787165643070723?f=rss', '36kr', '2026-04-29', '今年以来，多家银行加速旗下村镇银行减量提质改革，“村并村”“村改支”等整合重组案例密集落地，行业改革持续提速。苏商银行特约研究员高政扬对记者表示，当前中小金融机构改革有序推进。针对部分中小银行治理不完善、风控能力薄弱、抗风险水平不足等痛点，监管部门持续压实各方主体责任，引导行业通过兼并重组优化组织架构，稳妥化解存量风险。本轮整合重组改革，有助于筑牢区域金融安全防线，优化县域金融服务布局，持续增强金', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 09:24:17', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_5993672276794454415', '人工智能', '前米哈游高管创业，AI 原生增长 Agent LeapMind Growth 获 CMC 资本领投', 'https://36kr.com/p/3786123369094405?f=rss', '36kr', '2026-04-29', '\n  2026 年 4 月 29&nbsp;日，上海讯 ——AI 原生增长 Agent LeapMind Growth&nbsp;今日宣布完成天使 + 轮融资，由 CMC 资本领投。本轮融资将主要用于核心产品 GrowthGPT 的研发迭代、产研团队扩充及早期市场拓展。\n  LeapMind Growth 成立于 2025 年 4 月，由前米哈游全球用户增长负责人、前快手增长策略中心负责人马如平（', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:13', '2026-04-29 09:33:13', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_6003769564033323630', '人工智能', '不谈空话，谈合作丨这场AI+产业对接会只聊落地', 'https://36kr.com/p/3788996733803782?f=rss', '36Kr', '2026-04-30', '\n  \n  “世界咖啡”[AI+]产业对接会正式定档北京亦庄。\n  <img src=\"https://', '该事件值得关注。', 'other', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:41', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_6012846993488538356', '人工智能', '期货市场交投活跃，上市期货公司首季盈利集体倍增', 'https://36kr.com/newsflashes/3787146901429504?f=rss', '36kr', '2026-04-29', '截至4月28日晚，4家A股主板上市期货公司悉数披露2025年年报与2026年一季报。从财务数据看，期货行业去年以来的盈利改善趋势较为明显，尤其是今年一季度呈现业绩爆发式增长，4家公司一季度归母净利润均倍增，同比增幅在138%至939%不等。 业内人士表示，一季度地缘政治风险持续发酵，带动能源化工、有色金属等大宗商品价格剧烈波动，期货市场成交规模同步增长，是推动期货行业盈利向好的主要原因。从行业角度', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_6087904520181678205', '人工智能', '白宫据悉正在研讨恢复与Anthropic合作', 'https://36kr.com/newsflashes/3787275928411395?f=rss', '36kr', '2026-04-29', '据知情人士透露，白宫正在制定指导方针，允许各机构绕过对Anthropic的供应链风险的认定，并引入包括其迄今为止最强大的Mythos在内的新模型。两位消息人士称，目前正在起草的一项行政命令草案，除其他与政府使用人工智能相关的措施外，可能还会为政府提供一种缓和与Anthropic公司对抗的途径。（新浪财经）', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:55:06', '2026-04-29 10:55:05', '2026-04-29 10:55:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_6195086269098615829', '人工智能', '白宫据悉正在研讨恢复与Anthropic合作', 'https://36kr.com/newsflashes/3787275928411395?f=rss', '36kr', '2026-04-29', '据知情人士透露，白宫正在制定指导方针，允许各机构绕过对Anthropic的供应链风险的认定，并引入包括其迄今为止最强大的Mythos在内的新模型。两位消息人士称，目前正在起草的一项行政命令草案，除其他与政府使用人工智能相关的措施外，可能还会为政府提供一种缓和与Anthropic公司对抗的途径。（新浪财经）', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:16:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_6198234334130105838', '机器人', '阿里云等在广东横琴成立数梦时空智联科技公司', 'https://36kr.com/newsflashes/3788955450400001?f=rss', '36Kr', '2026-04-30', '36氪获悉，爱企查App显示，近日，数梦时空智联（广东横琴）科技有限公司成立，法定代表人为李国伟，注册资本500万元人民币，经营范围包括数据处理服务、信息技术咨询服务、计算机软硬件及辅助设备批发、软件开发、云计算装备技术服务、大数据服务、信息系统集成服务等。股东信息显示，该公司由珠海数创智联壹号信息科技中心（有限合伙）、浙江阿里巴巴云计算有限公司、杭州银杏数股权投资合伙企业（有限合伙）等共同持股。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:42', '2026-04-30 16:46:41', '2026-04-30 16:46:41', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_6397368609152023375', '半导体', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:55:17', '2026-04-29 10:55:17', '2026-04-29 10:55:17', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_6459529930302913830', '人工智能', '氪星晚报 ｜腾讯ima推出全新知识Agent——copilot；魔法原子：目标到2036年营收达140亿美元', 'https://36kr.com/p/3787748082293766?f=rss', '36Kr', '2026-04-29', '大公司：\n  魔法原子：目标到2036年营收达140亿美元\n  36氪获悉，美西时间4月28日，魔法原子在硅谷举办全球具身智能创新大会（GEIS）落幕。会上发布自研世界模型Magic-Mix、灵巧手MagicHand H01及旗舰人形机器人MagicBot X1。大会上，公司首次对外披露魔法原子的长期营收目标：到2036年，公司将向140亿美元营收规模迈进，并宣布未来五年将持续投入10亿美元，打造', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 16:47:35', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_6548585657632828410', '新材料', '2连板金瑞矿业：主要原材料天青石若延续涨价趋势，将对公司经营业绩产生不利影响', 'https://36kr.com/newsflashes/3789143113063425?f=rss', '36Kr', '2026-04-30', '36氪获悉，金瑞矿业公告。公司主营业务未发生重大变化，生产经营情况正常。2026年第一季度，公司实现归属于上市公司股东的净利润为-108万元，较上年同期大幅下降。主要原因系一季度开展年度例行停产检修近两个多月，致使营业收入大幅减少，利润总额随之减少，造成亏损。受地缘局势等因素影响，公司主要原材料天青石采购价格同比上涨15.78%，环比上涨34.32%。若后续延续涨价趋势，将对公司经营业绩产生不利影', '财报数据反映公司经营状况。', 'report', 0.5, '2026-04-30 18:02:23', '2026-04-30 18:02:23', '2026-04-30 18:02:23', 0.5);
