INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_6681218031527781626', '人工智能', '独家对谈｜兴辉时代创始人高兴辉，90后小镇女孩离开教培大厂，三年创造2亿GMV的倔强人生', 'https://36kr.com/p/3786265971334150?f=rss', '36kr', '2026-04-29', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  兴辉，山西人，三次面试新东方才被录用。\n  转战高途教育后，她与另外三名男同事一同被封为公司的“三王一后”。\n  如今她已自己创业近三年。带着对教培行业发展水温的好奇，我们拜访了兴辉的公司。\n  一进门，同事们喊她“辉哥”——这与她外表精瘦，笑起来有虎牙的形象相比，实在让人难以关联。\n  但当我们听到在整个教培行业最为', '人事变动可能影响公司战略方向。', 'person', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:13', '2026-04-29 09:33:13', 0.5);
