INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_6860680570346615974', '人工智能', '36氪首发 | 韩国现代、微光创投押注焊接机器人，营收预计破数亿，拿下船厂数千万订单', 'https://36kr.com/p/3785955616152839?f=rss', '36kr', '2026-04-28', '作者丨欧雪\n  编辑丨袁斯来\n  硬氪获悉，专注于焊接垂直场景的具身智能机器人公司——昇视唯盛已完成数千万元A+轮融资。本轮融资由韩国现代、微光创投联合投资，资金将主要用于“具身大脑”的研发、软硬件产品的迭代以及市场推广。\n  昇视唯盛成立于2020年，核心团队由来自哈尔滨工业大学、上海交通大学等高校的机器人领域专家，以及拥有多年工业自动化从业经验的资深人员组成。创始人王德钊及核心团队在机器人及自', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_6945611709324482715', '人工智能', '不谈空话，谈合作丨这场AI+产业对接会只聊落地', 'https://36kr.com/p/3788996733803782?f=rss', '36Kr', '2026-04-30', '\n  \n  “世界咖啡”[AI+]产业对接会正式定档北京亦庄。\n  <img src=\"https://', '该事件值得关注。', 'other', 0.5, '2026-04-30 16:46:58', '2026-04-30 16:46:58', '2026-04-30 17:17:46', 0.5);
