INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_7197624387919951613', '人工智能', '期货市场交投活跃，上市期货公司首季盈利集体倍增', 'https://36kr.com/newsflashes/3787146901429504?f=rss', '36kr', '2026-04-29', '截至4月28日晚，4家A股主板上市期货公司悉数披露2025年年报与2026年一季报。从财务数据看，期货行业去年以来的盈利改善趋势较为明显，尤其是今年一季度呈现业绩爆发式增长，4家公司一季度归母净利润均倍增，同比增幅在138%至939%不等。 业内人士表示，一季度地缘政治风险持续发酵，带动能源化工、有色金属等大宗商品价格剧烈波动，期货市场成交规模同步增长，是推动期货行业盈利向好的主要原因。从行业角度', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_7287070534250269969', '人工智能', '8点1氪：中方禁止外资收购Manus；上海迪士尼回应游客吸烟冲突事件；泡泡玛特LABUBU 冰箱未发售已溢价3000元', 'https://36kr.com/p/3785730095127817?f=rss', '36kr', '2026-04-28', 'TOP3大新闻\n  DeepSeek 输入缓存降价\n  多家美国廉价航空公司寻求政府资金纾困\n  东方甄选回应大量用户申请退会员\n  穿西装开空调太费电，日本东京鼓励公务员穿短裤\n  印度移动支付平台MobiKwik获央行批准\n  TOP3大事件\n  国家发展改革委：依法依规对外资收购Manus项目作出禁止投资决定\n  据国家发展改革委网站4月27日消息，外商投资安全审查工作机制办公室（国家发展改', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_7294923136091139873', '人工智能', '“小长假”前一天北京拍地91.597亿，最贵楼面价超6万', 'https://36kr.com/p/3789084813548803?f=rss', '36Kr', '2026-04-30', '4月最后一天，北京楼市迎来一次春季土拍盛宴，分别位于朝阳东坝、丰台万泉寺、昌平北七家的三宗宅地成交，总价合计91.597亿元。\n  2026年1-4月，北京合计出让住宅用地13宗（2025年同期成交7宗），总成交价为217.577亿元（2025年同期成交约334.9亿元），相比去年同期有约35%的金额降幅。\n  但今年1-4月成交宅地规划总建面约83.7万㎡，与去年同期成交总建面82.2万㎡的总量', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:20', '2026-04-30 18:00:20', '2026-04-30 18:00:43', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_7396508535352520187', '人工智能', 'HappyHorse没有惊喜', 'https://36kr.com/p/3789098887077123?f=rss', '36Kr', '2026-04-30', '作者&nbsp;|&nbsp;兰杰\n  编辑&nbsp;|&nbsp;乔芊\n  4月27日，预热已久的HappyHorse终于开启测试，颇为遗憾的是，它没能像横空出世的Seedance2.0那样掀起巨浪。没有惊喜，对于HappyHorse来讲是一个颇为中肯的评价。&nbsp;\n  HappyHorse是阿里巴巴ATH事业群旗下创新事业部研发的视频模型，于4月27日开启灰测，并接入千问App。\n  ', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:20', '2026-04-30 18:00:20', '2026-04-30 18:01:07', 0.5);
