INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_7922031647592347965', '人工智能', '8点1氪丨官方通报“霸王茶姬中喝出水银”；马斯克称创办OpenAI只为拯救人类；三星家族财富一年翻倍至3000亿跃居亚洲第三', 'https://36kr.com/p/3788573115735299?f=rss', '36Kr', '2026-04-30', '今日热点导览\n  \n   四大主播集体离职，东方甄选奖励300名员工超4亿元股份，人均超140万元\n   马斯克天价薪酬方案曝光，薪酬目标包括火星殖民以及太空数据中心建设\n   5月1日起北京禁飞禁售无人机，大疆在京门店4月29日将下架相关产品\n   朋友圈改版，腾讯客服表示会持续优化\n   8天预计发送旅客1.58亿人次，铁路 “五一”假期运输今天启动\n  \n  TOP 3大新闻\n  官方通报“', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:51', '2026-04-30 18:01:50', '2026-04-30 18:02:39', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_808601860207127059', '人工智能', '成大生物在上海成立医药科技新公司', 'https://36kr.com/newsflashes/3787272147016969?f=rss', '36kr', '2026-04-29', '36氪获悉，爱企查App显示，近日，上海成大致远医药科技有限公司成立，法定代表人为李业基，注册资本10亿元人民币，经营范围包括人工智能理论与算法软件开发、人工智能基础软件开发、人工智能应用软件开发、人工智能双创服务平台等。股东信息显示，该公司由辽宁成大生物股份有限公司全资持股。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:54:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_8150763493374535569', '人工智能', '「优时科技」完成数亿元B2轮融资，从L4视觉自动驾驶延展至人形机器人，打造数据飞轮｜36氪首发', 'https://36kr.com/p/3788687934249989?f=rss', '36Kr', '2026-04-30', '一季度过去，具身智能行业的融资热潮还在继续。\n  36氪获悉，专注于L4低速自动驾驶的公司「优时科技」宣布完成数亿元人民币B2轮融资。本轮融资由前海方舟领投，前海母基金旗下多支基金参与，联同鲲翎资本、厚天资本等8家投资机构共同完成。\n  在此之前，「优时科技」已完成了6轮融资：\n  ·2018年6月，拿到&nbsp;PNP&nbsp;中国领投、北京汇丰投融、北京金种子和上海平阳复辉跟投的数百万人民', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 16:46:01', '2026-04-30 16:46:01', '2026-04-30 16:46:41', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_8156133813543081515', '新能源汽车', '欧莱雅一季度增长6.7%，中国区再现重大人事变动｜独家', 'https://36kr.com/p/3786192457063685?f=rss', '36Kr', '2026-04-30', '文｜贺哲馨\n  编辑｜乔芊\n  刚刚过去的一周，欧莱雅交出了一份超出市场预期的成绩单。\n  公司在2026年一季度实现销售额约121.5亿欧元，同比增长3.6%；在可比口径下（like-for-like），销售增长达到7.6%，经调整后为6.7%。 这一增速不仅高于此前市场普遍预期，财报发布次日，欧莱雅股价大涨9%，创下自2008年11月以来最大单日涨幅。\n  分品类看，四大事业部全部实现了增长，', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 16:46:36', '2026-04-30 16:46:35', '2026-04-30 16:46:35', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_8291342663587139474', '人工智能', 'Bug频出，官方致歉：《异环》能跳出《幻塔》的剧本吗？', 'https://36kr.com/p/3787956437179395?f=rss', '36Kr', '2026-04-30', '文丨贝果树\n  编辑丨果脯、刘士武\n  4月28日，距离游戏公测仅过5天，《异环》官方就不得不发布一篇正式的道歉信，以回应游戏在玩家群体间面临的诸多质疑与争议。\n  信中，官方公布了后续针对叙事、玩法、游戏Bug等功能的后续优化计划，并向全体玩家发放自选S级常驻角色作为补偿。\n  \n  《异环》官方发布道歉信\n  没办法，尽管现如今大家都说“开服没有争议的二游不是好二游”，但公测后的《异环》，暴露', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:00:20', '2026-04-30 18:00:20', '2026-04-30 18:01:16', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8307510117735866210', '人工智能', '前米哈游高管创业，AI 原生增长 Agent LeapMind Growth 获 CMC 资本领投', 'https://36kr.com/p/3786123369094405?f=rss', '36kr', '2026-04-29', '\n  2026 年 4 月 29&nbsp;日，上海讯 ——AI 原生增长 Agent LeapMind Growth&nbsp;今日宣布完成天使 + 轮融资，由 CMC 资本领投。本轮融资将主要用于核心产品 GrowthGPT 的研发迭代、产研团队扩充及早期市场拓展。\n  LeapMind Growth 成立于 2025 年 4 月，由前米哈游全球用户增长负责人、前快手增长策略中心负责人马如平（', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:16:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8360099428974227423', '半导体', '可回收火箭密集验证窗口开启，商业航天产业链有望迈入规模化量产元年', 'https://36kr.com/newsflashes/3787190594558981?f=rss', '36kr', '2026-04-29', '4月下旬，中国商业航天迎来可回收火箭密集验证窗口。长征十号乙、朱雀三号等多型火箭接连实施回收技术验证，国家《商业航天标准体系（1.0版）》同步落地。在产业政策与核心技术共振之下，A股产业链公司一季报业绩兑现亮眼。Wind数据显示，万得商业航天概念指数近期表现不俗，4月7日以来累计上涨6.51%。分析人士认为，可回收技术的工程化落地将推动发射成本指数级下降，叠加政策标准体系的顶层引导，商业航天正从技', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 09:24:17', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8548538073339306879', '人工智能', 'OpenAI和Anthropic就高阶网络安全AI模型与美国众议院委员会展开会晤', 'https://36kr.com/newsflashes/3787141617490945?f=rss', '36kr', '2026-04-29', 'OpenAI与Anthropic向美国众议院国土安全委员会工作人员，专项汇报了旗下具备网络攻防能力的新一代AI模型，以及该类技术对网络安全产生的各类影响。这是美国立法机构首次就新型AI模型引发的网络威胁，与两大AI巨头开展专项沟通的会议之一，重点涵盖防护薄弱的关键基础设施领域面临的安全风险。委员会一名助理证实，两家企业于上周四，以两场独立非公开机密会议形式，向国会工作人员进行专项简报。（新浪财经）', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8560003801884310590', '人工智能', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8588432127639291600', '人工智能', '「寻明生科」完成3500万美元A+轮融资，首个抗体药物即将进入临床｜36氪首发', 'https://36kr.com/p/3784480103455748?f=rss', '36kr', '2026-04-28', '文｜胡香赟\n  编辑｜海若镜\n  36氪获悉，寻明生科（Aureka Biotechnologies）近期已完成3500万美元A+轮融资。本轮融资由红杉中国领投，经纬创投、博远资本跟投，老股东五源资本、启明创投、纽尔利资本等持续加注。\n  去年底，寻明生科就曾获得一笔数千万美元的A轮融资。截至目前，公司A轮次融资的累计金额已接近1亿美元。\n  寻明生科方面表示，本轮募集资金将用于推动自研创新功能抗', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 08:45:58', '2026-04-29 08:45:57', '2026-04-29 08:46:04', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_8595553382069667613', '人工智能', '从扫地机到火箭车，追觅在硅谷造了一场“瞬息全宇宙”', 'https://36kr.com/p/3789057332043016?f=rss', '36Kr', '2026-04-30', '作者 | 邓咏仪\n  编辑 | 杨轩\n  如果你在4月27日这一周走进美国旧金山艺术宫，也许你会感到惊讶——这不像一个艺术圣地，更像一场包罗万象的博览会。\n  来自50多个国家的媒体、KOL、客户挤在展区里。映入眼帘的产品，小至智能吊坠、吹风机、LED 美容面罩、扫地机，大至洗地机、空调、冰箱、手机，甚至还有一辆“火箭车”的概念超跑。\n  \n  Nebula NEXT 01&nbsp;\n  在舞台', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:01:51', '2026-04-30 18:01:50', '2026-04-30 18:02:39', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8614526666479447877', '医疗健康', '独家对谈｜缘启智慧CEO邓江，一个80后银行码农出身的AI医疗创业者', 'https://36kr.com/p/3786252394945795?f=rss', '36kr', '2026-04-28', '\n  图源：公众号「职场Bonus」（ID：ZhiChangHongLi）\n  今年三月，《职场Bonus》报道了前百川智能商业化合伙人邓江加入北电数智</', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:55:14', '2026-04-29 10:55:14', '2026-04-29 10:55:17', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8680397820294906804', '人工智能', '前米哈游高管创业，AI 原生增长 Agent LeapMind Growth 获 CMC 资本领投', 'https://36kr.com/p/3786123369094405?f=rss', '36kr', '2026-04-29', '\n  2026 年 4 月 29&nbsp;日，上海讯 ——AI 原生增长 Agent LeapMind Growth&nbsp;今日宣布完成天使 + 轮融资，由 CMC 资本领投。本轮融资将主要用于核心产品 GrowthGPT 的研发迭代、产研团队扩充及早期市场拓展。\n  LeapMind Growth 成立于 2025 年 4 月，由前米哈游全球用户增长负责人、前快手增长策略中心负责人马如平（', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:55:05', '2026-04-29 10:55:05', '2026-04-29 10:55:25', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36Kr_8732566745723134284', '新能源汽车', '欧莱雅一季度增长6.7%，中国区再现重大人事变动｜独家', 'https://36kr.com/p/3786192457063685?f=rss', '36Kr', '2026-04-30', '文｜贺哲馨\n  编辑｜乔芊\n  刚刚过去的一周，欧莱雅交出了一份超出市场预期的成绩单。\n  公司在2026年一季度实现销售额约121.5亿欧元，同比增长3.6%；在可比口径下（like-for-like），销售增长达到7.6%，经调整后为6.7%。 这一增速不仅高于此前市场普遍预期，财报发布次日，欧莱雅股价大涨9%，创下自2008年11月以来最大单日涨幅。\n  分品类看，四大事业部全部实现了增长，', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 16:47:36', '2026-04-30 16:47:35', '2026-04-30 17:17:37', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_8882531513447156950', '人工智能', 'OpenAI和Anthropic就高阶网络安全AI模型与美国众议院委员会展开会晤', 'https://36kr.com/newsflashes/3787141617490945?f=rss', '36kr', '2026-04-29', 'OpenAI与Anthropic向美国众议院国土安全委员会工作人员，专项汇报了旗下具备网络攻防能力的新一代AI模型，以及该类技术对网络安全产生的各类影响。这是美国立法机构首次就新型AI模型引发的网络威胁，与两大AI巨头开展专项沟通的会议之一，重点涵盖防护薄弱的关键基础设施领域面临的安全风险。委员会一名助理证实，两家企业于上周四，以两场独立非公开机密会议形式，向国会工作人员进行专项简报。（新浪财经）', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-29 09:00:30', '2026-04-29 09:00:30', '2026-04-29 09:00:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_9029037403790069187', '人工智能', '氪星晚报｜我国最大规模AI4S集群接入全国一体化算力网；亚马逊低地轨道卫星计划又一批卫星发射升空；我国首款正向设计自转旋翼机完成首飞', 'https://36kr.com/p/3786324189027332?f=rss', '36kr', '2026-04-28', '大公司：\n  拒买新闻就交税，澳洲拟向科技巨头征约2%营收税\n  澳大利亚政府公布法案草案，拟对Meta、谷歌等科技巨头征收新税，除非这些平台自愿与当地新闻机构签署付费协议，以应对传统媒体在数码平台冲击下面临的生存压力。据报道，根据拟议的新法律安排，这些大型数码平台须就分享本地媒体新闻内容所带来的平台流量，向出版商提供经济补偿。澳洲总理阿尔巴尼斯表明，政府将给予Meta、谷歌等公司机会，与本地新闻', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('36kr_9087450683195329612', '人工智能', '苹果计划在iOS 27中借助AI对照片编辑功能进行全面升级', 'https://36kr.com/newsflashes/3787148066593798?f=rss', '36kr', '2026-04-29', '当地时间4月28日，据报道，苹果公司正计划对iPhone、iPad和Mac的内置照片编辑功能进行重大升级，并深度依托人工智能技术，以此缩小与安卓设备的竞争差距。据知情人士透露，该公司正在为计划于今年秋季发布的iOS 27、iPadOS 27和macOS 27开发一套由Apple Intelligence平台驱动的新工具套件。这些功能将允许用户利用设备端的AI模型对图片进行扩展、增强和重新构图。知情', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 08:43:23', '2026-04-29 08:43:22', '2026-04-29 08:43:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/391.htm', '半导体', '首发换新 2699 → 1648 元：小米 1.5 匹强劲风空调 10 年包修，双排纯铜蒸发器 + 冷凝器', 'https://www.ithome.com/0/944/391.htm', 'IT之家', '2026-04-28', '小米官方今日宣布，米家空调强劲风超 1.5 匹今日开售，新品官方定价 3999 元，首发价 2699 元（小米官网现售 2699 元）。夏天双排纯铜蒸发器 + 冷凝器 + 13cc 大排量压缩机 → 强制冷。冬天纯热泵制热技术 &nbsp;→ 出风不干燥。<img class=\"no-alt-img\" src=\"https://img.ithome.com/newsuploadfiles/2026', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-29 09:24:18', '2026-04-29 09:24:17', '2026-04-29 09:46:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/703.htm', '新材料', '威马汽车 1.275 亿债权 9.35 万元成交，无原始材料、不承诺可收回', 'https://www.ithome.com/0/944/703.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 28 日消息，4 月 28 日 16 时 54 分，据淘宝阿里拍卖平台，威马汽车旗下威马新能源汽车采购（上海）有限公司破产清算后，其账面合计 1.275 亿元的 24 笔对外应收账款债权，最终以 9.35 万元价格成交。根', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:20', '2026-04-29 09:24:20', '2026-04-29 09:24:20', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/704.htm', '机器人', 'ACEMAGIC 阿迈奇推出 F5A 迷你主机：锐龙 AI 9 HX 470 处理器、32GB 内存，支持 OCuLink 外接显卡', 'https://www.ithome.com/0/944/704.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 28 日消息，ACEMAGIC 阿迈奇现已在海外市场推出 F5A 迷你主机，新品配备 AMD 锐龙 AI 9 HX 470 处理器，支持 OCuLink 外接显卡。据介绍，这款迷你主机的处理器采用 12 核心 24 线程设计，包含 4 个 Zen5 核心 +8 个 Zen 5c 核心，最高加速频率可达 5.2 GHz。配备 Radeon 890M 集成显卡，NPU 的 AI 性能', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:33:29', '2026-04-29 09:33:29', '2026-04-29 09:34:32', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/705.htm', '新能源汽车', '苹果 Vision Pro 辅助完成白内障手术，支持 3D 可视化与远程协作', 'https://www.ithome.com/0/944/705.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 28 日消息，苹果 Vision Pro 再度创下医疗应用里程碑，纽约一位眼科医生成为首位借助这款空间计算头显完成白内障手术的外科医师。视光医疗机构 SightMD 的埃里克 · 罗森伯格医生于 2025 年 10 月完成了首例手术。此后，他利用自己为苹果混合现实设备联合开发的手术平台 ScopeXR，又陆续完成了数百例同类手术。ScopeXR 可将 3D 数字化手术显微镜的实时', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:33:26', '2026-04-29 09:33:26', '2026-04-29 09:34:32', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/722.htm', '新能源汽车', '立讯精密 2026 年一季度净利润 36.59 亿元，同比增长 20.24%', 'https://www.ithome.com/0/944/722.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 28 日消息，立讯精密今日发布 2026 年一季度报告：营业总收入：838.88 亿元，同比增长 35.77%归母净利润：36.6 亿元，同比增长 20.24%扣非净利润：27.76 亿元，同比增长 15.22%经营现金流：-70.68 亿元，同比下降 5.63%基本每股收益：0.50 元 / 股，同比增长 19.05%稀释每股收益：0.49 元 / 股，同比增长 16.67%加', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:33:26', '2026-04-29 09:33:26', '2026-04-29 09:46:49', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/723.htm', '半导体', '立讯精密 2026 年净利润 78.40 亿元 ~81.06 亿元，同比预增 18%~22%', 'https://www.ithome.com/0/944/723.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 28 日消息，立讯精密今日发布 2026 年业绩预告报告：归母净利润：784024.10 万元 ~810601.19 万元，同比预增 18.00%~22.00%扣非净利润：625670.32 万元 ~672247.41 万元，同比预增 11.74%~20.06%基本每股收益：1.07 元 / 股 ~1.11 元 / 股', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:18', '2026-04-29 09:24:17', '2026-04-29 09:46:44', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/728.htm', '新能源汽车', '加速你的创意落地：Claude AI 接入 Adobe、Blender 等创意软件生态', 'https://www.ithome.com/0/944/728.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，Anthropic 今天（4 月 29 日）宣布升级 Claude，面向创意人士新增多款专属连接器（connectors），全面接入 Adobe、Blender 等八大创意软件生态，将 AI 能力深度整合至创意专业工作流中。IT之家援引博文介绍，此次更新帮助设计师和音乐制作人突破传统操作限制，支持 Ableton、Adobe、Affinity、Autodesk Fu', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-29 09:33:26', '2026-04-29 09:33:26', '2026-04-29 09:46:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/729.htm', '半导体', '《永恒轮回》腾讯 WeGame 服 6 月 30 日停运，玩家数据可迁移至 Steam 版本', 'https://www.ithome.com/0/944/729.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，二次元大逃杀 MOBA 游戏《永恒轮回》发布公告，宣布 WeGame 服务器将于 2026 年 6 月 30 日正式停止运营。运营团队强调，《永恒轮回》国服并未停运，Steam 版本将继续正常运营，并与国内合作伙伴共同推进后续赛季内容、线下活动及赛事计划。根据公告，WeGame 服停运的主要原因是该版本作为独立运营服务器，当前用户活跃度难以维持健康可持续的运营状态，', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:18', '2026-04-29 09:24:17', '2026-04-29 09:46:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/731.htm', '人工智能', '继马里欧、银河之后，任天堂与照明娱乐合作的“第三部电影”确认 2028 年 4 月上映', 'https://www.ithome.com/0/944/731.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，《超级马里欧银河大电影》已于 4 月 3 日上映，目前豆瓣评分 7.0，IMDB 评分 6.4。VGC 发现，环球影业西班牙官网已经公布了任天堂与照明娱乐的第三部合作电影。环球影业官网显示，这部“未命名的照明娱乐 / 任天堂合作电影（2028 年 4 月）”项目上映日期为 2028 年 4 月 12 日。VGC 猜测，这既可能是《银河大电影》之后的又一部《超级马里欧', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:35', '2026-04-29 09:33:35', '2026-04-29 09:46:38', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/733.htm', '机器人', '消息称苹果 AirPods 将迎史诗级加强，iOS 27 全面重构 Siri AI 语音交互', 'https://www.ithome.com/0/944/733.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，科技媒体 9to5Mac 昨日（4 月 28 日）发布博文，报道称在 iOS 27 系统中，苹果公司将会全面重构 Siri 语音助手，从而增强 AirPods 耳机的交互体验，让其成为用户的全天候智能伴侣，实现类似电影《Her》中的无缝语音交互。IT之家援引博文介绍，基于目前掌握的信息，苹果 iOS 27 版 Siri 预估会提供以下功能：类似 ChatGPT 的对', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:33:29', '2026-04-29 09:33:28', '2026-04-29 09:46:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/734.htm', '新材料', 'IT早报 0429：央视解读“中方禁止 Manus 并购案”；“探店网红”白冰偷税被追罚 1891 万元；追觅 CEO 俞浩再轰小红书“算法问题”；张雪就声援华为余承东争议进行回应...', 'https://www.ithome.com/0/944/734.htm', 'IT之家', '2026-04-28', '“IT早报”时间，大家好，现在是 2026 年 4 月 29 日星期三，今天的重要科技资讯有：1、央视解读“中方禁止 Manus 并购案”：禁的是企业“洗澡式出海”2025 年 12 月，Meta 高调宣布以约 20 亿美元收购 Manus。作为一家依靠中国工程师和基础设施环境发展起来的 AI 公司，Manus 在获得美国投资后突然与中国元素进行“切割”，引发争议。&gt;&gt; 查看详情2、税', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:20', '2026-04-29 09:24:19', '2026-04-29 10:16:50', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/735.htm', '人工智能', '消息称苹果 iOS 27 将扩展 AI 修图功能，新增 3 项编辑功能', 'https://www.ithome.com/0/944/735.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，彭博社今天（4 月 29 日）发布博文，爆料称在 6 月 8 日开幕的 WWDC26 全球开发者大会上，苹果公司将会为 iOS 27 系统，引入三大 AI 照片编辑功能。彭博社称在 iOS 27 系统中，苹果公司将重点发力 AI 图像处理，帮助用户在几秒钟内快速优化、扩展和重构图像，引入 3 项 AI 编辑功能。在界面方面，新版照片（Photos）应用将新增“App', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:24:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/736.htm', '半导体', '漫步者发布严正声明：有不法分子篡改公司的媒体发布内容，制作并传播涉嫌污损伟人形象的伪造图片', 'https://www.ithome.com/0/944/736.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，漫步者官方微博昨晚发布严正声明，称发现有不法分子在社交平台及网络社群中，恶意篡改公司的媒体发布内容，制作并传播涉嫌污损伟人形象的伪造图片。漫步者微博配图显示，其已就此事向网络违法犯罪信息举报网站进行了举报。IT之家附漫步者声明原文如下：近日，我司发现有不法分子在社交平台及网络社群中，恶意篡改我司的媒体发布内容，制作并传播涉嫌污损伟人形象的伪造图片，同时捏造不实信息误', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:18', '2026-04-29 09:24:17', '2026-04-29 10:24:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/737.htm', '机器人', '马斯克庭审自述：创办公司只为拯救人类，OpenAI 奥尔特曼正掏空美国慈善根基', 'https://www.ithome.com/0/944/737.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，埃隆 · 马斯克与 OpenAI 联合创始人、现任 CEO 萨姆 · 奥尔特曼之间备受关注的庭审已于当地时间周一开庭，马斯克在证人席上将自己定位为“人类的拯救者”。他详细回顾了自己的成长经历，从在南非长大、只带着 2500 美元（IT之家注：现汇率约合 17087 元人民币）旅行支票和一袋衣服到加拿大上大学，再到后来创办 Zip2、PayPal 以及如今运营着的一系', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:25', '2026-04-29 09:24:25', '2026-04-29 10:24:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/738.htm', '半导体', '突破 2 纳米工艺极限：DNA 生物晶体管实现分子级计算与存储双重突破', 'https://www.ithome.com/0/944/738.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，韩国科学技术院（KAIST）于 4 月 22 日发布博文，宣布其工程生物学研究生院崔英宰（Yeongjae Choi）教授领导的团队突破 2 纳米工艺极限，成功研发出一种基于 DNA 的生物晶体管，实现了分子层面的计算与信息存储双重功能。相关研究成果已发表于国际期刊《Science Advances》。IT之家援引博文介绍，随着半导体技术逼近 2 纳米极限，进一步微', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:24:54', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/739.htm', '人工智能', '英伟达推出 Nemotron 3 Nano Omni 模型：采用 30B‑A3B 混合 MoE 架构，吞吐量最高提升 9.2 倍', 'https://www.ithome.com/0/944/739.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，当地时间 4 月 28 日，英伟达宣布推出名为 Nemotron 3 Nano Omni 的开源全模态推理模型，旨在为企业级 AI Agent 提供一体化基础模型底座。据介绍，这是一款将视频、音频、图像和文本的统一多模态推理集成于单个高效开放模型中的产品。该模型旨在替代智能体系统中常见的碎片化视觉-语音-语言模型链，从而减少推理跳数与编排复杂度，降低推理成本，同时增', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:24:37', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/741.htm', '机器人', '《连线》称苹果 2024 年斥资 120 万美元，雇佣旧金山警察保护 3 家门店', 'https://www.ithome.com/0/944/741.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，《连线》（Wired）于 4 月 27 日发布博文，报道称苹果公司于 2024 年斥资超 120 万美元，通过第三方安保公司雇佣旧金山警察为其三家门店提供安保。报道指出苹果公司在 2024 年支付超过 120 万美元（IT之家注：现汇率约合 820.2 万元人民币），通过安保供应商 Security Industry Specialists，为旧金山的三家 Appl', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:25', '2026-04-29 09:24:25', '2026-04-29 10:24:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/743.htm', '半导体', '苹果已修复天气应用服务异常，影响约 3 小时 45 分钟', 'https://www.ithome.com/0/944/743.htm', 'IT之家', '2026-04-28', 'IT之家 4 月 29 日消息，根据苹果官方系统状态页面信息，苹果天气应用（Apple Weather）于昨晚出现宕机情况，部分用户遭遇数据加载缓慢或完全失效情况，持续约 3 小时 45 分钟，目前故障已经修复。在故障期间，用户发现该应用无法正常加载天气数据。根据苹果官方系统状态页面信息，本次服务中断于北京时间 4 月 28 日晚上 10 点 45 分钟开始，到 29 日凌晨 2 点 30 分修复', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:22', 0.5);
