INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/745.htm', '人工智能', 'iPad 版 AI 浏览器 Comet 上线，适配苹果 iPadOS 多任务处理', 'https://www.ithome.com/0/944/745.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，Perplexity 旗下 AI 浏览器 Comet 今天官宣全面适配苹果 iPadOS。新版本不仅引入多窗口浏览与多任务处理功能，还深度整合 OpenAI 与 Anthropic 等主流 AI 模型。Comet 浏览器在提供传统的网页浏览功能外，还深度整合了 AI 聊天机器人，支持调用 OpenAI、Anthropic 等主流 AI 模型，为用户提供智能化的搜索与', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/746.htm', '半导体', '微软 PowerToys 0.99 发布：任意位置拖动或缩放窗口、在系统托盘直接调整亮度对比度、加速 WinUI 3 迁移以贴近 Win11 现代化外观', 'https://www.ithome.com/0/944/746.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，微软昨晚发布了最新的 PowerToys 0.99 版本。感兴趣的用户可通过微软商店或 GitHub 下载，也可直接在 PowerToys 内检查更新。PowerToys 0.99 带来了两项全新预览功能：Grab And Move（抓取并移动）与 Power Display（显示器控制），同时命令面板（Command Palette）、Dock 等多项实用功能获得', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/747.htm', '半导体', '中国专门为动物建 240 米长桥，可保障斑林狸、豹猫等本土物种的迁徙不受运河阻隔', 'https://www.ithome.com/0/944/747.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，据央视新闻今日报道，随着在广西的子材大桥昨日正式通车，平陆运河 27 座跨运河桥梁建成。值得一提的是，27 座桥中有一座专门为动物建的通道桥。桥长 240.2 米、宽 20 米，主要为保障斑林狸、豹猫等本土物种的迁徙不受运河阻隔。桥上还会布置植物，模拟动物的生活环境，引导动物通行。IT之家查询获悉，平陆运河是新中国成立', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/750.htm', '新能源汽车', '安靠科技 2026 财年第一财季净利润 8300 万美元，同比增长 293.23%', 'https://www.ithome.com/0/944/750.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，Amkor（安靠科技）今日发布 2026 财年第一财季（也是第一季度）报告：营业总收入： 16.85 亿美元，同比增长 27%归母净利润： 8335.1 万美元，同比增长 294.50%经营现金流： 1.45 亿美元，同比增长 +500.80%基本每股收益： 0.34 美元 / 股，同比增长 277.78%稀释每股收益： 0.33 美元 / 股，同比增长 266.6', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:24:23', '2026-04-29 09:24:22', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/751.htm', '半导体', '部分第三方备份工具不兼容微软 Win11 四月更新，无法读取 / 挂载备份文件', 'https://www.ithome.com/0/944/751.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，科技媒体 BornCity 昨日（4 月 28 日）发布博文，报道称部分磁盘备份软件不兼容微软 Windows 11 四月更新，导致无法正常挂载备份文件。IT之家注：在 2026 年 4 月 14 日补丁星期二活动日，微软面向 Windows 11 系统推送累积更新（KB5083769，内部版本 26200.8246/26100.8246），多位用户反馈安装后，导致', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/753.htm', '人工智能', '小米米家中央空调人感风风管机大 4 匹开售：可变上下双出风，8999 元', 'https://www.ithome.com/0/944/753.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，小米米家中央空调人感风风管机大 4 匹双出风版本昨晚 20:00 正式开售，售价 8999 元，国补到手价 7649.15 元。这款空调为超一级能效（APF 4.62），外机大双排、内机大三排纯铜换热器，换热面积 +15%，支持 10 年免费包修；采用全新一代可变双出风风道，制冷制热双风路；人感智能科技可实现风吹人、风避人、人近柔风、人走节能等功能。<img cl', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/754.htm', '人工智能', '美国国防部确认与谷歌 AI 合作并暗讽 Anthropic：过度依赖单一供应商不是好事', 'https://www.ithome.com/0/944/754.htm', 'IT之家', '2026-04-29', '4 月 29 日，据 CNBC 报道，美国国防部 AI 负责人卡梅伦 · 斯坦利 (Cameron Stanley) 周二证实，美国国防部正扩大对谷歌 Gemini AI 模型的使用。就在大约两个月前，美国防部已将 Anthropic 列为供应链风险，并终止了与其合作。此前，知情人士透露，美国国防部正将谷歌最新模型用于机密项目。图注：谷歌 Gemini站 The Information 援引知情人', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/755.htm', '新能源汽车', '远程执行漏洞被 GitHub 紧急修复：1 条 git push 命令，可访问数百万代码库', 'https://www.ithome.com/0/944/755.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，安全机构 Wiz Research 昨日（4 月 28 日）发布博文，披露 GitHub 存在严重漏洞 CVE-2026-3854。攻击者仅需一条标准 git push 命令，即可触发远程代码执行，进而访问数百万公共和私有仓库。该漏洞追踪编号为 CVE-2026-3854，任何经过身份验证的用户只需执行标准的 git push 命令，就能在 GitHub 后端服务器', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:23', '2026-04-29 09:24:22', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/756.htm', '人工智能', '全新一代红旗 H9 汽车官图发布：中式宫殿礼序章法外观、首搭华为乾崑智驾 ADS 5', 'https://www.ithome.com/0/944/756.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，一汽红旗昨日放出了全新一代红旗 H9 的官图，展示了新车的外观细节和内饰设计。据介绍，全新一代红旗 H9 外观设计灵感取自中式宫殿的礼序章法，融自然山水的流转气韵。新车主打中式豪华美学，采用高山飞瀑格栅搭配贯穿式 U 型灯组设计，辅以四平八稳尾灯 + 镭射工艺。<img class=\"no-alt-img\" src=\"https://img.ithome.com/n', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/760.htm', '半导体', '福岛核事故 15 年后，日本野猪体内放射性铯仍检测超标', 'https://www.ithome.com/0/944/760.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，日本福岛县政府于 4 月 27 日公布了最新的野生鸟兽放射线监测调查结果。其中明确标注了二本松市和须贺川市捕获的野猪共 3 头，其体内放射性铯（铯-134 与铯-137）超过食品卫生法基准值（100 Bq / kg），具体数值未公布。据日本《福岛民报》4 月 28 日报道，此次野猪体内放射性物质检出的根源可追溯至 2011 年福岛第一核电站的核泄漏事故。受事故影响，', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:24:17', '2026-04-29 09:24:17', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/761.htm', '人工智能', '开源鸿蒙 OpenHarmony 社区代码量突破 1.3 亿行，版本已迭代至 6.1 Release', 'https://www.ithome.com/0/944/761.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，在第九届数字中国建设峰会召开前夕，鸿蒙生态峰会（以下简称“峰会”）在福州海峡国际会展中心成功举办。开放原子开源基金会理事长谢少锋在致辞中分享了一组数据：开源鸿蒙自华为捐赠至开放原子开源基金会以来实现快速发展，社区代码量已突破 1.3 亿行，贡献者超过 13000 名，版本已迭代至 6.1 Release，支持手机、平板、电脑、电视、穿戴及行业智能终端等形态。目前，已', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:26', 0.5);
