INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/763.htm', '机器人', 'Framework 推出 RTX 5070 笔记本电脑 GPU 12GB 版本显卡模块，比 8GB 贵 70+%', 'https://www.ithome.com/0/944/763.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，NVIDIA（英伟达）北京时间昨晚推出了 GeForce RTX 5070 笔记本电脑 GPU 12GB 版本，模块化硬件制造商 Framework 也在官网上线了基于该新版本的显卡模块，预售价 1199 美元（IT之家注：现汇率约合 8209 元人民币）。IT之家注意到，Framework 同时也提供原版的 RTX 5070 笔记本电脑 GPU 显卡模块，现价 6', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:24:25', '2026-04-29 09:24:25', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/764.htm', '人工智能', '苹果 iPhone 印度扩产受阻，春节期间失去中国团队支持直接停摆', 'https://www.ithome.com/0/944/764.htm', 'IT之家', '2026-04-29', '北京时间 4 月 29 日，据《日经亚洲》报道，苹果希望实现生产的多元化，但是其供应链依旧高度依赖中国。虽然该公司对印度寄予厚望，但是没有中国团队的帮助，印度生产难以独立运作。iPhone 17 Pro报道称，苹果一直面临压力，需要实现供应链多元化以增强韧性，但这一过程漫长而复杂，将持续到其下一任 CEO 约翰 · 特努斯 (John Ternus) 的任期内。不过，苹果供应商及公司内部人士向《日', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:24:10', '2026-04-29 09:24:09', '2026-04-29 10:56:24', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/765.htm', '新能源汽车', '旺宏抓住三星退场窗口：补位入门级存储芯片，MLC NAND 收入 2026Q1 同比增长 382%', 'https://www.ithome.com/0/944/765.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，集邦咨询 Trendforce 昨日（4 月 28 日）发布博文，报道称三星退出 LPDDR4、LPDDR4X 和 MLC NAND 等存储业务后，旺宏电子（Macronix）等存储厂商获得补位机会。IT之家援引博文介绍，三星近期退出低端 NAND 和 DRAM 业务，把产能转向利润更高的 LPDDR5/X 与高端 NAND 市场。受此影响，入门级平台所需的 LPD', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:33:26', '2026-04-29 09:33:26', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/766.htm', '元宇宙', 'DCU《超级少女》确认引进内地：颓废拽姐开启星际之旅、原 DCEU 海王变“暴狼”，档期待定', 'https://www.ithome.com/0/944/766.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，DC 电影官方今日发布 DCU《超级少女》全新中字预告，并宣布本片将引进内地，档期待定（北美今年 6 月 26 日上映）。本片一大亮点就是原本在 DCEU 饰演海王的杰森・莫玛将饰演暴狼一角。IT之家注：DCU 即 DC Universe（DC 宇宙），2022 年起由詹姆斯・古恩、彼得・萨夫兰联袂打造的架空世界，涵盖电影、剧集、游', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 09:33:16', '2026-04-29 09:33:16', '2026-04-29 10:56:18', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/768.htm', '人工智能', '蚂蚁集团百灵大模型开源 Ling-2.6-flash，提供 BF16、FP8、INT4 等版本', 'https://www.ithome.com/0/944/768.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，蚂蚁集团旗下的百灵大模型今日宣布，Ling-2.6-flash 正式开源。同步提供 BF16、FP8、INT4 等多个版本，方便开发者根据不同硬件环境、推理成本和部署需求灵活选择。Ling-2.6-flash 是一款总参数量 104B、激活参数 7.4B 的 Instruct 模型，两周前以 Elephant Alpha 的匿名身份登陆 OpenRouter。官方表', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:33:14', '2026-04-29 09:33:13', '2026-04-29 10:56:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/769.htm', '人工智能', '昔日“彩电一哥”康佳 2025 年巨亏 125.82 亿元同比扩大 237.73%，将被实施退市风险警示', 'https://www.ithome.com/0/944/769.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，康佳集团股份有限公司 4 月 28 日晚发布了 2025 年年度报告：实现营业收入为 98.35 亿元，同比下降 11.51%；实现归属于上市公司股东的净利润为-125.82 亿元，同比下降 237.73%；经营活动产生的现金流量净额为 16.11 亿元，同比下降 1026%。2025 年业绩变动原', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 09:45:56', '2026-04-29 09:45:55', '2026-04-29 10:56:24', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/770.htm', '新能源汽车', '消息称三星为内置 Qi2 磁吸组件，将调整 Galaxy S27 系列手机后摄布局', 'https://www.ithome.com/0/944/770.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，消息源 yeux1122 于 4 月 27 日发布博文，报道称三星为了内置磁吸模块，将调整手机内部元件方案，进而会调整相机布局。消息称三星调整 Galaxy S27 系列调整相机布局的原因，并非出于外观设计考量，而是为了在机身内部腾出充足空间，内置磁吸线圈和磁铁阵列，从而完全兼容 Qi2 无线充电标准。对于三星消费者而言，可以获得类似苹果 MagSafe 的体验。用', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 09:46:07', '2026-04-29 09:46:07', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/772.htm', '新材料', '同德接管影驰在海外运营，国内市场尚无变动消息', 'https://www.ithome.com/0/944/772.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，综合外媒 Wccftech 报道和油管频道 TecLab 视频，NVIDIA AIC 合作伙伴影驰 (GALAX) 在海外市场的运营由其母公司同德 (Palit) 直接接管。同德就此表示：为了提升管理与运营效率，并应对 AI 时代带来的各类原材料供应短缺问题，同德集团认为有必要进一步整合所有资源，以增强实力并为客户提供更优质的支持。IT之家注意到，影驰在中国大陆与海', '该事件值得关注。', 'other', 0.5, '2026-04-29 09:46:05', '2026-04-29 09:46:05', '2026-04-29 10:56:24', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/778.htm', '人工智能', 'Take-Two CEO 暗示《黑色洛城 2》仍有希望，但原开发商早已倒闭', 'https://www.ithome.com/0/944/778.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，Take-Two CEO 施特劳斯 · 泽尔尼克（Strauss Zelnick）在拉斯维加斯首届 iicon 活动上表示，公司正在考虑为《黑色洛城》等其他沉寂 IP 推出续作的可能性，但暂无具体计划可对外公布。当被问及 Take-Two 是否计划对《黑色洛城》IP 做更多开发时，Zelnick 明确回答“是的”，但随即又补充道“谁也说不准”。“从广义上讲，我们正在', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:56:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/779.htm', '新材料', '华为 WATCH FIT 5 智能手表首销：首发腕上微运动、1.82 英寸 AMOLED 屏，1099 元起', 'https://www.ithome.com/0/944/779.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，除了 Pura 90 Pro 系列手机外，华为 WATCH FIT 5 智能手表今日也迎来首销。该表主打超轻薄大屏 + 腕上微运动 + 长续航，售价 1099 元起。风信紫 / 向新绿 / 韵律黑 / 悦动白（氟胶表带）：1099 元光织银（尼龙表带）：1199 元<a contenteditable=\"false\" href=\"https://u.jd.com/f', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:16:50', '2026-04-29 10:16:50', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/785.htm', '新材料', '海盗船推出 ThermalProtect PCIe 5.1 600W 12V-2x6 线缆：内置高温断电保护机制', 'https://www.ithome.com/0/944/785.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，CORSAIR（海盗船）美国当地时间昨日宣布推出 ThermalProtect PCIe 5.1 600W 12V-2x6 线缆。这一产品在距端子 30mm 的线梳处集成了高温保护 (OTP) 模块，当其检测到不安全温度时 OTP 技术会立即启动，使显卡关机以防止任何潜在损坏。如果用户确认 OTP 激活，则应长按电源键直到关机，等待电脑冷却，检查线缆端子和显卡接口是', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:50', '2026-04-29 10:16:50', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/786.htm', '人工智能', '地平线创始人余凯：不做“内卷”要“外卷”，16 万的车必须能卖 19 万，客户开开心心掏钱', 'https://www.ithome.com/0/944/786.htm', 'IT之家', '2026-04-29', '4 月 28 日上午消息，2026 北京国际车展期间，面对汽车行业强内卷与强降本的双重挤压，地平线创始人余凯给出了一个反共识的答案：跳出包围圈，在外线作战。“如果是顺着传统当前的现状让你去玩，在车厂、供应商和用户之间其实是三输，大家都输。”余凯直言，同质化竞争下，价格压力传导至供应商，没有利润就无法开发有竞争力的技术，最终恶性的环境传递给消费者，“消费者能够享受到高性能、美轮美奂的产品吗？不会的。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/788.htm', '人工智能', 'Proton 揭示谷歌美国用户平均广告价值：苹果 iPhone 用户价值是安卓的 2.7 倍', 'https://www.ithome.com/0/944/788.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，隐私服务商 Proton 昨日（4 月 28 日）发布报告，指出谷歌正根据人口统计数据，为几乎每位美国用户“明码标价”。数据显示美国用户平均年度广告价值为 1605 美元（IT之家注：现汇率约合 10988 元人民币）。该报告利用 2025 年的广告竞价数据，分析了超过 54000 个人口统计资料，精准测算出广告商为接触不同美国用户所支付的费用。研究发现谷歌为了精准', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/789.htm', '新能源汽车', '深蓝 S09 汽车开启 V5.2.0 版本 OTA 升级：支持哨兵模式自动开启等', 'https://www.ithome.com/0/944/789.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，深蓝汽车今日宣布，深蓝 S09 汽车 OTA 升级 V5.2.0 版本。IT之家附主要更新内容如下：驾驶辅助哨兵模式：（ADS Max 版）驻车后哨兵模式根据环境自动开启，可设置家 / 公司等地点免打扰；开启哨兵时收到 OTA 升级任务，车辆完成升级后将自动恢复后视辅助：新增可通过方向盘自定义按键或中控屏，一键开启后鱼眼摄像头，弹窗查看车后情况（ADS SE 版）<', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:16:54', '2026-04-29 10:16:53', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/791.htm', '机器人', '小米米家无线吸尘器 4C 开售：170AW 吸力、75 分钟续航，国补价 799 元', 'https://www.ithome.com/0/944/791.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，小米旗下米家无线吸尘器 4C 今日正式开售，该产品提供 170AW 吸力，官方定价 940 元，叠加国补后 799 元。京东小米米家无线吸尘器 4C</sp', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:56', '2026-04-29 10:16:56', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/792.htm', '机器人', 'PS5-Linux 工具发布：PS5 变 Linux PC，解锁 3.5GHz CPU 与 2.23GHz GPU', 'https://www.ithome.com/0/944/792.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，科技媒体 NotebookCheck 今天（4 月 29 日）发布博文，报道称安全工程师 Andy Nguyen 发布 PS5-Linux 工具，扩展索尼 PlayStation 5 的应用边界，将这款游戏主机转化为功能完备的 Linux 游戏 PC。根据 GitHub 项目文档，PS5-Linux 利用虚拟机管理程序漏洞（已修复），来解锁主机硬件限制。用户在 PS', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:16:56', '2026-04-29 10:16:56', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/793.htm', '人工智能', '特斯拉用 V14 Lite 让 HW3 老车主体验 FSD 最新功能，后续扩展至更多国际市场', 'https://www.ithome.com/0/944/793.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，马斯克已经在特斯拉 2026 年第一季度财报电话会议上确认，Hardware 3 车辆将无法实现无监督 FSD 功能，但公司并未抛弃老车主。为弥补硬件上的差距，特斯拉官方宣布为 HW3 设计的 V14 Lite 将于 6 月底在美国推出。这是一个大规模软件更新，旨在为老款车型引入最新 FSD 功能。特斯拉官方今日确认，继美国推出后，他们也计划将 V14 Lite 扩', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:16:39', '2026-04-29 10:16:38', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/798.htm', '新材料', '华硕灵耀 14 Air 骁龙版开售：X2 Elite Extreme 处理器，48GB+1TB 售 13999 元', 'https://www.ithome.com/0/944/798.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，全新华硕灵耀 16 Air 骁龙版轻薄本宣布开售。该机提供了两个版本，IT之家汇总如下：高通骁龙 X2 Elite 处理器、16GB 内存、1TB 固态硬盘：11999 元。高通骁龙 X2 Elite Extreme 处理器、48GB 内存、1TB 固态硬盘：13999 元。', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:24:04', '2026-04-29 10:24:04', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/800.htm', '新能源汽车', '我国稀土、钨、锡等 14 种矿产储量居世界第一位，新一轮找矿突破行动成果公布', 'https://www.ithome.com/0/944/800.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，据央视新闻今日报道，我国新一轮找矿突破战略行动取得一系列新突破，矿产资源家底进一步夯实，有力保障了国家能源资源安全。自然资源部表示，2021 年启动新一轮找矿突破战略行动以来，我国矿产资源储量大幅增长，新发现战略性矿产大中型矿产地（油气田）398 处，铜、金、钾盐等大宗矿产勘查取得一批历史性突破，锂、氦气、高纯石英等战略新兴矿产勘查实现跨越式发展，资源自主保障能力显', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:53', '2026-04-29 10:54:53', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/801.htm', '人工智能', '缺乏 XInput 兼容性，Steam Controller 手柄暂未适配 Xbox 游戏库', 'https://www.ithome.com/0/944/801.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，科技媒体 NotebookCheck 今天（4 月 29 日）发布博文，报道称 Steam Controller 游戏手柄依赖 Steam 生态，无法原生兼容 Xbox Game Pass 等第三方平台游戏。Valve 官宣将于北京时间 5 月 5 日凌晨 1 点发售 Steam Controller 游戏手柄，售价为 99 美元（IT之家注：现汇率约合 677.8', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/806.htm', '半导体', 'Anthropic Claude Code 大幅涨价：从预估每日 6 美元翻倍至 13 美元', 'https://www.ithome.com/0/944/806.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，据多个媒体报道，Anthropic 近期在没有发布公告的情况下，悄悄将其 Claude Code 的 token 成本翻倍。根据 Claude Code 官网的最新说明，“在企业部署中，每个开发者每个活跃日的平均成本约为 13 美元，90% 的用户每日成本低于 30 美元。每个开发者每月的成本约为 150-250 美元（现汇率约合 1027 - 1712 元人民币）', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:47', '2026-04-29 10:54:47', '2026-04-29 10:56:26', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/810.htm', '人工智能', '京东快递“小红箱”全国上线，手机碰一碰就能寄特产行李', 'https://www.ithome.com/0/944/810.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，京东快递今日宣布在全国 80 个文旅城市完成“小红箱”智能寄递设备部署，全面覆盖景区、酒店、交通枢纽等出行核心场景，通过将 NFC（近场通信）技术与快递服务融合，进一步升级“轻松行”服务，提升五一假期出行体验。据介绍，京东快递“小红箱”核心依托 NFC 技术，实现秒碰秒寄。游客只需打开手机 NFC 功能轻碰“小红箱”，便可快速完成领券、下单、寄件全流程操作，无需手动', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.ithome.com/0/944/811.htm', '人工智能', 'Valve 坦言受运输成本上涨影响，Steam Controller 手柄售价高于内部预期', 'https://www.ithome.com/0/944/811.htm', 'IT之家', '2026-04-29', 'IT之家 4 月 29 日消息，在接受 Polygon 媒体采访时，Valve 硬件工程师史蒂夫 · 卡尔达利（Steve Cardinali）坦言，受内存短缺和物流成本攀升影响，因此决定提前发布 Steam Controller 游戏手柄。Valve 于 2025 年发布游戏手柄 Steam Controller、游戏 PC 主机 Steam Machine 和 VR 头显 Steam Fram', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-29 10:54:38', '2026-04-29 10:54:38', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.tmtpost.com/7925084.html', '机器人', '群核科技VP再创业：首创3DGS相机品类，峰瑞资本领投｜融资速递', 'https://www.tmtpost.com/7925084.html', '钛媒体', '2026-04-29', '本轮融资资金将主要用于核心技术研发、首代产品量产以及全球顶尖人才引进。', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-29 10:16:57', '2026-04-29 10:16:56', '2026-04-29 10:56:29', 0.5);
