INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.tmtpost.com/7971324.html', '机器人', '对话宝马新世代负责人：中国速度，正在改写宝马的开发方式', 'https://www.tmtpost.com/7971324.html', '钛媒体', '2026-04-29', '宝马正在用中国速度重做“驾驶机器”。', '该事件值得关注。', 'other', 0.5, '2026-04-29 10:16:57', '2026-04-29 10:16:56', '2026-04-29 10:56:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.tmtpost.com/7971741.html', '人工智能', '继往开来：探索 AI 时代新的认知体系', 'https://www.tmtpost.com/7971741.html', '钛媒体', '2026-04-30', '当前，人工智能技术正在以前所未有的速度和深度改变人类社会的生产方式、组织形态、认知模式乃至存在方式，其冲击的广度和烈度堪比甚至超越以往任何一次文明转型。在这一历史节点上，重新审视人类伟大思想体系形成的历史条件与内在逻辑，进而探索AI时代所需要的新思想认知框架，是时代赋予思想者的紧迫使命。', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 17:17:03', '2026-04-30 17:17:02', '2026-04-30 18:08:57', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('https://www.tmtpost.com/7973821.html', '机器人', '银河通用拉着英伟达，把人形机器人最大的谎言拆穿了', 'https://www.tmtpost.com/7973821.html', '钛媒体', '2026-04-30', '放下对完美数据的傲慢，让AI从粗糙和失败中汲取真实世界的物理法则。', '该事件值得关注。', 'other', 0.5, '2026-04-30 17:17:50', '2026-04-30 17:17:50', '2026-04-30 18:09:46', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-1284871187211468299', '机器人', '无人机实名登记和激活要求将于5月1日起全国实施', 'https://www.chinanews.com.cn/cj/2026/04-30/10613761.shtml', '中新经纬', '2026-04-30', '新华社北京4月30日电(记者王聿昊)记者4月30日从中国民航局获悉，由中国民航局发布的强制性国家标准《民用无人驾驶航空器实名登记和激活要求》将于5月1日起正式实施，旨在将“实名登记激活”要求落到实处，构建覆盖全生命周期的可追溯管理体系，为公共安全、空域秩序及个人权益提供基础保障。', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:01:15', '2026-04-30 18:01:15', '2026-04-30 18:01:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-1290571538254493331', '人工智能', '机器人进厂打工还有多远？浙江发力攻克“练兵”全链条', 'https://www.chinanews.com.cn/cj/2026/04-30/10613828.shtml', '中新经纬', '2026-04-30', '中新网杭州4月30日电(蓝伊旎)随着人工智能技术加速落地，越来越多机器人成为生产线上的好帮手。今年一季度，浙江工业机器人产品产量同比增长44.0%，折射出制造业智能化转型的步伐。', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
