INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-1766828418214437048', '半导体', '依托京东JoyAI大模型 京办、京通APP数字中国创新大赛同获大奖', 'https://www.chinanews.com.cn/cj/2026/04-30/10613904.shtml', '中新经纬', '2026-04-30', '4月29-30日，第九届数字中国建设峰会在福建福州举办，京东可信 AI与政务智能体为核心成果亮相，全面展示AI助力数字政务建设的创新实践与落地成效。京东集团副总裁、协同办公业务总经理王涛受邀发表主题演讲，分享京东政务智能体的技术突破与创新实践，并现场参与国家网信办主导的《政务智能体研发应用自律倡议》签约活动。', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:03:32', '2026-04-30 18:03:31', '2026-04-30 18:03:31', 0.5);
