INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-4558038526801059836', '人工智能', '机器人进厂打工还有多远？浙江发力攻克“练兵”全链条', 'https://www.chinanews.com.cn/cj/2026/04-30/10613828.shtml', '中新经纬', '2026-04-30', '中新网杭州4月30日电(蓝伊旎)随着人工智能技术加速落地，越来越多机器人成为生产线上的好帮手。今年一季度，浙江工业机器人产品产量同比增长44.0%，折射出制造业智能化转型的步伐。', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:07:59', '2026-04-30 18:07:59', '2026-04-30 18:08:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-471963639059735519', '人工智能', '中国电信董事长：AI技术迭代提速  产业呈三大新变化', 'https://www.chinanews.com.cn/cj/2026/04-30/10613749.shtml', '中新经纬', '2026-04-30', '中新社福州4月30日电 (记者 刘亮)第九届数字中国建设峰会·智能云生态大会30日在福州召开。中国电信集团董事长柯瑞文在会上致辞时指出，今年以来，人工智能(AI)技术迭代明显提速，产业呈三大新的形势变化。', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:04:14', '2026-04-30 18:04:13', '2026-04-30 18:04:13', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-5237643466215229960', '新材料', '首席记者谈首季经济｜从“三个样本”看吉林全面振兴的“新质答卷”', 'https://www.chinanews.com.cn/cj/2026/04-30/10613847.shtml', '中新经纬', '2026-04-30', '松辽沃野，春暖花开。广袤的东北黑土地，如今不仅能长出好庄稼，还能“长”出新材料、新能源、创新药这些“金豆子”。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:04:41', '2026-04-30 18:04:40', '2026-04-30 18:04:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-5538657334678361494', '新能源汽车', '2026湖南车展开幕  首发经济赋能汽车消费提质', 'https://www.chinanews.com.cn/cj/2026/04-30/10613846.shtml', '中新经纬', '2026-04-30', '中新网长沙4月30日电 (记者 杨华峰)4月30日，2026湖南汽车展览会暨长沙市汽车促消费活动在湖南国际会展中心(芒果馆)启幕，展会将持续至5月5日。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:06:56', '2026-04-30 18:06:55', '2026-04-30 18:06:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-598939583696834865', '机器人', '无人机实名登记和激活要求将于5月1日起全国实施', 'https://www.chinanews.com.cn/cj/2026/04-30/10613761.shtml', '中新经纬', '2026-04-30', '新华社北京4月30日电(记者王聿昊)记者4月30日从中国民航局获悉，由中国民航局发布的强制性国家标准《民用无人驾驶航空器实名登记和激活要求》将于5月1日起正式实施，旨在将“实名登记激活”要求落到实处，构建覆盖全生命周期的可追溯管理体系，为公共安全、空域秩序及个人权益提供基础保障。', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:03:55', '2026-04-30 18:03:55', '2026-04-30 18:03:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-5994535444338676184', '新能源汽车', '成都“第二水源”李家岩水库正式下闸蓄水', 'https://www.chinanews.com.cn/cj/2026/04-30/10613805.shtml', '中新经纬', '2026-04-30', '中新网成都4月30日电 (尧欣雨)30日，成都“第二水源”李家岩水库正式下闸蓄水。据悉，下闸蓄水是水利工程建设历程中最关键、最重要的里程碑节点之一。作为国家172项节水供水重大水利项目之一，李家岩水库的正式蓄水将打破成都长期以来的单一水源供水格局，构建起“双水源保障网”，极大增强超大城市供水系统的抗风险能力和韧性，全面提升城市水资源保障能力。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:06:56', '2026-04-30 18:06:55', '2026-04-30 18:06:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-6243879883594211974', '半导体', '依托京东JoyAI大模型 京办、京通APP数字中国创新大赛同获大奖', 'https://www.chinanews.com.cn/cj/2026/04-30/10613904.shtml', '中新经纬', '2026-04-30', '4月29-30日，第九届数字中国建设峰会在福建福州举办，京东可信 AI与政务智能体为核心成果亮相，全面展示AI助力数字政务建设的创新实践与落地成效。京东集团副总裁、协同办公业务总经理王涛受邀发表主题演讲，分享京东政务智能体的技术突破与创新实践，并现场参与国家网信办主导的《政务智能体研发应用自律倡议》签约活动。', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:08:20', '2026-04-30 18:08:19', '2026-04-30 18:08:19', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-6349634906854988221', '新能源汽车', '成都“第二水源”李家岩水库正式下闸蓄水', 'https://www.chinanews.com.cn/cj/2026/04-30/10613805.shtml', '中新经纬', '2026-04-30', '中新网成都4月30日电 (尧欣雨)30日，成都“第二水源”李家岩水库正式下闸蓄水。据悉，下闸蓄水是水利工程建设历程中最关键、最重要的里程碑节点之一。作为国家172项节水供水重大水利项目之一，李家岩水库的正式蓄水将打破成都长期以来的单一水源供水格局，构建起“双水源保障网”，极大增强超大城市供水系统的抗风险能力和韧性，全面提升城市水资源保障能力。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:35', '2026-04-30 18:08:34', '2026-04-30 18:08:34', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-6372995241547774551', '人工智能', '国家人工智能应用中试基地已汇聚近300P国产化推理算力', 'https://www.chinanews.com.cn/cj/2026/04-30/10613878.shtml', '中新经纬', '2026-04-30', '中新网东莞4月30日电 (记者 许青青)东莞市工业和信息化局、东莞市发展和改革局、东莞市政务服务和数据管理局等共同主办国家人工智能应用中试基地对接大会29日在东莞滨海湾新区举行。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:09', '2026-04-30 18:03:09', 0.5);
