INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-8137245295522996065', '人工智能', '中国电信董事长：AI技术迭代提速  产业呈三大新变化', 'https://www.chinanews.com.cn/cj/2026/04-30/10613749.shtml', '中新经纬', '2026-04-30', '中新社福州4月30日电 (记者 刘亮)第九届数字中国建设峰会·智能云生态大会30日在福州召开。中国电信集团董事长柯瑞文在会上致辞时指出，今年以来，人工智能(AI)技术迭代明显提速，产业呈三大新的形势变化。', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:09', '2026-04-30 18:03:09', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-832288303276815477', '机器人', '5月1日起 民用无人驾驶航空器等1071项国标开始实施', 'https://www.chinanews.com.cn/cj/2026/04-30/10613928.shtml', '中新经纬', '2026-04-30', '新华社权威快报｜5月1日起 民用无人驾驶航空器等1071项国标开始实施', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:43', '2026-04-30 18:08:42', '2026-04-30 18:08:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-8580812192933011965', '机器人', '无人机实名登记和激活要求将于5月1日起全国实施', 'https://www.chinanews.com.cn/cj/2026/04-30/10613761.shtml', '中新经纬', '2026-04-30', '新华社北京4月30日电(记者王聿昊)记者4月30日从中国民航局获悉，由中国民航局发布的强制性国家标准《民用无人驾驶航空器实名登记和激活要求》将于5月1日起正式实施，旨在将“实名登记激活”要求落到实处，构建覆盖全生命周期的可追溯管理体系，为公共安全、空域秩序及个人权益提供基础保障。', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:04:54', '2026-04-30 18:04:53', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_-8580874149714991554', '人工智能', '中国电信董事长：AI技术迭代提速  产业呈三大新变化', 'https://www.chinanews.com.cn/cj/2026/04-30/10613749.shtml', '中新经纬', '2026-04-30', '中新社福州4月30日电 (记者 刘亮)第九届数字中国建设峰会·智能云生态大会30日在福州召开。中国电信集团董事长柯瑞文在会上致辞时指出，今年以来，人工智能(AI)技术迭代明显提速，产业呈三大新的形势变化。', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:01:59', '2026-04-30 18:01:58', '2026-04-30 18:01:58', 0.5);
