INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_2458734375506658358', '新能源汽车', '成都“第二水源”李家岩水库正式下闸蓄水', 'https://www.chinanews.com.cn/cj/2026/04-30/10613805.shtml', '中新经纬', '2026-04-30', '中新网成都4月30日电 (尧欣雨)30日，成都“第二水源”李家岩水库正式下闸蓄水。据悉，下闸蓄水是水利工程建设历程中最关键、最重要的里程碑节点之一。作为国家172项节水供水重大水利项目之一，李家岩水库的正式蓄水将打破成都长期以来的单一水源供水格局，构建起“双水源保障网”，极大增强超大城市供水系统的抗风险能力和韧性，全面提升城市水资源保障能力。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:09:39', '2026-04-30 18:09:38', '2026-04-30 18:09:38', 0.5);
