INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_2719972687581411935', '机器人', '黑龙江机场集团“五一”小长假预计运送旅客37万人次', 'https://www.chinanews.com.cn/cj/2026/04-30/10613716.shtml', '中新经纬', '2026-04-30', '中新网哈尔滨4月30日电 (刘烨)2026年“五一”假期临近，黑龙江机场集团迎来出行客流高峰，预计保障航班起降2700架次，运送旅客37万人次。其中，哈尔滨机场预计保障航班起降2100架次，运送旅客31万人次。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:01:15', '2026-04-30 18:01:15', '2026-04-30 18:01:15', 0.5);
