INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_3242926184691792929', '新能源汽车', '成都“第二水源”李家岩水库正式下闸蓄水', 'https://www.chinanews.com.cn/cj/2026/04-30/10613805.shtml', '中新经纬', '2026-04-30', '中新网成都4月30日电 (尧欣雨)30日，成都“第二水源”李家岩水库正式下闸蓄水。据悉，下闸蓄水是水利工程建设历程中最关键、最重要的里程碑节点之一。作为国家172项节水供水重大水利项目之一，李家岩水库的正式蓄水将打破成都长期以来的单一水源供水格局，构建起“双水源保障网”，极大增强超大城市供水系统的抗风险能力和韧性，全面提升城市水资源保障能力。', '该事件值得关注。', 'other', 0.5, '2026-04-30 17:17:44', '2026-04-30 17:17:44', '2026-04-30 17:17:44', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_3482450722307975098', '人工智能', '机器人进厂打工还有多远？浙江发力攻克“练兵”全链条', 'https://www.chinanews.com.cn/cj/2026/04-30/10613828.shtml', '中新经纬', '2026-04-30', '中新网杭州4月30日电(蓝伊旎)随着人工智能技术加速落地，越来越多机器人成为生产线上的好帮手。今年一季度，浙江工业机器人产品产量同比增长44.0%，折射出制造业智能化转型的步伐。', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:04:14', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_3562863881191000753', '新能源汽车', '2026湖南车展开幕  首发经济赋能汽车消费提质', 'https://www.chinanews.com.cn/cj/2026/04-30/10613846.shtml', '中新经纬', '2026-04-30', '中新网长沙4月30日电 (记者 杨华峰)4月30日，2026湖南汽车展览会暨长沙市汽车促消费活动在湖南国际会展中心(芒果馆)启幕，展会将持续至5月5日。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:09:39', '2026-04-30 18:09:38', '2026-04-30 18:09:38', 0.5);
