INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_824094483841787708', '新材料', '首席记者谈首季经济｜从“三个样本”看吉林全面振兴的“新质答卷”', 'https://www.chinanews.com.cn/cj/2026/04-30/10613847.shtml', '中新经纬', '2026-04-30', '松辽沃野，春暖花开。广袤的东北黑土地，如今不仅能长出好庄稼，还能“长”出新材料、新能源、创新药这些“金豆子”。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:28', '2026-04-30 18:08:27', '2026-04-30 18:08:34', 0.5);
