INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_9117868743389273738', '新能源汽车', '成都“第二水源”李家岩水库正式下闸蓄水', 'https://www.chinanews.com.cn/cj/2026/04-30/10613805.shtml', '中新经纬', '2026-04-30', '中新网成都4月30日电 (尧欣雨)30日，成都“第二水源”李家岩水库正式下闸蓄水。据悉，下闸蓄水是水利工程建设历程中最关键、最重要的里程碑节点之一。作为国家172项节水供水重大水利项目之一，李家岩水库的正式蓄水将打破成都长期以来的单一水源供水格局，构建起“双水源保障网”，极大增强超大城市供水系统的抗风险能力和韧性，全面提升城市水资源保障能力。', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:01:05', '2026-04-30 18:01:05', '2026-04-30 18:01:05', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_9131867487215203373', '机器人', '无人机实名登记和激活要求将于5月1日起全国实施', 'https://www.chinanews.com.cn/cj/2026/04-30/10613761.shtml', '中新经纬', '2026-04-30', '新华社北京4月30日电(记者王聿昊)记者4月30日从中国民航局获悉，由中国民航局发布的强制性国家标准《民用无人驾驶航空器实名登记和激活要求》将于5月1日起正式实施，旨在将“实名登记激活”要求落到实处，构建覆盖全生命周期的可追溯管理体系，为公共安全、空域秩序及个人权益提供基础保障。', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 17:17:52', '2026-04-30 17:17:51', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('中新经纬_984087436282484399', '半导体', '依托京东JoyAI大模型 京办、京通APP数字中国创新大赛同获大奖', 'https://www.chinanews.com.cn/cj/2026/04-30/10613904.shtml', '中新经纬', '2026-04-30', '4月29-30日，第九届数字中国建设峰会在福建福州举办，京东可信 AI与政务智能体为核心成果亮相，全面展示AI助力数字政务建设的创新实践与落地成效。京东集团副总裁、协同办公业务总经理王涛受邀发表主题演讲，分享京东政务智能体的技术突破与创新实践，并现场参与国家网信办主导的《政务智能体研发应用自律倡议》签约活动。', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:09:22', '2026-04-30 18:09:21', '2026-04-30 18:09:21', 0.5);
