INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-1162439009814552350', '人工智能', 'OpenAI 最强模型 GPT-5.5 上线；传特斯拉与 SpaceX 终将合并；票价 20 万！12306 惊现豪华专列', 'http://www.geekpark.net/news/363096', '极客公园', '2026-04-24', 'OpenAI 最智能 AI 模型：GPT-5.5 登场，Token 成本降至 1/35、输出提速 50 倍4 月 24 日，OpenAI 正式发布旗下迄今最智能的 AI 模型 GPT-5.5。该模型核心突破在于大幅升级的 Agent 智能体能力，能精准理解用户模糊指令，自主规划、调用工具并执行多步骤复杂任务，无需用户精细管控每一步流程，在 Agentic Coding、计算机使用、科研等领域表现卓', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-1207808867174886585', '人工智能', '余承东：问界 M9 Ultimate 5 月亮相；苹果新 CEO 首秀定档 9 月发布会；马斯克：无人驾驶车正式投产｜极客早知道', 'http://www.geekpark.net/news/363263', '极客公园', '2026-04-27', '\n&nbsp;\n\nD', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-1213184830661002381', '人工智能', '豆包上线「帮你选」功能； 5999 元，泡泡玛特首推冰箱；高铁试点「坐火车带自行车」 | 极客早知道｜极客早知道', 'http://www.geekpark.net/news/363226', '极客公园', '2026-04-25', '\n英特尔股价周五暴涨 24% 创 1987 年以来最大单日涨幅\n4 月 25 日消息，英特尔股价周五飙升 24%，创下自 1987 年 10 月以来的最佳单日表现，投资者对因人工智能需求增长而带来的复苏迹象感到振奋。\n该股收于 82.57 美元，继 2025 年全年上涨 84% 之后，今年迄今已累计上涨 124%。上周五的涨势超过了该股在 9 月 18 日 23% 的涨幅&mdash;&mdash', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-1222541803375836665', '人工智能', '阿里、美团、字节、小米罕见「会师」，四大厂为何共同押注自变量机器人', 'http://www.geekpark.net/news/363262', '极客公园', '2026-04-26', '\n\n\n当很多具身智能公司更关心机器人先在哪些场景里跑通商业化时，自变量更想寻找哪条路径能够通往 AGI。\n作者｜Li Yuan<strong style=\"text-indent: 0em; font-size: 16px; color: #3', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:07:59', '2026-04-30 18:07:58', '2026-04-30 18:08:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-1264827992781023568', '人工智能', '小红书：内容添加 AI 标识，反对 AI 造假；小米全新机器人亮相；微信 15 周年皮肤衣开卖，238 元 | 极客早知道', 'http://www.geekpark.net/news/363371', '极客公园', '2026-04-28', '\n小红书首次公布 AI 治理主张：坚决反对四类 AI 行为，给 AI 创作划出清晰边界\n4 月 27 日，小红书首次公布平台对 AI 内容的治理主张，并在北京举办首届 AI 治理开放日。此次 AI 治理主张共分为「平台鼓励的 AI 内容及行为」和「平台反对的 AI 内容及行为」两大板块，以给到创作者清晰指引。\n小红书明确了对待 AI 相关现象的核心态度：鼓励 AI 作为创意放大器，反对 AI 作为', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:07:59', '2026-04-30 18:07:58', '2026-04-30 18:08:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-1276644390349512054', '人工智能', 'DeepSeek 正式发布 V4 API：Flash/Pro 双版本齐发，百万上下文成标配', 'http://www.geekpark.net/news/363222', '极客公园', '2026-04-24', '&nbsp;\n极客一问：你怎么看这次 DeepSeek V4 的更新？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n万众期待中，DeepSeek V4，终于发布了！\n&nbsp;\n就在刚刚，被期待已久的DeepSeek V4 预览版正式登场。两个版本&mdash;&mdash;V4-Pro 和 V4-Flash，全系标配 1M（百万字）超长上下文，同步开源模型权重和技术报告。\n&nbsp;\n', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
