INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-1340216195827541162', '人工智能', 'MiniMax 登上戛纳，AI 与艺术的全球和解开始了？', 'http://www.geekpark.net/news/363324', '极客公园', '2026-04-27', '作者｜Cynthia \n编辑｜ 郑玄\n&nbsp;\n2026 年的春天，影视圈的风向开始变了。\n4 月 21 日，全球首个，也是迄今为止规模最大的 AI 电影节 WAIFF（2026），在法国戛纳电影宫正式举办。蔚蓝海岸线前，一众影视行业的从业者鱼贯而入，但一改往日红毯众星云集的流光溢彩，这一次的电影节，地毯换成了象征科技的紫色，而走上这条「紫毯」的，也换成了一众 AI 内容的创作者。\n<p st', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:46', 0.5);
