INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-1459263600846208001', '人工智能', '大模型上车两年，为什么「真·AI 汽车」现在才出现？', 'http://www.geekpark.net/news/363204', '极客公园', '2026-04-24', '今天在北京车展上爆火的极氪 8X，有网友放出了一段新车演示视频，用户坐在车里说了一句「带我去接孩子放学，顺便找一家麦当劳，5 点前我要到学校」。\n接下来发生的事情，和你过去对「智能汽车」的认知完全不同。车辆自主规划路线，启动智能驾驶，中途停靠麦当劳，到达学校门口自动泊车。整个过程，用户不需要碰导航、手动切换智驾模式、或者在停车场里找车位。\n这不是一个语音助手在帮你搜索，而是一个 Agent 在替你', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:55', 0.5);
