INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-2268605535206040887', '人工智能', '小红书：内容添加 AI 标识，反对 AI 造假；小米全新机器人亮相；微信 15 周年皮肤衣开卖，238 元 | 极客早知道', 'http://www.geekpark.net/news/363371', '极客公园', '2026-04-28', '\n小红书首次公布 AI 治理主张：坚决反对四类 AI 行为，给 AI 创作划出清晰边界\n4 月 27 日，小红书首次公布平台对 AI 内容的治理主张，并在北京举办首届 AI 治理开放日。此次 AI 治理主张共分为「平台鼓励的 AI 内容及行为」和「平台反对的 AI 内容及行为」两大板块，以给到创作者清晰指引。\n小红书明确了对待 AI 相关现象的核心态度：鼓励 AI 作为创意放大器，反对 AI 作为', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-2326769751005823677', '新材料', '清华姚班到全球 3D AI 第一：胡渊鸣的 Meshy ARR 已超 4000 万美元', 'http://www.geekpark.net/news/363031', '极客公园', '2026-04-23', '\n\n\n当文字、图像、视频已经先后被生成式 AI 重写，3D 很可能就是下一站。\n<strong style=\"text-indent: 0em; font-size: 16px; color: #375474; font-famil', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:02:30', '2026-04-30 18:02:29', '2026-04-30 18:02:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-2334091680482740565', '人工智能', '阿里、美团、字节、小米罕见「会师」，四大厂为何共同押注自变量机器人', 'http://www.geekpark.net/news/363262', '极客公园', '2026-04-26', '\n\n\n当很多具身智能公司更关心机器人先在哪些场景里跑通商业化时，自变量更想寻找哪条路径能够通往 AGI。\n作者｜Li Yuan<strong style=\"text-indent: 0em; font-size: 16px; color: #3', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-2425281644259790992', '新材料', 'Kimi K2.6 这次把 Agent 玩明白了吗？', 'http://www.geekpark.net/news/362947', '极客公园', '2026-04-22', '&nbsp;\n头图来源：Kimi官网\n&nbsp;\n&nbsp;\n当一个AI系统可以在无人工干预的情况下，独立完成一个复杂项目的完整交付，以及，当这些能力开始可以被复用、被沉淀为「技能」，AI在职场中的角色，是否已经发生了本质变化？\nOpenClaw这波热潮带动了大模型竞争进入深水区，赛道的分水岭，从「谁更强」，转向了「谁能真正交付生产力」。自主Agent的落地能力、工程化适配水平以及长时稳定运行', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:57', '2026-04-30 18:00:56', '2026-04-30 18:00:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-2458475298203346298', '人工智能', '马斯克：OpenAI 是我的创意，Altman 是小偷；Claude Code 使用成本翻倍；Image 2 登顶视觉模型榜｜极客早知道', 'http://www.geekpark.net/news/363594', '极客公园', '2026-04-30', '\n结束与微软独家合作，OpenAI 模型接入亚马逊 AWS\n4 月 29 日，在亚马逊云科技（Amazon Web Services，简称 AWS）新品发布会上，AWS 宣布携手 OpenAI，将 OpenAI 最新大模型接入 Amazon Bedrock，在 Amazon Bedrock 上线 Codex 代码 Agent，并推出由 OpenAI 赋能的 Amazon Bedrock 托管 Ag', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
