INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-2605885307624441318', '人工智能', 'OpenAI 硬件负责人的闭门分享，向我们揭示了为什么硬件「终点」仍是智能手机', 'http://www.geekpark.net/news/363596', '极客公园', '2026-04-29', '\n\n\n「你必须为模型将要去的方向设计硬件，而不是为今天的模型。」\n<section class=\"js_darkmode__3', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-2704531026452922882', '人工智能', 'OpenAI 最强模型 GPT-5.5 上线；传特斯拉与 SpaceX 终将合并；票价 20 万！12306 惊现豪华专列', 'http://www.geekpark.net/news/363096', '极客公园', '2026-04-24', 'OpenAI 最智能 AI 模型：GPT-5.5 登场，Token 成本降至 1/35、输出提速 50 倍4 月 24 日，OpenAI 正式发布旗下迄今最智能的 AI 模型 GPT-5.5。该模型核心突破在于大幅升级的 Agent 智能体能力，能精准理解用户模糊指令，自主规划、调用工具并执行多步骤复杂任务，无需用户精细管控每一步流程，在 Agentic Coding、计算机使用、科研等领域表现卓', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:09', '2026-04-30 18:03:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-3331451304191957435', '人工智能', '当剪辑工具开始「听懂人话」：剪映做了视频创作的Skill化Agent', 'http://www.geekpark.net/news/363407', '极客公园', '2026-04-28', '&nbsp;\n如果有人告诉你，视频剪辑可以像「刷手机」一样轻松，你大概率会在脑海里冒个问号。\n毕竟在我们的习惯里，剪辑往往意味着「高强度的手眼协同」&mdash;&mdash;要么是端坐桌前、左手快捷键、右手鼠标；要么就是盯着巴掌大的手机屏幕，在层层折叠的菜单里寻找功能，小心翼翼地用手指拖拽那几毫米的轨道。\n但剪映刚上线的 AI 助手，正在试图打破这个刻板印象。\n想象一下，你靠在椅子上，不需要触碰', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-3334086455188051355', '半导体', '重构腾讯 AI 之后，姚顺雨交出入场后的第一份答卷', 'http://www.geekpark.net/news/363076', '极客公园', '2026-04-23', '&nbsp;\n极客一问：你看好接下来的混元大模型吗？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n&nbsp;\n姚顺雨交出了加入腾讯后的第一份模型答卷。\n4 月 23 日，腾讯混元 Hy3 preview 语言模型发布并开源。这是一款主打快慢思考融合的 MoE 语言模型，总参数 295B，激活参数 21B，最大支持 256K 上下文长度，官方称其整体性能达到同尺寸模型最佳水平。\n从研发节奏来', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:02:22', '2026-04-30 18:02:21', '2026-04-30 18:02:37', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-3415615547532963532', '人工智能', 'GPT-5.5 来了，但这次 OpenAI 想证明的不只是「更聪明」', 'http://www.geekpark.net/news/363131', '极客公园', '2026-04-24', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n如果几年前有人跟说，「你以后评测一个新 AI 模型，可能还没写完稿子，下一代就出来了」，你大概率会觉得是扯淡。\n但现在，这件事真的发生了。\nGPT-5.4 发布于六周前。今天，GPT-5.5 已经在 ChatGPT 上向付费用户推送。\n这不是一次普通的版本迭代。OpenAI 给它的定位是「全新的智能等级」&mdash;&mda', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:09', '2026-04-30 18:04:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-3447405175697747577', '人工智能', '汽车的「OpenClaw 时刻」，到了？', 'http://www.geekpark.net/news/363403', '极客公园', '2026-04-28', '汽车的「OpenClaw 时刻」，到了？摘要：更聪明的智能助手，和真正的「AI 控车」。极客一问：你觉得现在车上的「AI 助手」智能化程度如何？头图来源：极客公园作者｜靖宇走完 2026 北京车展的十几个展馆，我最大的感受是，车企的高管，肯定是用上「小龙虾」了——今年，如果你的新车没搭个大模型，你都不好意思开发布会。火山引擎带着豆包宣布搭载超 700 万辆车；腾讯发布出行全场景智能体开放平台；科大', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-3452139376977172670', '新材料', 'OPPO Find X9 Ultra 影像体验：方寸之间的哈苏与 10 倍「望远镜」', 'http://www.geekpark.net/news/363000', '极客公园', '2026-04-22', '\n\n\n「无论远近」里那个「远」字，今年被 OPPO 押到了极致。\n<strong class=\"js_darkmode__4\" style=\"text-indent: 0em; font-size: 16px; color: #375474; font-family: Optima-Regular, PingFa', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:02:30', '2026-04-30 18:02:29', '2026-04-30 18:02:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-3684506693709541646', '人工智能', '小红书：内容添加 AI 标识，反对 AI 造假；小米全新机器人亮相；微信 15 周年皮肤衣开卖，238 元 | 极客早知道', 'http://www.geekpark.net/news/363371', '极客公园', '2026-04-28', '\n小红书首次公布 AI 治理主张：坚决反对四类 AI 行为，给 AI 创作划出清晰边界\n4 月 27 日，小红书首次公布平台对 AI 内容的治理主张，并在北京举办首届 AI 治理开放日。此次 AI 治理主张共分为「平台鼓励的 AI 内容及行为」和「平台反对的 AI 内容及行为」两大板块，以给到创作者清晰指引。\n小红书明确了对待 AI 相关现象的核心态度：鼓励 AI 作为创意放大器，反对 AI 作为', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-385211228178747497', '人工智能', '一年烧掉 1850 亿美元、Google 要做智能体时代的「企业 Windows」', 'http://www.geekpark.net/news/363090', '极客公园', '2026-04-23', '4 月 22 号，拉斯维加斯，Google Cloud Next 2026 正在如火如荼地举行。\n\n了解 Google 每年产品发布节奏的人都知道，I/O 是讲手机、讲安卓、讲各种新产品如何改变人类世界。而 Next 的画风完全不同，它一上来就直奔企业客户，聚焦在云基础设施怎么搭，AI 怎么落到生产环境里去。\n而如果把过去四年的 Next 大会串在一起，你会看到 AI 时代 Google Clou', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-3959629199029507127', '人工智能', '比亚迪天神之眼 B 选装5月1日开始涨价；微信朋友圈悄然改版；麦当劳奶昔正式回归', 'http://www.geekpark.net/news/363496', '极客公园', '2026-04-29', '\n谷歌被曝与五角大楼签署机密 AI 协议，条款宽松程度超OpenAI\n当地时间 4 月 27 日，据知情人士透露，谷歌与美国国防部签署了一项机密 AI 协议，允许五角大楼将谷歌 AI 用于任何合法的政府目的。\n协议同时要求谷歌根据政府要求协助调整其 AI 安全设置与过滤器。媒体指出，该协议的条款宽松程度被认为超过 OpenAI 今年 2 月与五角大楼达成的协议。\n截', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:07:59', '2026-04-30 18:07:58', '2026-04-30 18:08:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-3967573986507510347', '人工智能', '阿里、美团、字节、小米罕见「会师」，四大厂为何共同押注自变量机器人', 'http://www.geekpark.net/news/363262', '极客公园', '2026-04-26', '\n\n\n当很多具身智能公司更关心机器人先在哪些场景里跑通商业化时，自变量更想寻找哪条路径能够通往 AGI。\n作者｜Li Yuan<strong style=\"text-indent: 0em; font-size: 16px; color: #3', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-4033008037131724902', '人工智能', '大模型上车两年，为什么「真·AI 汽车」现在才出现？', 'http://www.geekpark.net/news/363204', '极客公园', '2026-04-24', '今天在北京车展上爆火的极氪 8X，有网友放出了一段新车演示视频，用户坐在车里说了一句「带我去接孩子放学，顺便找一家麦当劳，5 点前我要到学校」。\n接下来发生的事情，和你过去对「智能汽车」的认知完全不同。车辆自主规划路线，启动智能驾驶，中途停靠麦当劳，到达学校门口自动泊车。整个过程，用户不需要碰导航、手动切换智驾模式、或者在停车场里找车位。\n这不是一个语音助手在帮你搜索，而是一个 Agent 在替你', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-4060061153534661973', '人工智能', 'OpenAI 硬件负责人的闭门分享，向我们揭示了为什么硬件「终点」仍是智能手机', 'http://www.geekpark.net/news/363596', '极客公园', '2026-04-29', '\n\n\n「你必须为模型将要去的方向设计硬件，而不是为今天的模型。」\n<section class=\"js_darkmode__3', '该事件值得关注。', 'other', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-4158706295332199150', '人工智能', '一个新视频模型背后，藏着蔡浩宇给游戏行业造的「新引擎」', 'http://www.geekpark.net/news/363077', '极客公园', '2026-04-23', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n4 月 9 日，一篇来自 Anuttacon 团队的论文悄悄出现在 arXiv 上。论文展示了一个叫 LPM 1.0 的视频模型&mdash;&mdash;全称 Large Performance Model，注意，是 Performance（表演），不是 Language（语言）。\n这个 170 亿参数的扩散 Transformer 模型，能让一个 ', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-4254353084332618121', '半导体', '重构腾讯 AI 之后，姚顺雨交出入场后的第一份答卷', 'http://www.geekpark.net/news/363076', '极客公园', '2026-04-23', '&nbsp;\n极客一问：你看好接下来的混元大模型吗？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n&nbsp;\n姚顺雨交出了加入腾讯后的第一份模型答卷。\n4 月 23 日，腾讯混元 Hy3 preview 语言模型发布并开源。这是一款主打快慢思考融合的 MoE 语言模型，总参数 295B，激活参数 21B，最大支持 256K 上下文长度，官方称其整体性能达到同尺寸模型最佳水平。\n从研发节奏来', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:49', '2026-04-30 18:00:49', '2026-04-30 18:01:05', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-4311570933020238994', '人工智能', '小红书：内容添加 AI 标识，反对 AI 造假；小米全新机器人亮相；微信 15 周年皮肤衣开卖，238 元 | 极客早知道', 'http://www.geekpark.net/news/363371', '极客公园', '2026-04-28', '\n小红书首次公布 AI 治理主张：坚决反对四类 AI 行为，给 AI 创作划出清晰边界\n4 月 27 日，小红书首次公布平台对 AI 内容的治理主张，并在北京举办首届 AI 治理开放日。此次 AI 治理主张共分为「平台鼓励的 AI 内容及行为」和「平台反对的 AI 内容及行为」两大板块，以给到创作者清晰指引。\n小红书明确了对待 AI 相关现象的核心态度：鼓励 AI 作为创意放大器，反对 AI 作为', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-4321489596134285315', '新材料', '马斯克 600 亿美元锁定 Cursor；字节、荣威合作推出「AI 汽车」；传今年存储厂商人均奖金超 300 万元', 'http://www.geekpark.net/news/362932', '极客公园', '2026-04-22', '\n600 亿美元！马斯克「锁定」Cursor\n美国时间 4 月 21 日，《纽约时报》发出了一条让科技圈炸锅的消息。\nCursor 授予 SpaceX 权利，允许其在今年晚些时候以 600 亿美元收购 Cursor，或就双方合作支付 100 亿美元。\n根据 SpaceX 在 X 上公布的消息，双方将在 GPU 算力上达成合作。xAI 旗下的 Colossus 超算系统拥有约 20 万张英伟达 GP', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:00:57', '2026-04-30 18:00:56', '2026-04-30 18:00:56', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-4342210881907765219', '新材料', 'Kimi K2.6 这次把 Agent 玩明白了吗？', 'http://www.geekpark.net/news/362947', '极客公园', '2026-04-22', '&nbsp;\n头图来源：Kimi官网\n&nbsp;\n&nbsp;\n当一个AI系统可以在无人工干预的情况下，独立完成一个复杂项目的完整交付，以及，当这些能力开始可以被复用、被沉淀为「技能」，AI在职场中的角色，是否已经发生了本质变化？\nOpenClaw这波热潮带动了大模型竞争进入深水区，赛道的分水岭，从「谁更强」，转向了「谁能真正交付生产力」。自主Agent的落地能力、工程化适配水平以及长时稳定运行', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:03:39', '2026-04-30 18:03:38', '2026-04-30 18:03:38', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-4441319675449593919', '人工智能', 'OpenAI 最强模型 GPT-5.5 上线；传特斯拉与 SpaceX 终将合并；票价 20 万！12306 惊现豪华专列', 'http://www.geekpark.net/news/363096', '极客公园', '2026-04-24', 'OpenAI 最智能 AI 模型：GPT-5.5 登场，Token 成本降至 1/35、输出提速 50 倍4 月 24 日，OpenAI 正式发布旗下迄今最智能的 AI 模型 GPT-5.5。该模型核心突破在于大幅升级的 Agent 智能体能力，能精准理解用户模糊指令，自主规划、调用工具并执行多步骤复杂任务，无需用户精细管控每一步流程，在 Agentic Coding、计算机使用、科研等领域表现卓', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-4479890169948220200', '人工智能', 'DeepSeek 正式发布 V4 API：Flash/Pro 双版本齐发，百万上下文成标配', 'http://www.geekpark.net/news/363222', '极客公园', '2026-04-24', '&nbsp;\n极客一问：你怎么看这次 DeepSeek V4 的更新？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n万众期待中，DeepSeek V4，终于发布了！\n&nbsp;\n就在刚刚，被期待已久的DeepSeek V4 预览版正式登场。两个版本&mdash;&mdash;V4-Pro 和 V4-Flash，全系标配 1M（百万字）超长上下文，同步开源模型权重和技术报告。\n&nbsp;\n', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
