INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-5332945341195011800', '元宇宙', '华为余承东：新 M9 友商永远追不上；谷歌曝光智能体专项 AI 芯片；兵乓机器人击败人类顶级选手｜极客早知道', 'http://www.geekpark.net/news/363008', '极客公园', '2026-04-23', '\n&nbsp;\n\n\n传腾讯与阿里巴巴洽谈投资 DeepSeek 估值或超 200 亿美元\n<p style=\"margin: ', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:08:06', '2026-04-30 18:08:05', '2026-04-30 18:08:27', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-5414090099799843294', '人工智能', '阿里、美团、字节、小米罕见「会师」，四大厂为何共同押注自变量机器人', 'http://www.geekpark.net/news/363262', '极客公园', '2026-04-26', '\n\n\n当很多具身智能公司更关心机器人先在哪些场景里跑通商业化时，自变量更想寻找哪条路径能够通往 AGI。\n作者｜Li Yuan<strong style=\"text-indent: 0em; font-size: 16px; color: #3', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-544971162373195297', '人工智能', '汽车的「OpenClaw 时刻」，到了？', 'http://www.geekpark.net/news/363403', '极客公园', '2026-04-28', '汽车的「OpenClaw 时刻」，到了？摘要：更聪明的智能助手，和真正的「AI 控车」。极客一问：你觉得现在车上的「AI 助手」智能化程度如何？头图来源：极客公园作者｜靖宇走完 2026 北京车展的十几个展馆，我最大的感受是，车企的高管，肯定是用上「小龙虾」了——今年，如果你的新车没搭个大模型，你都不好意思开发布会。火山引擎带着豆包宣布搭载超 700 万辆车；腾讯发布出行全场景智能体开放平台；科大', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-560805060784085278', '人工智能', 'AI 走出屏幕，家电变成「机器人」', 'http://www.geekpark.net/news/363602', '极客公园', '2026-04-30', 'AI 正在迈向下一个十年。\n当模型能力继续提升，AI 即将走出屏幕里「回答问题、生成代码」的任务，转向真实的物理世界。\n这也是为什么，AI 硬件会成为过去 1-2 年科技行业最热的关键词。相比手机、眼镜、人形机器人等更主流的硬件形态，家电是一个很容易被低估的的关键品类。\n因为家电面对的，是清洁、烹饪、洗衣、宠物、庭院这些最日常的生活任务。它们听起来没有人形机器人酷，但足够真实且高频。AI 要走进生', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-5723046863250964534', '人工智能', '豆包上线「帮你选」功能； 5999 元，泡泡玛特首推冰箱；高铁试点「坐火车带自行车」 | 极客早知道｜极客早知道', 'http://www.geekpark.net/news/363226', '极客公园', '2026-04-25', '\n英特尔股价周五暴涨 24% 创 1987 年以来最大单日涨幅\n4 月 25 日消息，英特尔股价周五飙升 24%，创下自 1987 年 10 月以来的最佳单日表现，投资者对因人工智能需求增长而带来的复苏迹象感到振奋。\n该股收于 82.57 美元，继 2025 年全年上涨 84% 之后，今年迄今已累计上涨 124%。上周五的涨势超过了该股在 9 月 18 日 23% 的涨幅&mdash;&mdash', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-5830682667398909234', '新材料', 'OPPO Find X9 Ultra 影像体验：方寸之间的哈苏与 10 倍「望远镜」', 'http://www.geekpark.net/news/363000', '极客公园', '2026-04-22', '\n\n\n「无论远近」里那个「远」字，今年被 OPPO 押到了极致。\n<strong class=\"js_darkmode__4\" style=\"text-indent: 0em; font-size: 16px; color: #375474; font-family: Optima-Regular, PingFa', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:00:57', '2026-04-30 18:00:56', '2026-04-30 18:00:56', 0.5);
