INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-5920714955270369352', '人工智能', '这张 4 万块的床垫，凭什么让马斯克、扎克伯格「疯狂上头」?', 'http://www.geekpark.net/news/363092', '极客公园', '2026-04-23', '4 月 18 日，深圳。 当 Eight Sleep 的智能床垫 Pod 5 系列首次在中国亮相时，现场最多听到的问题不是「它有什么功能」，而是「它凭什么卖这么贵」。\n一张 2M&times;2M 的 Pod 5 Ultra，售价 37999 元。这个价格足够买一台高配 MacBook Pro，或者三台 iPhone 16 Pro Max。更关键的是，它看起来并不奢侈，没有镶金边，没用什么稀有材质', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-592583902611603559', '人工智能', '汽车的「OpenClaw 时刻」，到了？', 'http://www.geekpark.net/news/363403', '极客公园', '2026-04-28', '汽车的「OpenClaw 时刻」，到了？摘要：更聪明的智能助手，和真正的「AI 控车」。极客一问：你觉得现在车上的「AI 助手」智能化程度如何？头图来源：极客公园作者｜靖宇走完 2026 北京车展的十几个展馆，我最大的感受是，车企的高管，肯定是用上「小龙虾」了——今年，如果你的新车没搭个大模型，你都不好意思开发布会。火山引擎带着豆包宣布搭载超 700 万辆车；腾讯发布出行全场景智能体开放平台；科大', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:07:59', '2026-04-30 18:07:58', '2026-04-30 18:08:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-6006204331004947601', '人工智能', '一个新视频模型背后，藏着蔡浩宇给游戏行业造的「新引擎」', 'http://www.geekpark.net/news/363077', '极客公园', '2026-04-23', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n4 月 9 日，一篇来自 Anuttacon 团队的论文悄悄出现在 arXiv 上。论文展示了一个叫 LPM 1.0 的视频模型&mdash;&mdash;全称 Large Performance Model，注意，是 Performance（表演），不是 Language（语言）。\n这个 170 亿参数的扩散 Transformer 模型，能让一个 ', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-6064222549046524734', '人工智能', '大模型上车两年，为什么「真·AI 汽车」现在才出现？', 'http://www.geekpark.net/news/363204', '极客公园', '2026-04-24', '今天在北京车展上爆火的极氪 8X，有网友放出了一段新车演示视频，用户坐在车里说了一句「带我去接孩子放学，顺便找一家麦当劳，5 点前我要到学校」。\n接下来发生的事情，和你过去对「智能汽车」的认知完全不同。车辆自主规划路线，启动智能驾驶，中途停靠麦当劳，到达学校门口自动泊车。整个过程，用户不需要碰导航、手动切换智驾模式、或者在停车场里找车位。\n这不是一个语音助手在帮你搜索，而是一个 Agent 在替你', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
