INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-6314379443612768908', '人工智能', 'DeepSeek 正式发布 V4 API：Flash/Pro 双版本齐发，百万上下文成标配', 'http://www.geekpark.net/news/363222', '极客公园', '2026-04-24', '&nbsp;\n极客一问：你怎么看这次 DeepSeek V4 的更新？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n万众期待中，DeepSeek V4，终于发布了！\n&nbsp;\n就在刚刚，被期待已久的DeepSeek V4 预览版正式登场。两个版本&mdash;&mdash;V4-Pro 和 V4-Flash，全系标配 1M（百万字）超长上下文，同步开源模型权重和技术报告。\n&nbsp;\n', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:55', 0.5);
