INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-656123659424178081', '人工智能', 'GPT-5.5 来了，但这次 OpenAI 想证明的不只是「更聪明」', 'http://www.geekpark.net/news/363131', '极客公园', '2026-04-24', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n如果几年前有人跟说，「你以后评测一个新 AI 模型，可能还没写完稿子，下一代就出来了」，你大概率会觉得是扯淡。\n但现在，这件事真的发生了。\nGPT-5.4 发布于六周前。今天，GPT-5.5 已经在 ChatGPT 上向付费用户推送。\n这不是一次普通的版本迭代。OpenAI 给它的定位是「全新的智能等级」&mdash;&mda', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:09', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-660214310050930819', '人工智能', '比亚迪天神之眼 B 选装5月1日开始涨价；微信朋友圈悄然改版；麦当劳奶昔正式回归', 'http://www.geekpark.net/news/363496', '极客公园', '2026-04-29', '\n谷歌被曝与五角大楼签署机密 AI 协议，条款宽松程度超OpenAI\n当地时间 4 月 27 日，据知情人士透露，谷歌与美国国防部签署了一项机密 AI 协议，允许五角大楼将谷歌 AI 用于任何合法的政府目的。\n协议同时要求谷歌根据政府要求协助调整其 AI 安全设置与过滤器。媒体指出，该协议的条款宽松程度被认为超过 OpenAI 今年 2 月与五角大楼达成的协议。\n截', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:15', 0.5);
