INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-6716557267505623028', '人工智能', '没有「身份证」的 Agent，接管不了世界', 'http://www.geekpark.net/news/363091', '极客公园', '2026-04-23', '焦虑与兴奋，是当下科技圈最真实的画像。大年初一蹲在家里装「小龙虾」的老板们，和深夜里顶着 Bug 调教 Agent 的独立开发者，被同一股力量推着往前走。他们既害怕错过，也害怕被反噬。\n但热潮之下，暗流也在涌动。前段时间工信部发出提醒 OpenClaw 这类新形态 Agent 中，恶意代码植入的风险正在浮现。\n当 Agent 从极客玩具变成人人标配的入口，它的安全和可信，谁来保证？\n这正是我们今天', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-6778585163400477221', '人工智能', '当剪辑工具开始「听懂人话」：剪映做了视频创作的Skill化Agent', 'http://www.geekpark.net/news/363407', '极客公园', '2026-04-28', '&nbsp;\n如果有人告诉你，视频剪辑可以像「刷手机」一样轻松，你大概率会在脑海里冒个问号。\n毕竟在我们的习惯里，剪辑往往意味着「高强度的手眼协同」&mdash;&mdash;要么是端坐桌前、左手快捷键、右手鼠标；要么就是盯着巴掌大的手机屏幕，在层层折叠的菜单里寻找功能，小心翼翼地用手指拖拽那几毫米的轨道。\n但剪映刚上线的 AI 助手，正在试图打破这个刻板印象。\n想象一下，你靠在椅子上，不需要触碰', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-6855000584712237725', '新材料', '马斯克 600 亿美元锁定 Cursor；字节、荣威合作推出「AI 汽车」；传今年存储厂商人均奖金超 300 万元', 'http://www.geekpark.net/news/362932', '极客公园', '2026-04-22', '\n600 亿美元！马斯克「锁定」Cursor\n美国时间 4 月 21 日，《纽约时报》发出了一条让科技圈炸锅的消息。\nCursor 授予 SpaceX 权利，允许其在今年晚些时候以 600 亿美元收购 Cursor，或就双方合作支付 100 亿美元。\n根据 SpaceX 在 X 上公布的消息，双方将在 GPU 算力上达成合作。xAI 旗下的 Colossus 超算系统拥有约 20 万张英伟达 GP', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:09:30', '2026-04-30 18:09:30', '2026-04-30 18:09:30', 0.5);
