INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-7694426810125221167', '人工智能', '阿里、美团、字节、小米罕见「会师」，四大厂为何共同押注自变量机器人', 'http://www.geekpark.net/news/363262', '极客公园', '2026-04-26', '\n\n\n当很多具身智能公司更关心机器人先在哪些场景里跑通商业化时，自变量更想寻找哪条路径能够通往 AGI。\n作者｜Li Yuan<strong style=\"text-indent: 0em; font-size: 16px; color: #3', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-782437613357654001', '人工智能', 'GPT-5.5 来了，但这次 OpenAI 想证明的不只是「更聪明」', 'http://www.geekpark.net/news/363131', '极客公园', '2026-04-24', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n如果几年前有人跟说，「你以后评测一个新 AI 模型，可能还没写完稿子，下一代就出来了」，你大概率会觉得是扯淡。\n但现在，这件事真的发生了。\nGPT-5.4 发布于六周前。今天，GPT-5.5 已经在 ChatGPT 上向付费用户推送。\n这不是一次普通的版本迭代。OpenAI 给它的定位是「全新的智能等级」&mdash;&mda', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:05:00', 0.5);
