INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-8129003234806667710', '人工智能', '当剪辑工具开始「听懂人话」：剪映做了视频创作的Skill化Agent', 'http://www.geekpark.net/news/363407', '极客公园', '2026-04-28', '&nbsp;\n如果有人告诉你，视频剪辑可以像「刷手机」一样轻松，你大概率会在脑海里冒个问号。\n毕竟在我们的习惯里，剪辑往往意味着「高强度的手眼协同」&mdash;&mdash;要么是端坐桌前、左手快捷键、右手鼠标；要么就是盯着巴掌大的手机屏幕，在层层折叠的菜单里寻找功能，小心翼翼地用手指拖拽那几毫米的轨道。\n但剪映刚上线的 AI 助手，正在试图打破这个刻板印象。\n想象一下，你靠在椅子上，不需要触碰', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-8260424917630109259', '人工智能', '一年烧掉 1850 亿美元、Google 要做智能体时代的「企业 Windows」', 'http://www.geekpark.net/news/363090', '极客公园', '2026-04-23', '4 月 22 号，拉斯维加斯，Google Cloud Next 2026 正在如火如荼地举行。\n\n了解 Google 每年产品发布节奏的人都知道，I/O 是讲手机、讲安卓、讲各种新产品如何改变人类世界。而 Next 的画风完全不同，它一上来就直奔企业客户，聚焦在云基础设施怎么搭，AI 怎么落到生产环境里去。\n而如果把过去四年的 Next 大会串在一起，你会看到 AI 时代 Google Clou', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:07:59', '2026-04-30 18:07:58', '2026-04-30 18:08:42', 0.5);
