INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-8436867746688217696', '人工智能', 'AI 走出屏幕，家电变成「机器人」', 'http://www.geekpark.net/news/363602', '极客公园', '2026-04-30', 'AI 正在迈向下一个十年。\n当模型能力继续提升，AI 即将走出屏幕里「回答问题、生成代码」的任务，转向真实的物理世界。\n这也是为什么，AI 硬件会成为过去 1-2 年科技行业最热的关键词。相比手机、眼镜、人形机器人等更主流的硬件形态，家电是一个很容易被低估的的关键品类。\n因为家电面对的，是清洁、烹饪、洗衣、宠物、庭院这些最日常的生活任务。它们听起来没有人形机器人酷，但足够真实且高频。AI 要走进生', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-8533477689494192537', '人工智能', '没有「身份证」的 Agent，接管不了世界', 'http://www.geekpark.net/news/363091', '极客公园', '2026-04-23', '焦虑与兴奋，是当下科技圈最真实的画像。大年初一蹲在家里装「小龙虾」的老板们，和深夜里顶着 Bug 调教 Agent 的独立开发者，被同一股力量推着往前走。他们既害怕错过，也害怕被反噬。\n但热潮之下，暗流也在涌动。前段时间工信部发出提醒 OpenClaw 这类新形态 Agent 中，恶意代码植入的风险正在浮现。\n当 Agent 从极客玩具变成人人标配的入口，它的安全和可信，谁来保证？\n这正是我们今天', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-8541005703396803988', '新材料', '马斯克 600 亿美元锁定 Cursor；字节、荣威合作推出「AI 汽车」；传今年存储厂商人均奖金超 300 万元', 'http://www.geekpark.net/news/362932', '极客公园', '2026-04-22', '\n600 亿美元！马斯克「锁定」Cursor\n美国时间 4 月 21 日，《纽约时报》发出了一条让科技圈炸锅的消息。\nCursor 授予 SpaceX 权利，允许其在今年晚些时候以 600 亿美元收购 Cursor，或就双方合作支付 100 亿美元。\n根据 SpaceX 在 X 上公布的消息，双方将在 GPU 算力上达成合作。xAI 旗下的 Colossus 超算系统拥有约 20 万张英伟达 GP', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:02:30', '2026-04-30 18:02:29', '2026-04-30 18:02:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-860304944122074088', '半导体', '居然有手机厂商坚持今年旗舰提质不提价', 'http://www.geekpark.net/news/363057', '极客公园', '2026-04-23', '2026 年智能手机行业开场即迎来涨价潮。在 AI 算力需求拉动下，存储芯片价格大涨并传导至消费电子终端。Counterpoint 预测，3 月后中国市场新机均价将较去年同档机型上涨约 15%&mdash;25%。\n现实正在快速应验这一预测，三星、荣耀、vivo、小米等品牌新一代旗舰涨价幅度在 1000 至 1600 元不等，成为行业应对成本的普遍策略。\n\n在此背景下，4 月 21 日发布的 OP', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:00:49', '2026-04-30 18:00:49', '2026-04-30 18:00:49', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-861213985172243179', '元宇宙', '华为余承东：新 M9 友商永远追不上；谷歌曝光智能体专项 AI 芯片；兵乓机器人击败人类顶级选手｜极客早知道', 'http://www.geekpark.net/news/363008', '极客公园', '2026-04-23', '\n&nbsp;\n\n\n传腾讯与阿里巴巴洽谈投资 DeepSeek 估值或超 200 亿美元\n<p style=\"margin: ', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:06:24', '2026-04-30 18:06:24', '2026-04-30 18:06:46', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-8665682823222574727', '新材料', '马斯克 600 亿美元锁定 Cursor；字节、荣威合作推出「AI 汽车」；传今年存储厂商人均奖金超 300 万元', 'http://www.geekpark.net/news/362932', '极客公园', '2026-04-22', '\n600 亿美元！马斯克「锁定」Cursor\n美国时间 4 月 21 日，《纽约时报》发出了一条让科技圈炸锅的消息。\nCursor 授予 SpaceX 权利，允许其在今年晚些时候以 600 亿美元收购 Cursor，或就双方合作支付 100 亿美元。\n根据 SpaceX 在 X 上公布的消息，双方将在 GPU 算力上达成合作。xAI 旗下的 Colossus 超算系统拥有约 20 万张英伟达 GP', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:03:39', '2026-04-30 18:03:38', '2026-04-30 18:03:38', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-8741922293034863020', '新材料', '大模型已成「黑洞」，而逃逸速度是「光速」', 'http://www.geekpark.net/news/363001', '极客公园', '2026-04-22', '昨晚和创新工场的汪华、Meshy 的胡渊鸣直播聊完「大模型奇点已至」，脑子里一直盘旋着一个宏大的景象：\nAI 大模型是一个正在形成的黑洞。\n而我们今天所有的创业者、所有的 Builder，都在这股引力的作用下，置身于黑洞周边的「吸积盘」上，以前所未有的速度高速旋转。在这个过程中，我们确实获得了巨大的能量，发出了极其绚烂的光芒&mdash;&mdash;创造出更好的产品、交付前所未有的价值，这是我们', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:09:30', '2026-04-30 18:09:29', '2026-04-30 18:09:54', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-8744177720860649783', '人工智能', '一个新视频模型背后，藏着蔡浩宇给游戏行业造的「新引擎」', 'http://www.geekpark.net/news/363077', '极客公园', '2026-04-23', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n4 月 9 日，一篇来自 Anuttacon 团队的论文悄悄出现在 arXiv 上。论文展示了一个叫 LPM 1.0 的视频模型&mdash;&mdash;全称 Large Performance Model，注意，是 Performance（表演），不是 Language（语言）。\n这个 170 亿参数的扩散 Transformer 模型，能让一个 ', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:54', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-8826383170848307453', '半导体', '重构腾讯 AI 之后，姚顺雨交出入场后的第一份答卷', 'http://www.geekpark.net/news/363076', '极客公园', '2026-04-23', '&nbsp;\n极客一问：你看好接下来的混元大模型吗？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n&nbsp;\n姚顺雨交出了加入腾讯后的第一份模型答卷。\n4 月 23 日，腾讯混元 Hy3 preview 语言模型发布并开源。这是一款主打快慢思考融合的 MoE 语言模型，总参数 295B，激活参数 21B，最大支持 256K 上下文长度，官方称其整体性能达到同尺寸模型最佳水平。\n从研发节奏来', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:03:32', '2026-04-30 18:03:31', '2026-04-30 18:03:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-9055881987335615422', '新材料', 'Kimi K2.6 这次把 Agent 玩明白了吗？', 'http://www.geekpark.net/news/362947', '极客公园', '2026-04-22', '&nbsp;\n头图来源：Kimi官网\n&nbsp;\n&nbsp;\n当一个AI系统可以在无人工干预的情况下，独立完成一个复杂项目的完整交付，以及，当这些能力开始可以被复用、被沉淀为「技能」，AI在职场中的角色，是否已经发生了本质变化？\nOpenClaw这波热潮带动了大模型竞争进入深水区，赛道的分水岭，从「谁更强」，转向了「谁能真正交付生产力」。自主Agent的落地能力、工程化适配水平以及长时稳定运行', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:08:27', '2026-04-30 18:08:27', '2026-04-30 18:08:27', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-9169526341613108660', '人工智能', '当剪辑工具开始「听懂人话」：剪映做了视频创作的Skill化Agent', 'http://www.geekpark.net/news/363407', '极客公园', '2026-04-28', '&nbsp;\n如果有人告诉你，视频剪辑可以像「刷手机」一样轻松，你大概率会在脑海里冒个问号。\n毕竟在我们的习惯里，剪辑往往意味着「高强度的手眼协同」&mdash;&mdash;要么是端坐桌前、左手快捷键、右手鼠标；要么就是盯着巴掌大的手机屏幕，在层层折叠的菜单里寻找功能，小心翼翼地用手指拖拽那几毫米的轨道。\n但剪映刚上线的 AI 助手，正在试图打破这个刻板印象。\n想象一下，你靠在椅子上，不需要触碰', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-9211856283282711516', '人工智能', '豆包上线「帮你选」功能； 5999 元，泡泡玛特首推冰箱；高铁试点「坐火车带自行车」 | 极客早知道｜极客早知道', 'http://www.geekpark.net/news/363226', '极客公园', '2026-04-25', '\n英特尔股价周五暴涨 24% 创 1987 年以来最大单日涨幅\n4 月 25 日消息，英特尔股价周五飙升 24%，创下自 1987 年 10 月以来的最佳单日表现，投资者对因人工智能需求增长而带来的复苏迹象感到振奋。\n该股收于 82.57 美元，继 2025 年全年上涨 84% 之后，今年迄今已累计上涨 124%。上周五的涨势超过了该股在 9 月 18 日 23% 的涨幅&mdash;&mdash', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:07:59', '2026-04-30 18:07:58', '2026-04-30 18:08:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_-9218014279489934424', '人工智能', '马斯克：OpenAI 是我的创意，Altman 是小偷；Claude Code 使用成本翻倍；Image 2 登顶视觉模型榜｜极客早知道', 'http://www.geekpark.net/news/363594', '极客公园', '2026-04-30', '\n结束与微软独家合作，OpenAI 模型接入亚马逊 AWS\n4 月 29 日，在亚马逊云科技（Amazon Web Services，简称 AWS）新品发布会上，AWS 宣布携手 OpenAI，将 OpenAI 最新大模型接入 Amazon Bedrock，在 Amazon Bedrock 上线 Codex 代码 Agent，并推出由 OpenAI 赋能的 Amazon Bedrock 托管 Ag', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:55', 0.5);
