INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_1311816168238836631', '新材料', 'Kimi K2.6 这次把 Agent 玩明白了吗？', 'http://www.geekpark.net/news/362947', '极客公园', '2026-04-22', '&nbsp;\n头图来源：Kimi官网\n&nbsp;\n&nbsp;\n当一个AI系统可以在无人工干预的情况下，独立完成一个复杂项目的完整交付，以及，当这些能力开始可以被复用、被沉淀为「技能」，AI在职场中的角色，是否已经发生了本质变化？\nOpenClaw这波热潮带动了大模型竞争进入深水区，赛道的分水岭，从「谁更强」，转向了「谁能真正交付生产力」。自主Agent的落地能力、工程化适配水平以及长时稳定运行', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 17:17:35', '2026-04-30 17:17:34', '2026-04-30 17:17:34', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_1383372347378247010', '人工智能', '这张 4 万块的床垫，凭什么让马斯克、扎克伯格「疯狂上头」?', 'http://www.geekpark.net/news/363092', '极客公园', '2026-04-23', '4 月 18 日，深圳。 当 Eight Sleep 的智能床垫 Pod 5 系列首次在中国亮相时，现场最多听到的问题不是「它有什么功能」，而是「它凭什么卖这么贵」。\n一张 2M&times;2M 的 Pod 5 Ultra，售价 37999 元。这个价格足够买一台高配 MacBook Pro，或者三台 iPhone 16 Pro Max。更关键的是，它看起来并不奢侈，没有镶金边，没用什么稀有材质', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:09', '2026-04-30 18:03:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_1402548423053410232', '人工智能', '豆包上线「帮你选」功能； 5999 元，泡泡玛特首推冰箱；高铁试点「坐火车带自行车」 | 极客早知道｜极客早知道', 'http://www.geekpark.net/news/363226', '极客公园', '2026-04-25', '\n英特尔股价周五暴涨 24% 创 1987 年以来最大单日涨幅\n4 月 25 日消息，英特尔股价周五飙升 24%，创下自 1987 年 10 月以来的最佳单日表现，投资者对因人工智能需求增长而带来的复苏迹象感到振奋。\n该股收于 82.57 美元，继 2025 年全年上涨 84% 之后，今年迄今已累计上涨 124%。上周五的涨势超过了该股在 9 月 18 日 23% 的涨幅&mdash;&mdash', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_1561386809664354541', '元宇宙', '华为余承东：新 M9 友商永远追不上；谷歌曝光智能体专项 AI 芯片；兵乓机器人击败人类顶级选手｜极客早知道', 'http://www.geekpark.net/news/363008', '极客公园', '2026-04-23', '\n&nbsp;\n\n\n传腾讯与阿里巴巴洽谈投资 DeepSeek 估值或超 200 亿美元\n<p style=\"margin: ', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:03:16', '2026-04-30 18:03:16', '2026-04-30 18:03:38', 0.5);
