INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_1726437305622175855', '人工智能', 'MiniMax 登上戛纳，AI 与艺术的全球和解开始了？', 'http://www.geekpark.net/news/363324', '极客公园', '2026-04-27', '作者｜Cynthia \n编辑｜ 郑玄\n&nbsp;\n2026 年的春天，影视圈的风向开始变了。\n4 月 21 日，全球首个，也是迄今为止规模最大的 AI 电影节 WAIFF（2026），在法国戛纳电影宫正式举办。蔚蓝海岸线前，一众影视行业的从业者鱼贯而入，但一改往日红毯众星云集的流光溢彩，这一次的电影节，地毯换成了象征科技的紫色，而走上这条「紫毯」的，也换成了一众 AI 内容的创作者。\n<p st', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:05', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_1744372627765711311', '人工智能', 'OpenAI 最强模型 GPT-5.5 上线；传特斯拉与 SpaceX 终将合并；票价 20 万！12306 惊现豪华专列', 'http://www.geekpark.net/news/363096', '极客公园', '2026-04-24', 'OpenAI 最智能 AI 模型：GPT-5.5 登场，Token 成本降至 1/35、输出提速 50 倍4 月 24 日，OpenAI 正式发布旗下迄今最智能的 AI 模型 GPT-5.5。该模型核心突破在于大幅升级的 Agent 智能体能力，能精准理解用户模糊指令，自主规划、调用工具并执行多步骤复杂任务，无需用户精细管控每一步流程，在 Agentic Coding、计算机使用、科研等领域表现卓', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_1934762706092837943', '元宇宙', '华为余承东：新 M9 友商永远追不上；谷歌曝光智能体专项 AI 芯片；兵乓机器人击败人类顶级选手｜极客早知道', 'http://www.geekpark.net/news/363008', '极客公园', '2026-04-23', '\n&nbsp;\n\n\n传腾讯与阿里巴巴洽谈投资 DeepSeek 估值或超 200 亿美元\n<p style=\"margin: ', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 17:17:13', '2026-04-30 17:17:12', '2026-04-30 17:17:34', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_1971564348217715806', '人工智能', 'GPT-5.5 来了，但这次 OpenAI 想证明的不只是「更聪明」', 'http://www.geekpark.net/news/363131', '极客公园', '2026-04-24', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n如果几年前有人跟说，「你以后评测一个新 AI 模型，可能还没写完稿子，下一代就出来了」，你大概率会觉得是扯淡。\n但现在，这件事真的发生了。\nGPT-5.4 发布于六周前。今天，GPT-5.5 已经在 ChatGPT 上向付费用户推送。\n这不是一次普通的版本迭代。OpenAI 给它的定位是「全新的智能等级」&mdash;&mda', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:22', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_20138442980175982', '人工智能', 'OpenAI 硬件负责人的闭门分享，向我们揭示了为什么硬件「终点」仍是智能手机', 'http://www.geekpark.net/news/363596', '极客公园', '2026-04-29', '\n\n\n「你必须为模型将要去的方向设计硬件，而不是为今天的模型。」\n<section class=\"js_darkmode__3', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_2016847734858709368', '人工智能', 'HappyHorse 1.0在千问首发开启灰测免费体验，重构 AI 视频赛道', 'http://www.geekpark.net/news/363406', '极客公园', '2026-04-29', '&nbsp;\n前段时间，AI 视频生成赛道迎来了一场无预热的行业震动。\n一款名为 HappyHorse 1.0 的模型以匿名形式空降权威第三方评测平台 Artificial Analysis 的 Video Arena 榜单，一度拿下第一。\n从全网对研发主体的密集猜测，到阿里巴巴 ATH 事业群正式官宣认领，这款被业内称为 「HappyHorse 1.0 」 的模型，迅速成为全球 AI 视频圈的核', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
