INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_2333328703354251715', '人工智能', '比亚迪天神之眼 B 选装5月1日开始涨价；微信朋友圈悄然改版；麦当劳奶昔正式回归', 'http://www.geekpark.net/news/363496', '极客公园', '2026-04-29', '\n谷歌被曝与五角大楼签署机密 AI 协议，条款宽松程度超OpenAI\n当地时间 4 月 27 日，据知情人士透露，谷歌与美国国防部签署了一项机密 AI 协议，允许五角大楼将谷歌 AI 用于任何合法的政府目的。\n协议同时要求谷歌根据政府要求协助调整其 AI 安全设置与过滤器。媒体指出，该协议的条款宽松程度被认为超过 OpenAI 今年 2 月与五角大楼达成的协议。\n截', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_2348747177343508873', '新材料', '大模型已成「黑洞」，而逃逸速度是「光速」', 'http://www.geekpark.net/news/363001', '极客公园', '2026-04-22', '昨晚和创新工场的汪华、Meshy 的胡渊鸣直播聊完「大模型奇点已至」，脑子里一直盘旋着一个宏大的景象：\nAI 大模型是一个正在形成的黑洞。\n而我们今天所有的创业者、所有的 Builder，都在这股引力的作用下，置身于黑洞周边的「吸积盘」上，以前所未有的速度高速旋转。在这个过程中，我们确实获得了巨大的能量，发出了极其绚烂的光芒&mdash;&mdash;创造出更好的产品、交付前所未有的价值，这是我们', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:57', '2026-04-30 18:00:56', '2026-04-30 18:01:22', 0.5);
