INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_2822659797160323232', '人工智能', 'AI 走出屏幕，家电变成「机器人」', 'http://www.geekpark.net/news/363602', '极客公园', '2026-04-30', 'AI 正在迈向下一个十年。\n当模型能力继续提升，AI 即将走出屏幕里「回答问题、生成代码」的任务，转向真实的物理世界。\n这也是为什么，AI 硬件会成为过去 1-2 年科技行业最热的关键词。相比手机、眼镜、人形机器人等更主流的硬件形态，家电是一个很容易被低估的的关键品类。\n因为家电面对的，是清洁、烹饪、洗衣、宠物、庭院这些最日常的生活任务。它们听起来没有人形机器人酷，但足够真实且高频。AI 要走进生', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:07:59', '2026-04-30 18:07:58', '2026-04-30 18:08:42', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_2822765072204297847', '人工智能', 'OpenAI 最强模型 GPT-5.5 上线；传特斯拉与 SpaceX 终将合并；票价 20 万！12306 惊现豪华专列', 'http://www.geekpark.net/news/363096', '极客公园', '2026-04-24', 'OpenAI 最智能 AI 模型：GPT-5.5 登场，Token 成本降至 1/35、输出提速 50 倍4 月 24 日，OpenAI 正式发布旗下迄今最智能的 AI 模型 GPT-5.5。该模型核心突破在于大幅升级的 Agent 智能体能力，能精准理解用户模糊指令，自主规划、调用工具并执行多步骤复杂任务，无需用户精细管控每一步流程，在 Agentic Coding、计算机使用、科研等领域表现卓', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:07:59', '2026-04-30 18:07:58', '2026-04-30 18:08:42', 0.5);
