INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_3016714480584665752', '人工智能', '比亚迪天神之眼 B 选装5月1日开始涨价；微信朋友圈悄然改版；麦当劳奶昔正式回归', 'http://www.geekpark.net/news/363496', '极客公园', '2026-04-29', '\n谷歌被曝与五角大楼签署机密 AI 协议，条款宽松程度超OpenAI\n当地时间 4 月 27 日，据知情人士透露，谷歌与美国国防部签署了一项机密 AI 协议，允许五角大楼将谷歌 AI 用于任何合法的政府目的。\n协议同时要求谷歌根据政府要求协助调整其 AI 安全设置与过滤器。媒体指出，该协议的条款宽松程度被认为超过 OpenAI 今年 2 月与五角大楼达成的协议。\n截', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:55', 0.5);
