INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_3409309128338019479', '人工智能', '一年烧掉 1850 亿美元、Google 要做智能体时代的「企业 Windows」', 'http://www.geekpark.net/news/363090', '极客公园', '2026-04-23', '4 月 22 号，拉斯维加斯，Google Cloud Next 2026 正在如火如荼地举行。\n\n了解 Google 每年产品发布节奏的人都知道，I/O 是讲手机、讲安卓、讲各种新产品如何改变人类世界。而 Next 的画风完全不同，它一上来就直奔企业客户，聚焦在云基础设施怎么搭，AI 怎么落到生产环境里去。\n而如果把过去四年的 Next 大会串在一起，你会看到 AI 时代 Google Clou', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_3439399453523245096', '人工智能', 'MiniMax 登上戛纳，AI 与艺术的全球和解开始了？', 'http://www.geekpark.net/news/363324', '极客公园', '2026-04-27', '作者｜Cynthia \n编辑｜ 郑玄\n&nbsp;\n2026 年的春天，影视圈的风向开始变了。\n4 月 21 日，全球首个，也是迄今为止规模最大的 AI 电影节 WAIFF（2026），在法国戛纳电影宫正式举办。蔚蓝海岸线前，一众影视行业的从业者鱼贯而入，但一改往日红毯众星云集的流光溢彩，这一次的电影节，地毯换成了象征科技的紫色，而走上这条「紫毯」的，也换成了一众 AI 内容的创作者。\n<p st', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_3572279551884873608', '半导体', '居然有手机厂商坚持今年旗舰提质不提价', 'http://www.geekpark.net/news/363057', '极客公园', '2026-04-23', '2026 年智能手机行业开场即迎来涨价潮。在 AI 算力需求拉动下，存储芯片价格大涨并传导至消费电子终端。Counterpoint 预测，3 月后中国市场新机均价将较去年同档机型上涨约 15%&mdash;25%。\n现实正在快速应验这一预测，三星、荣耀、vivo、小米等品牌新一代旗舰涨价幅度在 1000 至 1600 元不等，成为行业应对成本的普遍策略。\n\n在此背景下，4 月 21 日发布的 OP', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:09:21', '2026-04-30 18:09:21', '2026-04-30 18:09:21', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_3820197430024715605', '半导体', '重构腾讯 AI 之后，姚顺雨交出入场后的第一份答卷', 'http://www.geekpark.net/news/363076', '极客公园', '2026-04-23', '&nbsp;\n极客一问：你看好接下来的混元大模型吗？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n&nbsp;\n姚顺雨交出了加入腾讯后的第一份模型答卷。\n4 月 23 日，腾讯混元 Hy3 preview 语言模型发布并开源。这是一款主打快慢思考融合的 MoE 语言模型，总参数 295B，激活参数 21B，最大支持 256K 上下文长度，官方称其整体性能达到同尺寸模型最佳水平。\n从研发节奏来', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:09:21', '2026-04-30 18:09:21', '2026-04-30 18:09:38', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_3837133678187097268', '人工智能', '这张 4 万块的床垫，凭什么让马斯克、扎克伯格「疯狂上头」?', 'http://www.geekpark.net/news/363092', '极客公园', '2026-04-23', '4 月 18 日，深圳。 当 Eight Sleep 的智能床垫 Pod 5 系列首次在中国亮相时，现场最多听到的问题不是「它有什么功能」，而是「它凭什么卖这么贵」。\n一张 2M&times;2M 的 Pod 5 Ultra，售价 37999 元。这个价格足够买一台高配 MacBook Pro，或者三台 iPhone 16 Pro Max。更关键的是，它看起来并不奢侈，没有镶金边，没用什么稀有材质', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4014243451068536529', '人工智能', '一年烧掉 1850 亿美元、Google 要做智能体时代的「企业 Windows」', 'http://www.geekpark.net/news/363090', '极客公园', '2026-04-23', '4 月 22 号，拉斯维加斯，Google Cloud Next 2026 正在如火如荼地举行。\n\n了解 Google 每年产品发布节奏的人都知道，I/O 是讲手机、讲安卓、讲各种新产品如何改变人类世界。而 Next 的画风完全不同，它一上来就直奔企业客户，聚焦在云基础设施怎么搭，AI 怎么落到生产环境里去。\n而如果把过去四年的 Next 大会串在一起，你会看到 AI 时代 Google Clou', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:09', '2026-04-30 18:03:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4059104893113792565', '人工智能', 'AI 走出屏幕，家电变成「机器人」', 'http://www.geekpark.net/news/363602', '极客公园', '2026-04-30', 'AI 正在迈向下一个十年。\n当模型能力继续提升，AI 即将走出屏幕里「回答问题、生成代码」的任务，转向真实的物理世界。\n这也是为什么，AI 硬件会成为过去 1-2 年科技行业最热的关键词。相比手机、眼镜、人形机器人等更主流的硬件形态，家电是一个很容易被低估的的关键品类。\n因为家电面对的，是清洁、烹饪、洗衣、宠物、庭院这些最日常的生活任务。它们听起来没有人形机器人酷，但足够真实且高频。AI 要走进生', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4065527107575160401', '半导体', '居然有手机厂商坚持今年旗舰提质不提价', 'http://www.geekpark.net/news/363057', '极客公园', '2026-04-23', '2026 年智能手机行业开场即迎来涨价潮。在 AI 算力需求拉动下，存储芯片价格大涨并传导至消费电子终端。Counterpoint 预测，3 月后中国市场新机均价将较去年同档机型上涨约 15%&mdash;25%。\n现实正在快速应验这一预测，三星、荣耀、vivo、小米等品牌新一代旗舰涨价幅度在 1000 至 1600 元不等，成为行业应对成本的普遍策略。\n\n在此背景下，4 月 21 日发布的 OP', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:02:22', '2026-04-30 18:02:21', '2026-04-30 18:02:21', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4186951710903219038', '人工智能', 'OpenAI 硬件负责人的闭门分享，向我们揭示了为什么硬件「终点」仍是智能手机', 'http://www.geekpark.net/news/363596', '极客公园', '2026-04-29', '\n\n\n「你必须为模型将要去的方向设计硬件，而不是为今天的模型。」\n<section class=\"js_darkmode__3', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
