INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4604953402172347790', '人工智能', '一年烧掉 1850 亿美元、Google 要做智能体时代的「企业 Windows」', 'http://www.geekpark.net/news/363090', '极客公园', '2026-04-23', '4 月 22 号，拉斯维加斯，Google Cloud Next 2026 正在如火如荼地举行。\n\n了解 Google 每年产品发布节奏的人都知道，I/O 是讲手机、讲安卓、讲各种新产品如何改变人类世界。而 Next 的画风完全不同，它一上来就直奔企业客户，聚焦在云基础设施怎么搭，AI 怎么落到生产环境里去。\n而如果把过去四年的 Next 大会串在一起，你会看到 AI 时代 Google Clou', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4629541196434475863', '人工智能', '汽车的「OpenClaw 时刻」，到了？', 'http://www.geekpark.net/news/363403', '极客公园', '2026-04-28', '汽车的「OpenClaw 时刻」，到了？摘要：更聪明的智能助手，和真正的「AI 控车」。极客一问：你觉得现在车上的「AI 助手」智能化程度如何？头图来源：极客公园作者｜靖宇走完 2026 北京车展的十几个展馆，我最大的感受是，车企的高管，肯定是用上「小龙虾」了——今年，如果你的新车没搭个大模型，你都不好意思开发布会。火山引擎带着豆包宣布搭载超 700 万辆车；腾讯发布出行全场景智能体开放平台；科大', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4674255372400220627', '人工智能', '没有「身份证」的 Agent，接管不了世界', 'http://www.geekpark.net/news/363091', '极客公园', '2026-04-23', '焦虑与兴奋，是当下科技圈最真实的画像。大年初一蹲在家里装「小龙虾」的老板们，和深夜里顶着 Bug 调教 Agent 的独立开发者，被同一股力量推着往前走。他们既害怕错过，也害怕被反噬。\n但热潮之下，暗流也在涌动。前段时间工信部发出提醒 OpenClaw 这类新形态 Agent 中，恶意代码植入的风险正在浮现。\n当 Agent 从极客玩具变成人人标配的入口，它的安全和可信，谁来保证？\n这正是我们今天', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_474531518919358914', '人工智能', 'HappyHorse 1.0在千问首发开启灰测免费体验，重构 AI 视频赛道', 'http://www.geekpark.net/news/363406', '极客公园', '2026-04-29', '&nbsp;\n前段时间，AI 视频生成赛道迎来了一场无预热的行业震动。\n一款名为 HappyHorse 1.0 的模型以匿名形式空降权威第三方评测平台 Artificial Analysis 的 Video Arena 榜单，一度拿下第一。\n从全网对研发主体的密集猜测，到阿里巴巴 ATH 事业群正式官宣认领，这款被业内称为 「HappyHorse 1.0 」 的模型，迅速成为全球 AI 视频圈的核', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4760684465044427459', '半导体', '重构腾讯 AI 之后，姚顺雨交出入场后的第一份答卷', 'http://www.geekpark.net/news/363076', '极客公园', '2026-04-23', '&nbsp;\n极客一问：你看好接下来的混元大模型吗？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n&nbsp;\n姚顺雨交出了加入腾讯后的第一份模型答卷。\n4 月 23 日，腾讯混元 Hy3 preview 语言模型发布并开源。这是一款主打快慢思考融合的 MoE 语言模型，总参数 295B，激活参数 21B，最大支持 256K 上下文长度，官方称其整体性能达到同尺寸模型最佳水平。\n从研发节奏来', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 17:17:27', '2026-04-30 17:17:27', '2026-04-30 17:17:43', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4762462321859399509', '人工智能', '没有「身份证」的 Agent，接管不了世界', 'http://www.geekpark.net/news/363091', '极客公园', '2026-04-23', '焦虑与兴奋，是当下科技圈最真实的画像。大年初一蹲在家里装「小龙虾」的老板们，和深夜里顶着 Bug 调教 Agent 的独立开发者，被同一股力量推着往前走。他们既害怕错过，也害怕被反噬。\n但热潮之下，暗流也在涌动。前段时间工信部发出提醒 OpenClaw 这类新形态 Agent 中，恶意代码植入的风险正在浮现。\n当 Agent 从极客玩具变成人人标配的入口，它的安全和可信，谁来保证？\n这正是我们今天', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4811132879611744357', '人工智能', 'GPT-5.5 来了，但这次 OpenAI 想证明的不只是「更聪明」', 'http://www.geekpark.net/news/363131', '极客公园', '2026-04-24', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n如果几年前有人跟说，「你以后评测一个新 AI 模型，可能还没写完稿子，下一代就出来了」，你大概率会觉得是扯淡。\n但现在，这件事真的发生了。\nGPT-5.4 发布于六周前。今天，GPT-5.5 已经在 ChatGPT 上向付费用户推送。\n这不是一次普通的版本迭代。OpenAI 给它的定位是「全新的智能等级」&mdash;&mda', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:57', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4876302876853755223', '人工智能', '大模型上车两年，为什么「真·AI 汽车」现在才出现？', 'http://www.geekpark.net/news/363204', '极客公园', '2026-04-24', '今天在北京车展上爆火的极氪 8X，有网友放出了一段新车演示视频，用户坐在车里说了一句「带我去接孩子放学，顺便找一家麦当劳，5 点前我要到学校」。\n接下来发生的事情，和你过去对「智能汽车」的认知完全不同。车辆自主规划路线，启动智能驾驶，中途停靠麦当劳，到达学校门口自动泊车。整个过程，用户不需要碰导航、手动切换智驾模式、或者在停车场里找车位。\n这不是一个语音助手在帮你搜索，而是一个 Agent 在替你', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4918274925858548329', '元宇宙', '华为 Pura X Max 深度体验：比起「阔折」，「主动式 AI」更吸引我', 'http://www.geekpark.net/news/363246', '极客公园', '2026-04-25', '\n\n\n一台手机和一台口袋里的小平板，共用一副机身。\n<strong class=\"js_darkmode__4\" style=\"text-indent: 0em; font-size: 16px; color: #375474; font-family: Optima-Regular, PingFangTC-lig', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:09:06', '2026-04-30 18:09:06', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_4929828677099485926', '人工智能', '当剪辑工具开始「听懂人话」：剪映做了视频创作的Skill化Agent', 'http://www.geekpark.net/news/363407', '极客公园', '2026-04-28', '&nbsp;\n如果有人告诉你，视频剪辑可以像「刷手机」一样轻松，你大概率会在脑海里冒个问号。\n毕竟在我们的习惯里，剪辑往往意味着「高强度的手眼协同」&mdash;&mdash;要么是端坐桌前、左手快捷键、右手鼠标；要么就是盯着巴掌大的手机屏幕，在层层折叠的菜单里寻找功能，小心翼翼地用手指拖拽那几毫米的轨道。\n但剪映刚上线的 AI 助手，正在试图打破这个刻板印象。\n想象一下，你靠在椅子上，不需要触碰', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5177969211883122081', '新材料', '大模型已成「黑洞」，而逃逸速度是「光速」', 'http://www.geekpark.net/news/363001', '极客公园', '2026-04-22', '昨晚和创新工场的汪华、Meshy 的胡渊鸣直播聊完「大模型奇点已至」，脑子里一直盘旋着一个宏大的景象：\nAI 大模型是一个正在形成的黑洞。\n而我们今天所有的创业者、所有的 Builder，都在这股引力的作用下，置身于黑洞周边的「吸积盘」上，以前所未有的速度高速旋转。在这个过程中，我们确实获得了巨大的能量，发出了极其绚烂的光芒&mdash;&mdash;创造出更好的产品、交付前所未有的价值，这是我们', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:03:39', '2026-04-30 18:03:38', '2026-04-30 18:04:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5300307168687789490', '新材料', 'OPPO Find X9 Ultra 影像体验：方寸之间的哈苏与 10 倍「望远镜」', 'http://www.geekpark.net/news/363000', '极客公园', '2026-04-22', '\n\n\n「无论远近」里那个「远」字，今年被 OPPO 押到了极致。\n<strong class=\"js_darkmode__4\" style=\"text-indent: 0em; font-size: 16px; color: #375474; font-family: Optima-Regular, PingFa', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:04:40', '2026-04-30 18:04:40', '2026-04-30 18:04:40', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5322243627064713566', '人工智能', '比亚迪天神之眼 B 选装5月1日开始涨价；微信朋友圈悄然改版；麦当劳奶昔正式回归', 'http://www.geekpark.net/news/363496', '极客公园', '2026-04-29', '\n谷歌被曝与五角大楼签署机密 AI 协议，条款宽松程度超OpenAI\n当地时间 4 月 27 日，据知情人士透露，谷歌与美国国防部签署了一项机密 AI 协议，允许五角大楼将谷歌 AI 用于任何合法的政府目的。\n协议同时要求谷歌根据政府要求协助调整其 AI 安全设置与过滤器。媒体指出，该协议的条款宽松程度被认为超过 OpenAI 今年 2 月与五角大楼达成的协议。\n截', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5347640398932943793', '人工智能', '小红书：内容添加 AI 标识，反对 AI 造假；小米全新机器人亮相；微信 15 周年皮肤衣开卖，238 元 | 极客早知道', 'http://www.geekpark.net/news/363371', '极客公园', '2026-04-28', '\n小红书首次公布 AI 治理主张：坚决反对四类 AI 行为，给 AI 创作划出清晰边界\n4 月 27 日，小红书首次公布平台对 AI 内容的治理主张，并在北京举办首届 AI 治理开放日。此次 AI 治理主张共分为「平台鼓励的 AI 内容及行为」和「平台反对的 AI 内容及行为」两大板块，以给到创作者清晰指引。\n小红书明确了对待 AI 相关现象的核心态度：鼓励 AI 作为创意放大器，反对 AI 作为', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
