INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5557796883859004177', '新材料', 'OPPO Find X9 Ultra 影像体验：方寸之间的哈苏与 10 倍「望远镜」', 'http://www.geekpark.net/news/363000', '极客公园', '2026-04-22', '\n\n\n「无论远近」里那个「远」字，今年被 OPPO 押到了极致。\n<strong class=\"js_darkmode__4\" style=\"text-indent: 0em; font-size: 16px; color: #375474; font-family: Optima-Regular, PingFa', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:09:30', '2026-04-30 18:09:29', '2026-04-30 18:09:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5666175776209900314', '人工智能', '这张 4 万块的床垫，凭什么让马斯克、扎克伯格「疯狂上头」?', 'http://www.geekpark.net/news/363092', '极客公园', '2026-04-23', '4 月 18 日，深圳。 当 Eight Sleep 的智能床垫 Pod 5 系列首次在中国亮相时，现场最多听到的问题不是「它有什么功能」，而是「它凭什么卖这么贵」。\n一张 2M&times;2M 的 Pod 5 Ultra，售价 37999 元。这个价格足够买一台高配 MacBook Pro，或者三台 iPhone 16 Pro Max。更关键的是，它看起来并不奢侈，没有镶金边，没用什么稀有材质', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5692466799168012976', '新材料', 'Kimi K2.6 这次把 Agent 玩明白了吗？', 'http://www.geekpark.net/news/362947', '极客公园', '2026-04-22', '&nbsp;\n头图来源：Kimi官网\n&nbsp;\n&nbsp;\n当一个AI系统可以在无人工干预的情况下，独立完成一个复杂项目的完整交付，以及，当这些能力开始可以被复用、被沉淀为「技能」，AI在职场中的角色，是否已经发生了本质变化？\nOpenClaw这波热潮带动了大模型竞争进入深水区，赛道的分水岭，从「谁更强」，转向了「谁能真正交付生产力」。自主Agent的落地能力、工程化适配水平以及长时稳定运行', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:09:30', '2026-04-30 18:09:30', '2026-04-30 18:09:30', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5727226067449737273', '人工智能', '比亚迪天神之眼 B 选装5月1日开始涨价；微信朋友圈悄然改版；麦当劳奶昔正式回归', 'http://www.geekpark.net/news/363496', '极客公园', '2026-04-29', '\n谷歌被曝与五角大楼签署机密 AI 协议，条款宽松程度超OpenAI\n当地时间 4 月 27 日，据知情人士透露，谷歌与美国国防部签署了一项机密 AI 协议，允许五角大楼将谷歌 AI 用于任何合法的政府目的。\n协议同时要求谷歌根据政府要求协助调整其 AI 安全设置与过滤器。媒体指出，该协议的条款宽松程度被认为超过 OpenAI 今年 2 月与五角大楼达成的协议。\n截', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5744113701608944526', '元宇宙', '华为余承东：新 M9 友商永远追不上；谷歌曝光智能体专项 AI 芯片；兵乓机器人击败人类顶级选手｜极客早知道', 'http://www.geekpark.net/news/363008', '极客公园', '2026-04-23', '\n&nbsp;\n\n\n传腾讯与阿里巴巴洽谈投资 DeepSeek 估值或超 200 亿美元\n<p style=\"margin: ', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:04:20', '2026-04-30 18:04:20', '2026-04-30 18:04:40', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_5898230394898164599', '人工智能', 'HappyHorse 1.0在千问首发开启灰测免费体验，重构 AI 视频赛道', 'http://www.geekpark.net/news/363406', '极客公园', '2026-04-29', '&nbsp;\n前段时间，AI 视频生成赛道迎来了一场无预热的行业震动。\n一款名为 HappyHorse 1.0 的模型以匿名形式空降权威第三方评测平台 Artificial Analysis 的 Video Arena 榜单，一度拿下第一。\n从全网对研发主体的密集猜测，到阿里巴巴 ATH 事业群正式官宣认领，这款被业内称为 「HappyHorse 1.0 」 的模型，迅速成为全球 AI 视频圈的核', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:15', 0.5);
