INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_6001110729946504223', '人工智能', 'GPT-5.5 来了，但这次 OpenAI 想证明的不只是「更聪明」', 'http://www.geekpark.net/news/363131', '极客公园', '2026-04-24', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n如果几年前有人跟说，「你以后评测一个新 AI 模型，可能还没写完稿子，下一代就出来了」，你大概率会觉得是扯淡。\n但现在，这件事真的发生了。\nGPT-5.4 发布于六周前。今天，GPT-5.5 已经在 ChatGPT 上向付费用户推送。\n这不是一次普通的版本迭代。OpenAI 给它的定位是「全新的智能等级」&mdash;&mda', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_6207834980748733550', '人工智能', '豆包上线「帮你选」功能； 5999 元，泡泡玛特首推冰箱；高铁试点「坐火车带自行车」 | 极客早知道｜极客早知道', 'http://www.geekpark.net/news/363226', '极客公园', '2026-04-25', '\n英特尔股价周五暴涨 24% 创 1987 年以来最大单日涨幅\n4 月 25 日消息，英特尔股价周五飙升 24%，创下自 1987 年 10 月以来的最佳单日表现，投资者对因人工智能需求增长而带来的复苏迹象感到振奋。\n该股收于 82.57 美元，继 2025 年全年上涨 84% 之后，今年迄今已累计上涨 124%。上周五的涨势超过了该股在 9 月 18 日 23% 的涨幅&mdash;&mdash', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
