INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_6510532737619489482', '人工智能', '大模型上车两年，为什么「真·AI 汽车」现在才出现？', 'http://www.geekpark.net/news/363204', '极客公园', '2026-04-24', '今天在北京车展上爆火的极氪 8X，有网友放出了一段新车演示视频，用户坐在车里说了一句「带我去接孩子放学，顺便找一家麦当劳，5 点前我要到学校」。\n接下来发生的事情，和你过去对「智能汽车」的认知完全不同。车辆自主规划路线，启动智能驾驶，中途停靠麦当劳，到达学校门口自动泊车。整个过程，用户不需要碰导航、手动切换智驾模式、或者在停车场里找车位。\n这不是一个语音助手在帮你搜索，而是一个 Agent 在替你', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_6552682300555798222', '人工智能', '一年烧掉 1850 亿美元、Google 要做智能体时代的「企业 Windows」', 'http://www.geekpark.net/news/363090', '极客公园', '2026-04-23', '4 月 22 号，拉斯维加斯，Google Cloud Next 2026 正在如火如荼地举行。\n\n了解 Google 每年产品发布节奏的人都知道，I/O 是讲手机、讲安卓、讲各种新产品如何改变人类世界。而 Next 的画风完全不同，它一上来就直奔企业客户，聚焦在云基础设施怎么搭，AI 怎么落到生产环境里去。\n而如果把过去四年的 Next 大会串在一起，你会看到 AI 时代 Google Clou', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_6602081975748649537', '人工智能', 'GPT-5.5 来了，但这次 OpenAI 想证明的不只是「更聪明」', 'http://www.geekpark.net/news/363131', '极客公园', '2026-04-24', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n如果几年前有人跟说，「你以后评测一个新 AI 模型，可能还没写完稿子，下一代就出来了」，你大概率会觉得是扯淡。\n但现在，这件事真的发生了。\nGPT-5.4 发布于六周前。今天，GPT-5.5 已经在 ChatGPT 上向付费用户推送。\n这不是一次普通的版本迭代。OpenAI 给它的定位是「全新的智能等级」&mdash;&mda', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:54', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_672981187580914495', '人工智能', '当剪辑工具开始「听懂人话」：剪映做了视频创作的Skill化Agent', 'http://www.geekpark.net/news/363407', '极客公园', '2026-04-28', '&nbsp;\n如果有人告诉你，视频剪辑可以像「刷手机」一样轻松，你大概率会在脑海里冒个问号。\n毕竟在我们的习惯里，剪辑往往意味着「高强度的手眼协同」&mdash;&mdash;要么是端坐桌前、左手快捷键、右手鼠标；要么就是盯着巴掌大的手机屏幕，在层层折叠的菜单里寻找功能，小心翼翼地用手指拖拽那几毫米的轨道。\n但剪映刚上线的 AI 助手，正在试图打破这个刻板印象。\n想象一下，你靠在椅子上，不需要触碰', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_6740719167150565305', '人工智能', '一个新视频模型背后，藏着蔡浩宇给游戏行业造的「新引擎」', 'http://www.geekpark.net/news/363077', '极客公园', '2026-04-23', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n4 月 9 日，一篇来自 Anuttacon 团队的论文悄悄出现在 arXiv 上。论文展示了一个叫 LPM 1.0 的视频模型&mdash;&mdash;全称 Large Performance Model，注意，是 Performance（表演），不是 Language（语言）。\n这个 170 亿参数的扩散 Transformer 模型，能让一个 ', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:09', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_6837578213543913986', '新材料', '清华姚班到全球 3D AI 第一：胡渊鸣的 Meshy ARR 已超 4000 万美元', 'http://www.geekpark.net/news/363031', '极客公园', '2026-04-23', '\n\n\n当文字、图像、视频已经先后被生成式 AI 重写，3D 很可能就是下一站。\n<strong style=\"text-indent: 0em; font-size: 16px; color: #375474; font-famil', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:09:30', '2026-04-30 18:09:29', '2026-04-30 18:09:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7016483015690225549', '半导体', '重构腾讯 AI 之后，姚顺雨交出入场后的第一份答卷', 'http://www.geekpark.net/news/363076', '极客公园', '2026-04-23', '&nbsp;\n极客一问：你看好接下来的混元大模型吗？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n&nbsp;\n姚顺雨交出了加入腾讯后的第一份模型答卷。\n4 月 23 日，腾讯混元 Hy3 preview 语言模型发布并开源。这是一款主打快慢思考融合的 MoE 语言模型，总参数 295B，激活参数 21B，最大支持 256K 上下文长度，官方称其整体性能达到同尺寸模型最佳水平。\n从研发节奏来', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:06:38', '2026-04-30 18:06:38', '2026-04-30 18:06:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_709304394366546903', '人工智能', '汽车的「OpenClaw 时刻」，到了？', 'http://www.geekpark.net/news/363403', '极客公园', '2026-04-28', '汽车的「OpenClaw 时刻」，到了？摘要：更聪明的智能助手，和真正的「AI 控车」。极客一问：你觉得现在车上的「AI 助手」智能化程度如何？头图来源：极客公园作者｜靖宇走完 2026 北京车展的十几个展馆，我最大的感受是，车企的高管，肯定是用上「小龙虾」了——今年，如果你的新车没搭个大模型，你都不好意思开发布会。火山引擎带着豆包宣布搭载超 700 万辆车；腾讯发布出行全场景智能体开放平台；科大', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7160761170033694691', '人工智能', 'OpenAI 硬件负责人的闭门分享，向我们揭示了为什么硬件「终点」仍是智能手机', 'http://www.geekpark.net/news/363596', '极客公园', '2026-04-29', '\n\n\n「你必须为模型将要去的方向设计硬件，而不是为今天的模型。」\n<section class=\"js_darkmode__3', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7174970606032022782', '人工智能', '马斯克：OpenAI 是我的创意，Altman 是小偷；Claude Code 使用成本翻倍；Image 2 登顶视觉模型榜｜极客早知道', 'http://www.geekpark.net/news/363594', '极客公园', '2026-04-30', '\n结束与微软独家合作，OpenAI 模型接入亚马逊 AWS\n4 月 29 日，在亚马逊云科技（Amazon Web Services，简称 AWS）新品发布会上，AWS 宣布携手 OpenAI，将 OpenAI 最新大模型接入 Amazon Bedrock，在 Amazon Bedrock 上线 Codex 代码 Agent，并推出由 OpenAI 赋能的 Amazon Bedrock 托管 Ag', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:51', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7185381316979083198', '半导体', '居然有手机厂商坚持今年旗舰提质不提价', 'http://www.geekpark.net/news/363057', '极客公园', '2026-04-23', '2026 年智能手机行业开场即迎来涨价潮。在 AI 算力需求拉动下，存储芯片价格大涨并传导至消费电子终端。Counterpoint 预测，3 月后中国市场新机均价将较去年同档机型上涨约 15%&mdash;25%。\n现实正在快速应验这一预测，三星、荣耀、vivo、小米等品牌新一代旗舰涨价幅度在 1000 至 1600 元不等，成为行业应对成本的普遍策略。\n\n在此背景下，4 月 21 日发布的 OP', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 17:17:27', '2026-04-30 17:17:27', '2026-04-30 17:17:27', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7222244351798854014', '人工智能', '大模型上车两年，为什么「真·AI 汽车」现在才出现？', 'http://www.geekpark.net/news/363204', '极客公园', '2026-04-24', '今天在北京车展上爆火的极氪 8X，有网友放出了一段新车演示视频，用户坐在车里说了一句「带我去接孩子放学，顺便找一家麦当劳，5 点前我要到学校」。\n接下来发生的事情，和你过去对「智能汽车」的认知完全不同。车辆自主规划路线，启动智能驾驶，中途停靠麦当劳，到达学校门口自动泊车。整个过程，用户不需要碰导航、手动切换智驾模式、或者在停车场里找车位。\n这不是一个语音助手在帮你搜索，而是一个 Agent 在替你', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:15', 0.5);
