INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7270079663904286865', '人工智能', 'MiniMax 登上戛纳，AI 与艺术的全球和解开始了？', 'http://www.geekpark.net/news/363324', '极客公园', '2026-04-27', '作者｜Cynthia \n编辑｜ 郑玄\n&nbsp;\n2026 年的春天，影视圈的风向开始变了。\n4 月 21 日，全球首个，也是迄今为止规模最大的 AI 电影节 WAIFF（2026），在法国戛纳电影宫正式举办。蔚蓝海岸线前，一众影视行业的从业者鱼贯而入，但一改往日红毯众星云集的流光溢彩，这一次的电影节，地毯换成了象征科技的紫色，而走上这条「紫毯」的，也换成了一众 AI 内容的创作者。\n<p st', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:38', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7320163375900480517', '元宇宙', '600 亿美元！马斯克「锁定」Cursor', 'http://www.geekpark.net/news/362963', '极客公园', '2026-04-22', '\n&nbsp;\n作者｜ 桦林舞王 \n编辑｜ 靖宇\n&nbsp;\nCursor 要卖了？！\n美国时间 4 月 21 日，《纽约时报》发出了', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:06:24', '2026-04-30 18:06:24', '2026-04-30 18:06:46', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7339963993963137774', '新材料', '大模型已成「黑洞」，而逃逸速度是「光速」', 'http://www.geekpark.net/news/363001', '极客公园', '2026-04-22', '昨晚和创新工场的汪华、Meshy 的胡渊鸣直播聊完「大模型奇点已至」，脑子里一直盘旋着一个宏大的景象：\nAI 大模型是一个正在形成的黑洞。\n而我们今天所有的创业者、所有的 Builder，都在这股引力的作用下，置身于黑洞周边的「吸积盘」上，以前所未有的速度高速旋转。在这个过程中，我们确实获得了巨大的能量，发出了极其绚烂的光芒&mdash;&mdash;创造出更好的产品、交付前所未有的价值，这是我们', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:06:46', '2026-04-30 18:06:46', '2026-04-30 18:07:09', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7487425141360404420', '新材料', '大模型已成「黑洞」，而逃逸速度是「光速」', 'http://www.geekpark.net/news/363001', '极客公园', '2026-04-22', '昨晚和创新工场的汪华、Meshy 的胡渊鸣直播聊完「大模型奇点已至」，脑子里一直盘旋着一个宏大的景象：\nAI 大模型是一个正在形成的黑洞。\n而我们今天所有的创业者、所有的 Builder，都在这股引力的作用下，置身于黑洞周边的「吸积盘」上，以前所未有的速度高速旋转。在这个过程中，我们确实获得了巨大的能量，发出了极其绚烂的光芒&mdash;&mdash;创造出更好的产品、交付前所未有的价值，这是我们', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:08:27', '2026-04-30 18:08:27', '2026-04-30 18:08:48', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7543713559936748238', '人工智能', 'DeepSeek 正式发布 V4 API：Flash/Pro 双版本齐发，百万上下文成标配', 'http://www.geekpark.net/news/363222', '极客公园', '2026-04-24', '&nbsp;\n极客一问：你怎么看这次 DeepSeek V4 的更新？\n&nbsp;\n头图来源：GPT生成\n&nbsp;\n万众期待中，DeepSeek V4，终于发布了！\n&nbsp;\n就在刚刚，被期待已久的DeepSeek V4 预览版正式登场。两个版本&mdash;&mdash;V4-Pro 和 V4-Flash，全系标配 1M（百万字）超长上下文，同步开源模型权重和技术报告。\n&nbsp;\n', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_771394998163793255', '人工智能', '没有「身份证」的 Agent，接管不了世界', 'http://www.geekpark.net/news/363091', '极客公园', '2026-04-23', '焦虑与兴奋，是当下科技圈最真实的画像。大年初一蹲在家里装「小龙虾」的老板们，和深夜里顶着 Bug 调教 Agent 的独立开发者，被同一股力量推着往前走。他们既害怕错过，也害怕被反噬。\n但热潮之下，暗流也在涌动。前段时间工信部发出提醒 OpenClaw 这类新形态 Agent 中，恶意代码植入的风险正在浮现。\n当 Agent 从极客玩具变成人人标配的入口，它的安全和可信，谁来保证？\n这正是我们今天', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_781959406693072940', '新材料', 'OPPO Find X9 Ultra 影像体验：方寸之间的哈苏与 10 倍「望远镜」', 'http://www.geekpark.net/news/363000', '极客公园', '2026-04-22', '\n\n\n「无论远近」里那个「远」字，今年被 OPPO 押到了极致。\n<strong class=\"js_darkmode__4\" style=\"text-indent: 0em; font-size: 16px; color: #375474; font-family: Optima-Regular, PingFa', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:08:27', '2026-04-30 18:08:27', '2026-04-30 18:08:27', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7967022335848726746', '人工智能', 'HappyHorse 1.0在千问首发开启灰测免费体验，重构 AI 视频赛道', 'http://www.geekpark.net/news/363406', '极客公园', '2026-04-29', '&nbsp;\n前段时间，AI 视频生成赛道迎来了一场无预热的行业震动。\n一款名为 HappyHorse 1.0 的模型以匿名形式空降权威第三方评测平台 Artificial Analysis 的 Video Arena 榜单，一度拿下第一。\n从全网对研发主体的密集猜测，到阿里巴巴 ATH 事业群正式官宣认领，这款被业内称为 「HappyHorse 1.0 」 的模型，迅速成为全球 AI 视频圈的核', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7985853744895621360', '人工智能', '汽车的「OpenClaw 时刻」，到了？', 'http://www.geekpark.net/news/363403', '极客公园', '2026-04-28', '汽车的「OpenClaw 时刻」，到了？摘要：更聪明的智能助手，和真正的「AI 控车」。极客一问：你觉得现在车上的「AI 助手」智能化程度如何？头图来源：极客公园作者｜靖宇走完 2026 北京车展的十几个展馆，我最大的感受是，车企的高管，肯定是用上「小龙虾」了——今年，如果你的新车没搭个大模型，你都不好意思开发布会。火山引擎带着豆包宣布搭载超 700 万辆车；腾讯发布出行全场景智能体开放平台；科大', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:08:58', '2026-04-30 18:08:58', '2026-04-30 18:09:47', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_7996850381699307465', '新材料', '大模型已成「黑洞」，而逃逸速度是「光速」', 'http://www.geekpark.net/news/363001', '极客公园', '2026-04-22', '昨晚和创新工场的汪华、Meshy 的胡渊鸣直播聊完「大模型奇点已至」，脑子里一直盘旋着一个宏大的景象：\nAI 大模型是一个正在形成的黑洞。\n而我们今天所有的创业者、所有的 Builder，都在这股引力的作用下，置身于黑洞周边的「吸积盘」上，以前所未有的速度高速旋转。在这个过程中，我们确实获得了巨大的能量，发出了极其绚烂的光芒&mdash;&mdash;创造出更好的产品、交付前所未有的价值，这是我们', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:02:30', '2026-04-30 18:02:29', '2026-04-30 18:02:59', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_8021170954353190016', '新材料', 'Kimi K2.6 这次把 Agent 玩明白了吗？', 'http://www.geekpark.net/news/362947', '极客公园', '2026-04-22', '&nbsp;\n头图来源：Kimi官网\n&nbsp;\n&nbsp;\n当一个AI系统可以在无人工干预的情况下，独立完成一个复杂项目的完整交付，以及，当这些能力开始可以被复用、被沉淀为「技能」，AI在职场中的角色，是否已经发生了本质变化？\nOpenClaw这波热潮带动了大模型竞争进入深水区，赛道的分水岭，从「谁更强」，转向了「谁能真正交付生产力」。自主Agent的落地能力、工程化适配水平以及长时稳定运行', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:02:30', '2026-04-30 18:02:29', '2026-04-30 18:02:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_8175387908948759958', '人工智能', '当剪辑工具开始「听懂人话」：剪映做了视频创作的Skill化Agent', 'http://www.geekpark.net/news/363407', '极客公园', '2026-04-28', '&nbsp;\n如果有人告诉你，视频剪辑可以像「刷手机」一样轻松，你大概率会在脑海里冒个问号。\n毕竟在我们的习惯里，剪辑往往意味着「高强度的手眼协同」&mdash;&mdash;要么是端坐桌前、左手快捷键、右手鼠标；要么就是盯着巴掌大的手机屏幕，在层层折叠的菜单里寻找功能，小心翼翼地用手指拖拽那几毫米的轨道。\n但剪映刚上线的 AI 助手，正在试图打破这个刻板印象。\n想象一下，你靠在椅子上，不需要触碰', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_8457619143205543459', '半导体', '居然有手机厂商坚持今年旗舰提质不提价', 'http://www.geekpark.net/news/363057', '极客公园', '2026-04-23', '2026 年智能手机行业开场即迎来涨价潮。在 AI 算力需求拉动下，存储芯片价格大涨并传导至消费电子终端。Counterpoint 预测，3 月后中国市场新机均价将较去年同档机型上涨约 15%&mdash;25%。\n现实正在快速应验这一预测，三星、荣耀、vivo、小米等品牌新一代旗舰涨价幅度在 1000 至 1600 元不等，成为行业应对成本的普遍策略。\n\n在此背景下，4 月 21 日发布的 OP', '新产品发布将加剧市场竞争格局变化。', 'product', 0.5, '2026-04-30 18:06:38', '2026-04-30 18:06:38', '2026-04-30 18:06:38', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_8544212736650477722', '元宇宙', '600 亿美元！马斯克「锁定」Cursor', 'http://www.geekpark.net/news/362963', '极客公园', '2026-04-22', '\n&nbsp;\n作者｜ 桦林舞王 \n编辑｜ 靖宇\n&nbsp;\nCursor 要卖了？！\n美国时间 4 月 21 日，《纽约时报》发出了', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:02:07', '2026-04-30 18:02:06', '2026-04-30 18:02:29', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_8574216937006621755', '人工智能', '一年烧掉 1850 亿美元、Google 要做智能体时代的「企业 Windows」', 'http://www.geekpark.net/news/363090', '极客公园', '2026-04-23', '4 月 22 号，拉斯维加斯，Google Cloud Next 2026 正在如火如荼地举行。\n\n了解 Google 每年产品发布节奏的人都知道，I/O 是讲手机、讲安卓、讲各种新产品如何改变人类世界。而 Next 的画风完全不同，它一上来就直奔企业客户，聚焦在云基础设施怎么搭，AI 怎么落到生产环境里去。\n而如果把过去四年的 Next 大会串在一起，你会看到 AI 时代 Google Clou', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:00:27', '2026-04-30 18:00:27', '2026-04-30 18:01:15', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_8881942260083355948', '人工智能', '一个新视频模型背后，藏着蔡浩宇给游戏行业造的「新引擎」', 'http://www.geekpark.net/news/363077', '极客公园', '2026-04-23', '作者｜桦林舞王 \n编辑｜ 靖宇\n&nbsp;\n4 月 9 日，一篇来自 Anuttacon 团队的论文悄悄出现在 arXiv 上。论文展示了一个叫 LPM 1.0 的视频模型&mdash;&mdash;全称 Large Performance Model，注意，是 Performance（表演），不是 Language（语言）。\n这个 170 亿参数的扩散 Transformer 模型，能让一个 ', '该事件值得关注。', 'other', 0.5, '2026-04-30 17:17:04', '2026-04-30 17:17:04', '2026-04-30 17:17:57', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_9024353656673711235', '人工智能', 'HappyHorse 1.0在千问首发开启灰测免费体验，重构 AI 视频赛道', 'http://www.geekpark.net/news/363406', '极客公园', '2026-04-29', '&nbsp;\n前段时间，AI 视频生成赛道迎来了一场无预热的行业震动。\n一款名为 HappyHorse 1.0 的模型以匿名形式空降权威第三方评测平台 Artificial Analysis 的 Video Arena 榜单，一度拿下第一。\n从全网对研发主体的密集猜测，到阿里巴巴 ATH 事业群正式官宣认领，这款被业内称为 「HappyHorse 1.0 」 的模型，迅速成为全球 AI 视频圈的核', '技术突破可能带来新的商业机会。', 'tech', 0.5, '2026-04-30 18:01:58', '2026-04-30 18:01:58', '2026-04-30 18:02:45', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_9079167749519363063', '人工智能', '马斯克：OpenAI 是我的创意，Altman 是小偷；Claude Code 使用成本翻倍；Image 2 登顶视觉模型榜｜极客早知道', 'http://www.geekpark.net/news/363594', '极客公园', '2026-04-30', '\n结束与微软独家合作，OpenAI 模型接入亚马逊 AWS\n4 月 29 日，在亚马逊云科技（Amazon Web Services，简称 AWS）新品发布会上，AWS 宣布携手 OpenAI，将 OpenAI 最新大模型接入 Amazon Bedrock，在 Amazon Bedrock 上线 Codex 代码 Agent，并推出由 OpenAI 赋能的 Amazon Bedrock 托管 Ag', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:06:17', '2026-04-30 18:06:17', '2026-04-30 18:07:02', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_9135619820019758501', '新材料', '马斯克 600 亿美元锁定 Cursor；字节、荣威合作推出「AI 汽车」；传今年存储厂商人均奖金超 300 万元', 'http://www.geekpark.net/news/362932', '极客公园', '2026-04-22', '\n600 亿美元！马斯克「锁定」Cursor\n美国时间 4 月 21 日，《纽约时报》发出了一条让科技圈炸锅的消息。\nCursor 授予 SpaceX 权利，允许其在今年晚些时候以 600 亿美元收购 Cursor，或就双方合作支付 100 亿美元。\n根据 SpaceX 在 X 上公布的消息，双方将在 GPU 算力上达成合作。xAI 旗下的 Colossus 超算系统拥有约 20 万张英伟达 GP', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:04:40', '2026-04-30 18:04:40', '2026-04-30 18:04:40', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_9169577480956418624', '人工智能', '小红书：内容添加 AI 标识，反对 AI 造假；小米全新机器人亮相；微信 15 周年皮肤衣开卖，238 元 | 极客早知道', 'http://www.geekpark.net/news/363371', '极客公园', '2026-04-28', '\n小红书首次公布 AI 治理主张：坚决反对四类 AI 行为，给 AI 创作划出清晰边界\n4 月 27 日，小红书首次公布平台对 AI 内容的治理主张，并在北京举办首届 AI 治理开放日。此次 AI 治理主张共分为「平台鼓励的 AI 内容及行为」和「平台反对的 AI 内容及行为」两大板块，以给到创作者清晰指引。\n小红书明确了对待 AI 相关现象的核心态度：鼓励 AI 作为创意放大器，反对 AI 作为', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:04:13', '2026-04-30 18:04:13', '2026-04-30 18:04:53', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_9200719785568737425', '元宇宙', '华为 Pura X Max 深度体验：比起「阔折」，「主动式 AI」更吸引我', 'http://www.geekpark.net/news/363246', '极客公园', '2026-04-25', '\n\n\n一台手机和一台口袋里的小平板，共用一副机身。\n<strong class=\"js_darkmode__4\" style=\"text-indent: 0em; font-size: 16px; color: #375474; font-family: Optima-Regular, PingFangTC-lig', '该事件值得关注。', 'other', 0.5, '2026-04-30 18:03:16', '2026-04-30 18:03:16', '2026-04-30 18:03:55', 0.5);
INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('极客公园_928249052657855422', '人工智能', '豆包上线「帮你选」功能； 5999 元，泡泡玛特首推冰箱；高铁试点「坐火车带自行车」 | 极客早知道｜极客早知道', 'http://www.geekpark.net/news/363226', '极客公园', '2026-04-25', '\n英特尔股价周五暴涨 24% 创 1987 年以来最大单日涨幅\n4 月 25 日消息，英特尔股价周五飙升 24%，创下自 1987 年 10 月以来的最佳单日表现，投资者对因人工智能需求增长而带来的复苏迹象感到振奋。\n该股收于 82.57 美元，继 2025 年全年上涨 84% 之后，今年迄今已累计上涨 124%。上周五的涨势超过了该股在 9 月 18 日 23% 的涨幅&mdash;&mdash', '融资事件表明资本市场对该领域持续看好。', 'funding', 0.5, '2026-04-30 18:03:09', '2026-04-30 18:03:08', '2026-04-30 18:03:55', 0.5);
