INSERT INTO `events` (`id`, `keyword`, `title`, `url`, `source`, `publish_date`, `summary`, `ai_commentary`, `event_type`, `relevance_score`, `crawled_at`, `created_at`, `updated_at`, `sentiment_score`) VALUES ('经济观察报_-231580710928684947', '机器人', '本田摩托车销售（上海）有限公司召回部分进口CB1000R型摩托车', 'http://www.eeo.com.cn/2026/0430/859046.shtml', '经济观察报', '2026-04-30', '经济观察网 据市场监管总局网站消息，日前，本田摩托车销售（上海）有限公司根据《缺陷汽车产品召回管理条例》《缺陷汽车产品召回管理条例实施办法》和《机动车排放召回管理规定》的要求，向国家市场监督管理总局备案了召回计划。召回编号E2026M0046V：自2026年5月25日起，召回2025年4月16日至2025年7月4日期间生产的部分进口2025款CB1000R型摩托车，共计37辆。本次召回范围内的部分', '政策发布将影响行业走向，需密切关注实施细则。', 'policy', 0.5, '2026-04-30 18:01:08', '2026-04-30 18:01:07', '2026-04-30 18:01:07', 0.5);
